export const IELTS_WORDS = [{"id":2001,"word":"say","phonetic":"/sei/","pos":"vt.","meaning":"说；讲；念；说明","example":"Please say your name clearly before the meeting begins.","exampleCn":"请在会议开始前清楚地说出你的名字。","level":"IELTS"},{"id":2002,"word":"all","phonetic":"/ɒ:l/","pos":"adj.","meaning":"所有的；全部的；一切的 adv. 全部；全然 pron. 全部 n. 全部","example":"All the students in our class passed the exam.","exampleCn":"我们班所有的学生都通过了考试。","level":"IELTS"},{"id":2003,"word":"get","phonetic":"/get/","pos":"vt.","meaning":"得到；获得；变成；使得","example":"You can get free tickets at the front desk.","exampleCn":"你可以在前台拿到免费的票。","level":"IELTS"},{"id":2004,"word":"make","phonetic":"/meik/","pos":"vt.","meaning":"制造；安排；创造；构成","example":"We make fresh bread in our kitchen every morning.","exampleCn":"我们每天早上在厨房做新鲜面包。","level":"IELTS"},{"id":2005,"word":"one","phonetic":"/wʌn/","pos":"n.","meaning":"一(个) pron. 一；任何人 num. 一；一个 a. 一致的；完整的","example":"There is only one apple left on the table.","exampleCn":"桌上只剩下一个苹果了。","level":"IELTS"},{"id":2006,"word":"time","phonetic":"/taim/","pos":"n.","meaning":"时间；时侯；时机；时期","example":"We don't have much time before the train leaves.","exampleCn":"火车开走之前我们没有多少时间了。","level":"IELTS"},{"id":2007,"word":"take","phonetic":"/teik/","pos":"vt.","meaning":"拿；取；抓；带领","example":"Please take this umbrella with you; it may rain.","exampleCn":"请带上这把伞，可能要下雨。","level":"IELTS"},{"id":2008,"word":"come","phonetic":"/kʌm/","pos":"vi.","meaning":"过来；来；到达；出现","example":"My friends often come to my house on weekends.","exampleCn":"我的朋友们周末经常来我家。","level":"IELTS"},{"id":2009,"word":"give","phonetic":"/giv/","pos":"n.","meaning":"弹性；适应性 vt. 给；授予；供给","example":"I will give you my answer tomorrow morning.","exampleCn":"我明天早上给你答复。","level":"IELTS"},{"id":2010,"word":"good","phonetic":"/gud/","pos":"n.","meaning":"善行；好处；利益 a. 好的；优良的","example":"Eating vegetables every day is good for your health.","exampleCn":"每天吃蔬菜对健康有好处。","level":"IELTS"},{"id":2011,"word":"may","phonetic":"/mei/","pos":"n.","meaning":"五月 aux. 愿能；可以；愿意","example":"You may leave the room when you finish the test.","exampleCn":"考试做完后你可以离开房间。","level":"IELTS"},{"id":2012,"word":"day","phonetic":"/dei/","pos":"n.","meaning":"天；日子；白天；工作日 日(一昼夜)","example":"We spent a wonderful day at the beach together.","exampleCn":"我们一起在海滩度过了美好的一天。","level":"IELTS"},{"id":2013,"word":"back","phonetic":"/bæk/","pos":"adj.","meaning":"后面的 vt. 使后退；支持 vi. 倒退；背靠 adv. 向后地 n. 背部；后面","example":"She came back home late after the long meeting.","exampleCn":"开完长会后她很晚才回到家。","level":"IELTS"},{"id":2014,"word":"even","phonetic":"/'i:vәn/","pos":"adj.","meaning":"平坦的；相等的；连贯的；均等的","example":"The workers made the road surface smooth and even.","exampleCn":"工人们把路面修得又光滑又平整。","level":"IELTS"},{"id":2015,"word":"child","phonetic":"/tʃaild/","pos":"n.","meaning":"孩子；产物；追随者 儿童","example":"Every child needs love and care from parents.","exampleCn":"每个孩子都需要父母的关爱。","level":"IELTS"},{"id":2016,"word":"put","phonetic":"/put/","pos":"vt.","meaning":"放；摆；安置；移动","example":"Please put the books back on the shelf.","exampleCn":"请把书放回书架上。","level":"IELTS"},{"id":2017,"word":"mean","phonetic":"/mi:n/","pos":"adj.","meaning":"低劣的；卑贱的；简陋的；吝啬的","example":"He is too mean to share his food with anyone.","exampleCn":"他太吝啬了，不愿和任何人分享食物。","level":"IELTS"},{"id":2018,"word":"call","phonetic":"/kɒ:l/","pos":"n.","meaning":"呼叫；访问；打电话；号召","example":"I got a call from my mother this morning.","exampleCn":"今天早上我接到了妈妈打来的电话。","level":"IELTS"},{"id":2019,"word":"become","phonetic":"/bi'kʌm/","pos":"vi.","meaning":"变成；变得 vt. 适合","example":"She wants to become a doctor in the future.","exampleCn":"她将来想成为一名医生。","level":"IELTS"},{"id":2020,"word":"world","phonetic":"/wә:ld/","pos":"n.","meaning":"世界；地球；宇宙；万物","example":"Travel helps us understand the world much better.","exampleCn":"旅行帮助我们更好地了解世界。","level":"IELTS"},{"id":2021,"word":"school","phonetic":"/sku:l/","pos":"n.","meaning":"学校；鱼群；门派；学派 vt. 教育","example":"The children walk to school together every morning.","exampleCn":"孩子们每天早上一起步行去上学。","level":"IELTS"},{"id":2022,"word":"leave","phonetic":"/li:v/","pos":"n.","meaning":"许可；告别；请假；休假 vt. 离开","example":"We will leave for the airport at six tomorrow.","exampleCn":"我们明天六点出发去机场。","level":"IELTS"},{"id":2023,"word":"feel","phonetic":"/fi:l/","pos":"vt.","meaning":"感觉；觉得；触摸；以为 vi. 有知觉","example":"I feel very happy when I listen to music.","exampleCn":"听音乐的时候我感到非常开心。","level":"IELTS"},{"id":2024,"word":"case","phonetic":"/keis/","pos":"n.","meaning":"情形；情况；箱；容器","example":"In that case, we should change our plan now.","exampleCn":"那样的话，我们现在应该改变计划。","level":"IELTS"},{"id":2025,"word":"group","phonetic":"/gru:p/","pos":"n.","meaning":"团体；组；团；群 v. 聚合","example":"A small group of students is studying in the library.","exampleCn":"一小组学生正在图书馆里学习。","level":"IELTS"},{"id":2026,"word":"most","phonetic":"/mәust/","pos":"n.","meaning":"最多；最大 a. 大多数的；几乎全部的；最多的 adv. 最","example":"Most people in this town work at the factory.","exampleCn":"这个镇上大多数人都在工厂工作。","level":"IELTS"},{"id":2027,"word":"family","phonetic":"/'fæmәli/","pos":"n.","meaning":"家庭；家人；族 a. 家庭的","example":"My family has dinner together every Sunday evening.","exampleCn":"我们一家每周日晚上一起吃晚饭。","level":"IELTS"},{"id":2028,"word":"house","phonetic":"/haus/","pos":"n.","meaning":"房子；住宅；机构；议院","example":"They bought a new house near the river last year.","exampleCn":"他们去年在河边买了一栋新房子。","level":"IELTS"},{"id":2029,"word":"company","phonetic":"/'kʌmpәni/","pos":"n.","meaning":"公司；友伴；交往；连队","example":"His company has offices in three different cities.","exampleCn":"他的公司在三个不同的城市设有办事处。","level":"IELTS"},{"id":2030,"word":"keep","phonetic":"/ki:p/","pos":"n.","meaning":"生计；维持；保持 vt. 保持；保存","example":"Please keep your room clean and tidy.","exampleCn":"请保持你的房间干净整洁。","level":"IELTS"},{"id":2031,"word":"student","phonetic":"/'stju:dnt/","pos":"n.","meaning":"学生；研究者；学者","example":"Every student should bring a notebook to class.","exampleCn":"每个学生都应该带笔记本来上课。","level":"IELTS"},{"id":2032,"word":"let","phonetic":"/let/","pos":"vt.","meaning":"让；假设；出租；排放","example":"Please let me know when you arrive home safely.","exampleCn":"你平安到家后请告诉我一声。","level":"IELTS"},{"id":2033,"word":"service","phonetic":"/'sә:vis/","pos":"n.","meaning":"服务；贡献；雇佣；公职","example":"The hotel is famous for its excellent service.","exampleCn":"这家旅馆以优质的服务而闻名。","level":"IELTS"},{"id":2034,"word":"place","phonetic":"/pleis/","pos":"n.","meaning":"地方；地点；位置；住所","example":"This quiet place is perfect for reading books.","exampleCn":"这个安静的地方非常适合读书。","level":"IELTS"},{"id":2035,"word":"hand","phonetic":"/hænd/","pos":"n.","meaning":"手；爪；指针；掌握","example":"She held the little key tightly in her hand.","exampleCn":"她把那把小钥匙紧紧握在手里。","level":"IELTS"},{"id":2036,"word":"party","phonetic":"/'pɑ:ti/","pos":"n.","meaning":"宴会；党；政党；团体","example":"We are planning a birthday party for my sister.","exampleCn":"我们正在为我妹妹筹备生日聚会。","level":"IELTS"},{"id":2037,"word":"country","phonetic":"/'kʌntri/","pos":"n.","meaning":"国家；乡村；地区；故乡 a. 乡下的","example":"China is a large country with a long history.","exampleCn":"中国是一个历史悠久的大国。","level":"IELTS"},{"id":2038,"word":"american","phonetic":"/ә'merikәn/","pos":"n.","meaning":"美国人 a. 美国的；美洲的","example":"My new neighbor is an American from New York.","exampleCn":"我的新邻居是来自纽约的美国人。","level":"IELTS"},{"id":2039,"word":"different","phonetic":"/'difәrәnt/","pos":"adj.","meaning":"不同的 差动；微分的；差速器","example":"People from different countries have different customs.","exampleCn":"来自不同国家的人有不同的风俗。","level":"IELTS"},{"id":2040,"word":"hold","phonetic":"/hәuld/","pos":"n.","meaning":"把握；把持力；柄；控制","example":"Please hold the door open for the old man.","exampleCn":"请为那位老人扶住门。","level":"IELTS"},{"id":2041,"word":"end","phonetic":"/end/","pos":"n.","meaning":"结束；终点；目标；末端","example":"We waited until the end of the movie.","exampleCn":"我们一直等到电影结束。","level":"IELTS"},{"id":2042,"word":"bring","phonetic":"/briŋ/","pos":"vt.","meaning":"带来；产生；促使；提出 vi. 生产","example":"Don't forget to bring your homework to school tomorrow.","exampleCn":"别忘了明天把作业带到学校。","level":"IELTS"},{"id":2043,"word":"night","phonetic":"/nait/","pos":"n.","meaning":"夜；夜晚；晚上；黑暗","example":"The stars look very bright on a clear night.","exampleCn":"在晴朗的夜晚，星星看起来非常明亮。","level":"IELTS"},{"id":2044,"word":"live","phonetic":"/liv.laiv/","pos":"adj.","meaning":"活的；生动的；精力充沛的；实况转播的 vi. 活","example":"Many wild animals live in this great forest.","exampleCn":"许多野生动物生活在这片大森林里。","level":"IELTS"},{"id":2045,"word":"side","phonetic":"/said/","pos":"n.","meaning":"旁边；侧；方面；胁","example":"There is a small shop on the other side of the street.","exampleCn":"街道的另一边有一家小商店。","level":"IELTS"},{"id":2046,"word":"set","phonetic":"/set/","pos":"n.","meaning":"日落；同伙；组合；集合","example":"She bought a new set of cups for the kitchen.","exampleCn":"她为厨房买了一套新杯子。","level":"IELTS"},{"id":2047,"word":"month","phonetic":"/mʌnθ/","pos":"n.","meaning":"月 月","example":"We will move to the new house next month.","exampleCn":"我们下个月搬进新房子。","level":"IELTS"},{"id":2048,"word":"important","phonetic":"/im'pɒ:tәnt/","pos":"adj.","meaning":"重要的；有地位的；大量的；显要的","example":"Learning English is very important for your future career.","exampleCn":"学英语对你将来的职业非常重要。","level":"IELTS"},{"id":2049,"word":"eye","phonetic":"/ai/","pos":"n.","meaning":"眼睛；视力；看 vt. 看；注视","example":"He closed one eye and looked through the telescope.","exampleCn":"他闭上一只眼睛，透过望远镜观看。","level":"IELTS"},{"id":2050,"word":"million","phonetic":"/'miljәn/","pos":"n.","meaning":"百万；无数 num. 百万","example":"More than a million people visit this park every year.","exampleCn":"每年有一百多万人来这个公园游玩。","level":"IELTS"},{"id":2051,"word":"information","phonetic":"/.infә'meiʃәn/","pos":"n.","meaning":"消息；知识；通知；情报","example":"You can find more information on our website.","exampleCn":"你可以在我们的网站上找到更多信息。","level":"IELTS"},{"id":2052,"word":"water","phonetic":"/'wɒ:tә/","pos":"n.","meaning":"水；雨水；海水；水位","example":"Please drink more water after you exercise.","exampleCn":"运动后请多喝水。","level":"IELTS"},{"id":2053,"word":"pay","phonetic":"/pei/","pos":"n.","meaning":"薪资；付款；补偿 vt. 支付；付清","example":"I will pay for the dinner tonight.","exampleCn":"今晚的晚餐我来付钱。","level":"IELTS"},{"id":2054,"word":"room","phonetic":"/ru:m/","pos":"n.","meaning":"房间；空位；场所 vi. 住宿；居住 vt. 留宿","example":"My room has a big window facing the garden.","exampleCn":"我的房间有一扇朝向花园的大窗户。","level":"IELTS"},{"id":2055,"word":"mother","phonetic":"/'mʌðә/","pos":"n.","meaning":"母亲；修女院长 vt. 产生；照看；收养","example":"My mother cooks delicious food for us every day.","exampleCn":"我妈妈每天为我们做美味的饭菜。","level":"IELTS"},{"id":2056,"word":"money","phonetic":"/'mʌni/","pos":"n.","meaning":"金钱；一笔款；财富；货币","example":"He saves money every month to buy a car.","exampleCn":"他每个月存钱想买一辆车。","level":"IELTS"},{"id":2057,"word":"story","phonetic":"/'stɒ:ri/","pos":"n.","meaning":"故事；小说；传奇；描述","example":"Grandma told us an interesting story before bed.","exampleCn":"奶奶睡前给我们讲了一个有趣的故事。","level":"IELTS"},{"id":2058,"word":"development","phonetic":"/di'velәpmәnt/","pos":"n.","meaning":"发展 展开","example":"The rapid development of the city surprised everyone.","exampleCn":"这座城市的快速发展让所有人惊讶。","level":"IELTS"},{"id":2059,"word":"book","phonetic":"/buk/","pos":"n.","meaning":"书；书籍；帐簿；名册","example":"This book about animals is really interesting.","exampleCn":"这本关于动物的书真的很有趣。","level":"IELTS"},{"id":2060,"word":"form","phonetic":"/fɒ:m/","pos":"n.","meaning":"形状；形体；类型；方式","example":"Ice is a solid form of water.","exampleCn":"冰是水的一种固态形式。","level":"IELTS"},{"id":2061,"word":"study","phonetic":"/'stʌdi/","pos":"n.","meaning":"学习；研究；学科；论文","example":"The study of history helps us understand today.","exampleCn":"对历史的研究帮助我们理解今天。","level":"IELTS"},{"id":2062,"word":"second","phonetic":"/'sekәnd/","pos":"n.","meaning":"秒；瞬间；第二名；支持者","example":"Wait a second; I need to find my keys.","exampleCn":"等一下，我得找找我的钥匙。","level":"IELTS"},{"id":2063,"word":"job","phonetic":"/dʒɒb/","pos":"n.","meaning":"工作；零活；职业；事情 vi. 做零工","example":"She found a new job at a local bank.","exampleCn":"她在当地一家银行找到了一份新工作。","level":"IELTS"},{"id":2064,"word":"london","phonetic":"/'lʌndәn/","pos":"n.","meaning":"伦敦","example":"London is the capital city of the United Kingdom.","exampleCn":"伦敦是英国的首都。","level":"IELTS"},{"id":2065,"word":"black","phonetic":"/blæk/","pos":"n.","meaning":"黑色；黑颜料 a. 黑色的","example":"She wore a beautiful black dress to the party.","exampleCn":"她穿了一条漂亮的黑色连衣裙去参加聚会。","level":"IELTS"},{"id":2066,"word":"market","phonetic":"/'mɑ:kit/","pos":"n.","meaning":"市场；交易；集市；推销地区","example":"My grandmother buys fresh vegetables at the market every morning.","exampleCn":"我奶奶每天早上在市场买新鲜蔬菜。","level":"IELTS"},{"id":2067,"word":"nothing","phonetic":"/'nʌθiŋ/","pos":"n.","meaning":"无；不关紧要之事；零 adv. 毫不；决不 interj. 什么也没有","example":"There is nothing in the box; it is empty.","exampleCn":"盒子里什么也没有，它是空的。","level":"IELTS"},{"id":2068,"word":"idea","phonetic":"/ai'diә/","pos":"n.","meaning":"主意；办法；理想；思想","example":"That is a great idea; let's try it now.","exampleCn":"这个主意太好了，我们现在就试试吧。","level":"IELTS"},{"id":2069,"word":"stand","phonetic":"/stænd/","pos":"n.","meaning":"站立；站住；停顿；讲台","example":"She stepped onto the stand and began her speech.","exampleCn":"她走上讲台，开始了演讲。","level":"IELTS"},{"id":2070,"word":"report","phonetic":"/ri'pɒ:t/","pos":"n.","meaning":"报告；报道；传说；案情报告","example":"The manager asked me to write a report today.","exampleCn":"经理让我今天写一份报告。","level":"IELTS"},{"id":2071,"word":"face","phonetic":"/feis/","pos":"n.","meaning":"脸；面容；正面；外观 vt. 面对","example":"The girl had a big smile on her face.","exampleCn":"女孩脸上挂着灿烂的笑容。","level":"IELTS"},{"id":2072,"word":"carry","phonetic":"/'kæri/","pos":"n.","meaning":"进位；射程；运载 vt. 携带；运送","example":"Let me help you carry these heavy bags.","exampleCn":"让我帮你提这些沉重的袋子。","level":"IELTS"},{"id":2073,"word":"road","phonetic":"/rәud/","pos":"n.","meaning":"路；道路；公路；途径","example":"This road leads directly to the train station.","exampleCn":"这条路直通火车站。","level":"IELTS"},{"id":2074,"word":"city","phonetic":"/'siti/","pos":"n.","meaning":"城市；市 都市；城市；市","example":"Shanghai is the largest city in China.","exampleCn":"上海是中国最大的城市。","level":"IELTS"},{"id":2075,"word":"once","phonetic":"/wʌns/","pos":"adv.","meaning":"一次；曾经；一旦 conj. 一旦；一经 n. 一次 a. 从前的","example":"I visit my grandparents once a month.","exampleCn":"我每个月看望祖父母一次。","level":"IELTS"},{"id":2076,"word":"office","phonetic":"/'ɒfis/","pos":"n.","meaning":"办公室；部；公职；职责 办公室","example":"My father works in an office near the park.","exampleCn":"我爸爸在公园附近的一间办公室工作。","level":"IELTS"},{"id":2077,"word":"learn","phonetic":"/lә:n/","pos":"vt.","meaning":"学习；认识到；得知","example":"Children learn new things quickly at school.","exampleCn":"孩子们在学校里学新东西学得很快。","level":"IELTS"},{"id":2078,"word":"minute","phonetic":"/'minit. mai'nju:t/","pos":"n.","meaning":"分；分钟；片刻；备忘录","example":"The bus will arrive in about one minute.","exampleCn":"公交车大约一分钟后到达。","level":"IELTS"},{"id":2079,"word":"person","phonetic":"/'pә:sn/","pos":"n.","meaning":"人；人身；人称 人；法人","example":"She is the kindest person I have ever met.","exampleCn":"她是我见过的最善良的人。","level":"IELTS"},{"id":2080,"word":"best","phonetic":"/best/","pos":"adj.","meaning":"最好的 adv. 最好地 n. 最好的人","example":"This is the best book I have ever read.","exampleCn":"这是我读过的最好的一本书。","level":"IELTS"},{"id":2081,"word":"reason","phonetic":"/'ri:zn/","pos":"n.","meaning":"理由；原因；理智；道理","example":"Tell me the reason why you were late today.","exampleCn":"告诉我你今天迟到的原因。","level":"IELTS"},{"id":2082,"word":"several","phonetic":"/'sevәrәl/","pos":"adj.","meaning":"几个的；一些的；各自的 pron. 几个","example":"I have read this novel several times already.","exampleCn":"这本小说我已经读过好几遍了。","level":"IELTS"},{"id":2083,"word":"parent","phonetic":"/'perәnt/","pos":"n.","meaning":"父母；父母亲；根源 父亲；母亲","example":"Every parent wants the best for their children.","exampleCn":"每位父母都希望给孩子最好的。","level":"IELTS"},{"id":2084,"word":"fall","phonetic":"/fɒ:l/","pos":"n.","meaning":"落下；瀑布；采伐量；下降","example":"He had a bad fall and hurt his leg.","exampleCn":"他重重摔了一跤，伤了腿。","level":"IELTS"},{"id":2085,"word":"price","phonetic":"/prais/","pos":"n.","meaning":"价格；代价；价值 vt. 定...的价格","example":"The price of fresh fruit is rising quickly.","exampleCn":"新鲜水果的价格上涨得很快。","level":"IELTS"},{"id":2086,"word":"cost","phonetic":"/kɒst/","pos":"n.","meaning":"代价；价值；费用 vi. 花费 vt. 使失去；值","example":"The total cost of the trip was three hundred dollars.","exampleCn":"这次旅行的总费用是三百美元。","level":"IELTS"},{"id":2087,"word":"health","phonetic":"/'helθ/","pos":"n.","meaning":"健康；卫生；蓬勃；健康状态 健康","example":"Regular exercise is good for your health.","exampleCn":"经常锻炼对你的健康有好处。","level":"IELTS"},{"id":2088,"word":"subject","phonetic":"/'sʌbdʒekt/","pos":"n.","meaning":"科目；主题；臣民；主语","example":"Math is my favorite subject at school.","exampleCn":"数学是我在学校最喜欢的科目。","level":"IELTS"},{"id":2089,"word":"age","phonetic":"/eidʒ/","pos":"n.","meaning":"年龄；老年；成年；寿命","example":"Children start school at the age of six here.","exampleCn":"这里的孩子六岁开始上学。","level":"IELTS"},{"id":2090,"word":"britain","phonetic":"/'britәn/","pos":"n.","meaning":"英国","example":"Britain is an island country in western Europe.","exampleCn":"英国是西欧的一个岛国。","level":"IELTS"},{"id":2091,"word":"food","phonetic":"/fu:d/","pos":"n.","meaning":"食物；养料 食物；食品","example":"The restaurant serves delicious food at low prices.","exampleCn":"这家餐馆供应价格实惠的美味食物。","level":"IELTS"},{"id":2092,"word":"order","phonetic":"/'ɒ:dә/","pos":"n.","meaning":"次序；规则；命令 vi. 命令；定货 vt. 整理","example":"Please put these files in order before the meeting.","exampleCn":"请在会议前把这些文件按次序整理好。","level":"IELTS"},{"id":2093,"word":"air","phonetic":"/єә/","pos":"n.","meaning":"空气；旋律；态度 vt. 晾；使通风","example":"The morning air in the mountains is fresh and cool.","exampleCn":"山里早晨的空气清新凉爽。","level":"IELTS"},{"id":2094,"word":"teacher","phonetic":"/'ti:tʃә/","pos":"n.","meaning":"教师；老师；导师","example":"Our English teacher always makes the class interesting.","exampleCn":"我们的英语老师总能把课上得很有趣。","level":"IELTS"},{"id":2095,"word":"foot","phonetic":"/fut/","pos":"n.","meaning":"脚；步调；英尺；底部","example":"He hurt his left foot while playing football.","exampleCn":"他踢足球时伤了左脚。","level":"IELTS"},{"id":2096,"word":"street","phonetic":"/stri:t/","pos":"n.","meaning":"街道；马路；街区 a. 街道的","example":"The street is full of shops and restaurants.","exampleCn":"这条街上满是商店和餐馆。","level":"IELTS"},{"id":2097,"word":"mind","phonetic":"/maind/","pos":"n.","meaning":"思想；愿望；智力；记忆","example":"A healthy body keeps the mind clear and active.","exampleCn":"健康的身体使头脑清醒而活跃。","level":"IELTS"},{"id":2098,"word":"class","phonetic":"/klɑ:s/","pos":"n.","meaning":"班级；阶级；种类；课 vt. 分类 类别","example":"Our class has forty students this year.","exampleCn":"我们班今年有四十名学生。","level":"IELTS"},{"id":2099,"word":"clear","phonetic":"/kliә/","pos":"adj.","meaning":"清楚的；明确的；澄清的 adv. 清晰地 vt. 澄清；清除障碍 vi. 放晴","example":"The teacher gave us a clear answer to the question.","exampleCn":"老师对这个问题给了我们明确的回答。","level":"IELTS"},{"id":2100,"word":"music","phonetic":"/'mju:zik/","pos":"n.","meaning":"音乐；乐曲","example":"She listens to soft music before going to sleep.","exampleCn":"她睡前听轻柔的音乐。","level":"IELTS"},{"id":2101,"word":"paper","phonetic":"/'peipә/","pos":"n.","meaning":"纸；文件；文章；报纸","example":"Please write your name on this piece of paper.","exampleCn":"请把你的名字写在这张纸上。","level":"IELTS"},{"id":2102,"word":"bank","phonetic":"/bæŋk/","pos":"n.","meaning":"银行；堤；岸 库","example":"He went to the bank to save some money.","exampleCn":"他去银行存了一些钱。","level":"IELTS"},{"id":2103,"word":"table","phonetic":"/'teibl/","pos":"n.","meaning":"桌子；餐桌；工作台；铭文","example":"Dinner is ready; please sit at the table.","exampleCn":"晚饭好了，请到餐桌边坐下。","level":"IELTS"},{"id":2104,"word":"england","phonetic":"/'iŋglәnd/","pos":"n.","meaning":"英格兰 英格兰；英国","example":"England is famous for its long football history.","exampleCn":"英格兰以悠久的足球历史而闻名。","level":"IELTS"},{"id":2105,"word":"plan","phonetic":"/plæn/","pos":"n.","meaning":"计划；方案；策略；方法","example":"We made a plan for our summer trip.","exampleCn":"我们为夏季旅行制订了一个计划。","level":"IELTS"},{"id":2106,"word":"cut","phonetic":"/kʌt/","pos":"n.","meaning":"切口；割伤；降低；切","example":"He got a small cut on his finger while cooking.","exampleCn":"他做饭时手指上划了一个小口子。","level":"IELTS"},{"id":2107,"word":"college","phonetic":"/'kɒlidʒ/","pos":"n.","meaning":"学院；大学；学会","example":"My brother studies engineering at a famous college.","exampleCn":"我哥哥在一所著名的学院学习工程。","level":"IELTS"},{"id":2108,"word":"building","phonetic":"/'bildiŋ/","pos":"n.","meaning":"建筑物；建筑 营造；建筑；建筑物","example":"The tallest building in our city has eighty floors.","exampleCn":"我们城市最高的建筑有八十层。","level":"IELTS"},{"id":2109,"word":"return","phonetic":"/ri'tә:n/","pos":"n.","meaning":"回来；返回；来回票；归还","example":"We look forward to your safe return from the trip.","exampleCn":"我们期待你旅行平安归来。","level":"IELTS"},{"id":2110,"word":"town","phonetic":"/taun/","pos":"n.","meaning":"城镇；市；镇 城镇；城市","example":"She grew up in a small town by the sea.","exampleCn":"她在海边的一个小镇长大。","level":"IELTS"},{"id":2111,"word":"care","phonetic":"/kєә/","pos":"n.","meaning":"小心；照料；忧虑 vi. 关心；介意 vt. 在意","example":"Old people need extra care in the cold winter.","exampleCn":"老年人在寒冷的冬天需要额外的照料。","level":"IELTS"},{"id":2112,"word":"language","phonetic":"/'læŋgwidʒ/","pos":"n.","meaning":"语言；文字；措辞 语言","example":"English is an important language for international business.","exampleCn":"英语是国际商务中一门重要的语言。","level":"IELTS"},{"id":2113,"word":"hard","phonetic":"/hɑ:d/","pos":"adj.","meaning":"坚硬的；硬的；难的；艰苦的","example":"This rock is too hard to break by hand.","exampleCn":"这块石头太硬了，徒手砸不开。","level":"IELTS"},{"id":2114,"word":"field","phonetic":"/fi:ld/","pos":"n.","meaning":"领域；田地；场地；战场","example":"She is a famous expert in the field of medicine.","exampleCn":"她是医学领域的著名专家。","level":"IELTS"},{"id":2115,"word":"difficult","phonetic":"/'difikәlt/","pos":"adj.","meaning":"困难的","example":"This math problem is too difficult for me.","exampleCn":"这道数学题对我来说太难了。","level":"IELTS"},{"id":2116,"word":"pass","phonetic":"/pæs/","pos":"n.","meaning":"经过；要隘；途径；通行","example":"You need a pass to enter the building.","exampleCn":"你需要通行证才能进入这栋大楼。","level":"IELTS"},{"id":2117,"word":"better","phonetic":"/'betә/","pos":"adj.","meaning":"较好的 adv. 比较好","example":"Your English is much better than before.","exampleCn":"你的英语比以前好多了。","level":"IELTS"},{"id":2118,"word":"practice","phonetic":"/'præktis/","pos":"n.","meaning":"实践；练习；实行；惯例","example":"Daily practice is the key to learning the piano.","exampleCn":"每天练习是学好钢琴的关键。","level":"IELTS"},{"id":2119,"word":"letter","phonetic":"/'letә/","pos":"n.","meaning":"信；字母；证书；字面意义","example":"I wrote a long letter to my old friend.","exampleCn":"我给老朋友写了一封长信。","level":"IELTS"},{"id":2120,"word":"ground","phonetic":"/graund/","pos":"n.","meaning":"土地；战场；场地；地面","example":"The children sat on the ground and played games.","exampleCn":"孩子们坐在地上玩游戏。","level":"IELTS"},{"id":2121,"word":"meeting","phonetic":"/'mi:tiŋ/","pos":"n.","meaning":"会议；会面 会议；会谈；集会","example":"The meeting will start at nine tomorrow morning.","exampleCn":"会议将于明天上午九点开始。","level":"IELTS"},{"id":2122,"word":"heart","phonetic":"/hɑ:t/","pos":"n.","meaning":"心；心脏；中心；内心","example":"Running every day makes your heart strong.","exampleCn":"每天跑步能使你的心脏强健。","level":"IELTS"},{"id":2123,"word":"light","phonetic":"/lait/","pos":"n.","meaning":"光；光亮；灯；日光","example":"The light in the kitchen is too weak for reading.","exampleCn":"厨房的灯光太暗，不适合看书。","level":"IELTS"},{"id":2124,"word":"third","phonetic":"/θә:d/","pos":"num.","meaning":"第三；三分之一 第三；第三的","example":"This is my third visit to the museum.","exampleCn":"这是我第三次参观这家博物馆。","level":"IELTS"},{"id":2125,"word":"pull","phonetic":"/pul/","pos":"vt.","meaning":"拉；拖；拔；牵","example":"Please pull the door open; don't push it.","exampleCn":"请把门拉开，不要推。","level":"IELTS"},{"id":2126,"word":"land","phonetic":"/lænd/","pos":"n.","meaning":"陆地；地面；地界；地产","example":"The farmers grow rice on this rich land.","exampleCn":"农民们在这片肥沃的土地上种水稻。","level":"IELTS"},{"id":2127,"word":"break","phonetic":"/breik/","pos":"n.","meaning":"休息；中断；破裂处；绝交","example":"Let's take a short break after this lesson.","exampleCn":"这节课后我们休息一会儿吧。","level":"IELTS"},{"id":2128,"word":"short","phonetic":"/ʃɒ:t/","pos":"adj.","meaning":"短的；近的；矮的；短期的","example":"She wrote a short note and left quickly.","exampleCn":"她写了一张简短的便条就匆匆离开了。","level":"IELTS"},{"id":2129,"word":"season","phonetic":"/'si:zn/","pos":"n.","meaning":"季节；时节；当令期；时期 vt. 给...调味","example":"Autumn is the best season for hiking here.","exampleCn":"秋天是这里远足的最佳季节。","level":"IELTS"},{"id":2130,"word":"manager","phonetic":"/'mænidʒә/","pos":"n.","meaning":"经理；管理员；管理器 管理器","example":"The manager will meet the new workers this afternoon.","exampleCn":"经理今天下午会见新员工。","level":"IELTS"},{"id":2131,"word":"example","phonetic":"/ig'zæmpl/","pos":"n.","meaning":"例子；样本；实例 实例","example":"The teacher gave a simple example to explain the rule.","exampleCn":"老师举了一个简单的例子来解释这条规则。","level":"IELTS"},{"id":2132,"word":"european","phonetic":"/.juәrә'pi:әn/","pos":"n.","meaning":"欧洲人 a. 欧洲的；欧洲人的","example":"Many European countries use the euro as money.","exampleCn":"许多欧洲国家使用欧元作为货币。","level":"IELTS"},{"id":2133,"word":"pick","phonetic":"/pik/","pos":"n.","meaning":"精选；选择；掘；精华","example":"Take your pick from these beautiful flowers.","exampleCn":"从这些漂亮的花里挑你喜欢的吧。","level":"IELTS"},{"id":2134,"word":"window","phonetic":"/'windәu/","pos":"n.","meaning":"窗户；窗子；窗口 vt. 给...开窗 窗口","example":"She opened the window to let in fresh air.","exampleCn":"她打开窗户让新鲜空气进来。","level":"IELTS"},{"id":2135,"word":"wear","phonetic":"/wєә/","pos":"n.","meaning":"穿着；戴；使用；耗损","example":"I wear a warm coat in the cold winter.","exampleCn":"寒冷的冬天我穿一件暖和的外套。","level":"IELTS"},{"id":2136,"word":"cover","phonetic":"/'kʌvә/","pos":"n.","meaning":"盖子；封面；藉口 vt. 覆盖；掩饰","example":"She put a plastic cover on the new book.","exampleCn":"她给新书包上了塑料封皮。","level":"IELTS"},{"id":2137,"word":"center","phonetic":"/'sentә/","pos":"n.","meaning":"中心；中心点；中锋 a. 中央的；位在正中的 vt. 集中","example":"There is a beautiful fountain in the center of the park.","exampleCn":"公园中心有一座漂亮的喷泉。","level":"IELTS"},{"id":2138,"word":"star","phonetic":"/stɑ:/","pos":"n.","meaning":"星；恒星；星形物；运气","example":"The brightest star in the night sky is beautiful.","exampleCn":"夜空中最亮的那颗星非常美丽。","level":"IELTS"},{"id":2139,"word":"similar","phonetic":"/'similә/","pos":"adj.","meaning":"相似的；类似的 n. 相似的东西","example":"Your idea is quite similar to mine.","exampleCn":"你的想法和我的很相似。","level":"IELTS"},{"id":2140,"word":"worker","phonetic":"/'wә:kә/","pos":"n.","meaning":"工人；劳动者 工人；劳工；劳动者","example":"Every worker in the factory wears a safety helmet.","exampleCn":"工厂里的每个工人都戴着安全帽。","level":"IELTS"},{"id":2141,"word":"europe","phonetic":"/'juәrәp/","pos":"n.","meaning":"欧洲","example":"Many students travel around Europe during summer vacation.","exampleCn":"许多学生暑假期间环游欧洲。","level":"IELTS"},{"id":2142,"word":"picture","phonetic":"/'piktʃә/","pos":"n.","meaning":"图画；照片；景色；美丽如画的人(或物)","example":"She drew a beautiful picture of her hometown.","exampleCn":"她画了一幅家乡的美丽图画。","level":"IELTS"},{"id":2143,"word":"hospital","phonetic":"/'hɒspitәl/","pos":"n.","meaning":"医院 医院","example":"The new hospital is near the train station.","exampleCn":"新医院在火车站附近。","level":"IELTS"},{"id":2144,"word":"single","phonetic":"/'siŋgl/","pos":"adj.","meaning":"单身的；单程的；单一的；个别的","example":"He did not make a single mistake in the test.","exampleCn":"他在考试中一个错也没犯。","level":"IELTS"},{"id":2145,"word":"doctor","phonetic":"/'dɒktә/","pos":"n.","meaning":"医生；博士 vt. 授以博士学位；诊断；修改 vi. 行医","example":"You should see a doctor about that bad cough.","exampleCn":"你咳嗽得厉害，应该去看医生。","level":"IELTS"},{"id":2146,"word":"date","phonetic":"/deit/","pos":"n.","meaning":"日期；约会；枣椰树 vt. 约会；定日期 vi. 注明日期","example":"Please write today's date at the top of the page.","exampleCn":"请在页面顶部写上今天的日期。","level":"IELTS"},{"id":2147,"word":"wall","phonetic":"/wɒ:l/","pos":"n.","meaning":"墙；墙壁；垣；内壁","example":"There is a beautiful painting on the wall.","exampleCn":"墙上挂着一幅漂亮的画。","level":"IELTS"},{"id":2148,"word":"computer","phonetic":"/kәm'pju:tә/","pos":"n.","meaning":"电脑；电子计算机 计算机","example":"I use my computer to write emails every day.","exampleCn":"我每天用电脑写电子邮件。","level":"IELTS"},{"id":2149,"word":"catch","phonetic":"/kætʃ/","pos":"n.","meaning":"捕捉；陷阱；捕捉之物；抓","example":"The fisherman proudly showed us his big catch today.","exampleCn":"渔夫自豪地向我们展示他今天的丰硕渔获。","level":"IELTS"},{"id":2150,"word":"film","phonetic":"/film/","pos":"n.","meaning":"软片；薄膜；胶卷；电影 vt. 覆以薄膜","example":"We watched an interesting film about ocean animals.","exampleCn":"我们看了一部关于海洋动物的有趣电影。","level":"IELTS"},{"id":2151,"word":"tree","phonetic":"/tri:/","pos":"n.","meaning":"树；木料；树状物 vt. 把...赶上树 树；DOS外部命令:显示指定磁盘驱动器的目录结构","example":"The old tree in our garden gives cool shade.","exampleCn":"我们花园里的老树投下凉爽的树荫。","level":"IELTS"},{"id":2152,"word":"wide","phonetic":"/waid/","pos":"adj.","meaning":"宽的；广阔的；普遍的；宽阔的","example":"The river is too wide to swim across.","exampleCn":"这条河太宽了，游不过去。","level":"IELTS"},{"id":2153,"word":"secretary","phonetic":"/'sekrәtәri/","pos":"n.","meaning":"秘书；书记；大臣 秘书","example":"The secretary answered the phone and took notes.","exampleCn":"秘书接了电话并做了记录。","level":"IELTS"},{"id":2154,"word":"summer","phonetic":"/'sʌmә/","pos":"n.","meaning":"夏季；全盛时期 vi. 避暑；过夏天 加法器","example":"We go swimming almost every day in summer.","exampleCn":"夏天我们几乎每天都去游泳。","level":"IELTS"},{"id":2155,"word":"foreign","phonetic":"/'fɒ:rin/","pos":"adj.","meaning":"外国的；外交的；外省的；外来的","example":"She can speak three foreign languages very well.","exampleCn":"她能很流利地说三门外语。","level":"IELTS"},{"id":2156,"word":"plant","phonetic":"/plænt. plɑ:nt/","pos":"n.","meaning":"植物；作物；工厂；树枝","example":"This green plant needs water twice a week.","exampleCn":"这株绿色植物每周需要浇两次水。","level":"IELTS"},{"id":2157,"word":"agreement","phonetic":"/ә'gri:mәnt/","pos":"n.","meaning":"同意；合约；协议 契约；协议","example":"The two companies signed an agreement last week.","exampleCn":"两家公司上周签署了一项协议。","level":"IELTS"},{"id":2158,"word":"simple","phonetic":"/'simpl/","pos":"adj.","meaning":"简单的；普通的；朴素的；单纯的","example":"The recipe is simple, so anyone can cook it.","exampleCn":"这个食谱很简单，任何人都能做。","level":"IELTS"},{"id":2159,"word":"thousand","phonetic":"/'θauznd/","pos":"num.","meaning":"千 a. 成千的；许多的 n. 许许多多","example":"About a thousand people attended the concert last night.","exampleCn":"昨晚大约有一千人参加了音乐会。","level":"IELTS"},{"id":2160,"word":"future","phonetic":"/'fju:tʃә/","pos":"n.","meaning":"未来；将来 a. 将来的；未来的","example":"She has big plans for her future.","exampleCn":"她对自己的未来有宏大的计划。","level":"IELTS"},{"id":2161,"word":"shop","phonetic":"/ʃɒp/","pos":"n.","meaning":"商店；工厂；车间 vi. 购物；到处寻找 vt. 选购","example":"There is a small flower shop near my home.","exampleCn":"我家附近有一家小花店。","level":"IELTS"},{"id":2162,"word":"evening","phonetic":"/'i:vniŋ/","pos":"n.","meaning":"傍晚；晚间；末期","example":"We often take a walk in the evening.","exampleCn":"我们经常在傍晚散步。","level":"IELTS"},{"id":2163,"word":"animal","phonetic":"/'ænimәl/","pos":"n.","meaning":"动物 动物","example":"The elephant is the largest animal on land.","exampleCn":"大象是陆地上最大的动物。","level":"IELTS"},{"id":2164,"word":"fire","phonetic":"/'faiә/","pos":"n.","meaning":"火；炉火；电炉；火灾","example":"They sat around the fire and told stories.","exampleCn":"他们围坐在火堆旁讲故事。","level":"IELTS"},{"id":2165,"word":"fine","phonetic":"/fain/","pos":"n.","meaning":"罚款；罚金；晴天；精细 a. 好的","example":"He paid a fine for parking in the wrong place.","exampleCn":"他因停错车位交了罚款。","level":"IELTS"},{"id":2166,"word":"west","phonetic":"/west/","pos":"n.","meaning":"西方；西部 a. 西方的；向西的 adv. 向西；自西方","example":"The sun sets in the west every evening.","exampleCn":"太阳每天傍晚在西方落下。","level":"IELTS"},{"id":2167,"word":"sport","phonetic":"/spɒ:t/","pos":"n.","meaning":"运动；游戏；娱乐；消遣","example":"Swimming is my favorite sport in summer.","exampleCn":"游泳是我夏天最喜欢的运动。","level":"IELTS"},{"id":2168,"word":"per","phonetic":"/pә:/","pos":"prep.","meaning":"每一；通过；经；按照 每","example":"The tickets cost ten dollars per person.","exampleCn":"票价是每人十美元。","level":"IELTS"},{"id":2169,"word":"present","phonetic":"/'preznt/","pos":"n.","meaning":"现在；礼品；瞄准 a. 现在的；出席的 vt. 介绍","example":"She gave me a lovely present for my birthday.","exampleCn":"她送了我一份可爱的生日礼物。","level":"IELTS"},{"id":2170,"word":"april","phonetic":"/'eiprәl/","pos":"n.","meaning":"四月","example":"It often rains a lot in April here.","exampleCn":"这里四月经常下很多雨。","level":"IELTS"},{"id":2171,"word":"june","phonetic":"/dʒu:n/","pos":"n.","meaning":"六月","example":"Our final exams usually begin in early June.","exampleCn":"我们的期末考试通常在六月初开始。","level":"IELTS"},{"id":2172,"word":"march","phonetic":"/mɑ:tʃ/","pos":"n.","meaning":"三月；进行；行军；步伐","example":"The weather gets warmer in March every year.","exampleCn":"每年三月天气都会变暖。","level":"IELTS"},{"id":2173,"word":"size","phonetic":"/saiz/","pos":"n.","meaning":"大小；尺寸；规模；尺码","example":"Do you have these shoes in a bigger size?","exampleCn":"这款鞋有大一号的尺码吗？","level":"IELTS"},{"id":2174,"word":"store","phonetic":"/stɒ:/","pos":"n.","meaning":"商店；贮藏；仓库；备用品","example":"The store sells fresh fruit and vegetables every day.","exampleCn":"这家商店每天出售新鲜的水果和蔬菜。","level":"IELTS"},{"id":2175,"word":"garden","phonetic":"/'gɑ:dn/","pos":"n.","meaning":"花园；果园；菜园 vi. 栽培花木 vt. 造园 a. 花园的；普通的","example":"My grandmother grows roses in her small garden.","exampleCn":"我奶奶在她的小花园里种玫瑰。","level":"IELTS"},{"id":2176,"word":"sound","phonetic":"/saund/","pos":"n.","meaning":"声音；语音；吵闹；声调","example":"The sound of rain helps me sleep well.","exampleCn":"雨声帮助我睡得很香。","level":"IELTS"},{"id":2177,"word":"hotel","phonetic":"/hәu'tel/","pos":"n.","meaning":"旅馆；客栈","example":"We stayed at a comfortable hotel near the beach.","exampleCn":"我们住在海滩附近一家舒适的旅馆。","level":"IELTS"},{"id":2178,"word":"village","phonetic":"/'vilidʒ/","pos":"n.","meaning":"村庄 a. 乡村的；村庄的","example":"The quiet village lies at the foot of the mountain.","exampleCn":"这个安静的村庄坐落在山脚下。","level":"IELTS"},{"id":2179,"word":"station","phonetic":"/'steiʃәn/","pos":"n.","meaning":"车站；站；局；驻地","example":"The train station is only ten minutes away on foot.","exampleCn":"火车站步行只需十分钟。","level":"IELTS"},{"id":2180,"word":"cup","phonetic":"/kʌp/","pos":"n.","meaning":"杯子；茶杯；优胜杯 vt. 使成杯状；为...拔火罐","example":"Would you like a cup of hot tea?","exampleCn":"你想来一杯热茶吗？","level":"IELTS"},{"id":2181,"word":"machine","phonetic":"/mә'ʃi:n/","pos":"n.","meaning":"机器；机械装置；机构；自动售货机","example":"This machine can wash one hundred dishes an hour.","exampleCn":"这台机器一小时能洗一百个盘子。","level":"IELTS"},{"id":2182,"word":"modern","phonetic":"/'mɒdәn/","pos":"n.","meaning":"现代人；有思想的人 a. 现代的；时髦的","example":"The museum shows both modern and traditional art.","exampleCn":"这家博物馆同时展出现代和传统艺术。","level":"IELTS"},{"id":2183,"word":"scotland","phonetic":"/'skɒtlәnd/","pos":"n.","meaning":"苏格兰","example":"Scotland is famous for its beautiful lakes and mountains.","exampleCn":"苏格兰以美丽的湖泊和山脉而闻名。","level":"IELTS"},{"id":2184,"word":"science","phonetic":"/'saiәns/","pos":"n.","meaning":"科学；学科；学问；自然科学 科学","example":"Science helps us understand the natural world.","exampleCn":"科学帮助我们理解自然世界。","level":"IELTS"},{"id":2185,"word":"television","phonetic":"/'teli.viʒәn/","pos":"n.","meaning":"电视 电视","example":"We watch the news on television after dinner.","exampleCn":"晚饭后我们在电视上看新闻。","level":"IELTS"},{"id":2186,"word":"horse","phonetic":"/hɒ:s/","pos":"n.","meaning":"马；骑兵；脚架 vi. 骑马；取笑 vt. 使骑马","example":"The white horse runs fast across the field.","exampleCn":"那匹白马飞快地跑过田野。","level":"IELTS"},{"id":2187,"word":"glass","phonetic":"/glɑ:s/","pos":"n.","meaning":"玻璃；玻璃杯；透镜 vt. 装玻璃于；反射","example":"She filled the glass with cold water.","exampleCn":"她把玻璃杯倒满了凉水。","level":"IELTS"},{"id":2188,"word":"july","phonetic":"/dʒu:'lai/","pos":"n.","meaning":"七月","example":"The weather is usually very hot in July.","exampleCn":"七月的天气通常很热。","level":"IELTS"},{"id":2189,"word":"park","phonetic":"/pɑ:k/","pos":"n.","meaning":"公园；停车处 vt. 停车；置于 vi. 停车","example":"The children love playing in the park after school.","exampleCn":"孩子们喜欢放学后在公园里玩。","level":"IELTS"},{"id":2190,"word":"check","phonetic":"/tʃek/","pos":"n.","meaning":"检查；支票；阻止物；寄物牌","example":"Please check your answers before handing in the paper.","exampleCn":"交卷前请检查你的答案。","level":"IELTS"},{"id":2191,"word":"dark","phonetic":"/dɑ:k/","pos":"n.","meaning":"黑暗；夜；黄昏；模糊 a. 黑暗的","example":"The room was completely dark when the power went out.","exampleCn":"停电时房间里一片漆黑。","level":"IELTS"},{"id":2192,"word":"united","phonetic":"/ju:'naitid/","pos":"adj.","meaning":"联合的；团结的；一致的；和睦的 联合的","example":"The whole team stayed united during the hard season.","exampleCn":"整个球队在艰难的赛季中保持团结。","level":"IELTS"},{"id":2193,"word":"green","phonetic":"/gri:n/","pos":"n.","meaning":"绿色；绿色颜料 a. 绿色的；未成熟的；新鲜的","example":"The fields turn green when spring arrives.","exampleCn":"春天到来时，田野变得一片翠绿。","level":"IELTS"},{"id":2194,"word":"card","phonetic":"/kɑ:d/","pos":"n.","meaning":"卡片；纸牌；节目单；明信片","example":"She sent me a birthday card with warm wishes.","exampleCn":"她寄给我一张写满温暖祝福的生日贺卡。","level":"IELTS"},{"id":2195,"word":"seat","phonetic":"/si:t/","pos":"n.","meaning":"座；座位；位子；席位","example":"Please take a seat and wait for the doctor.","exampleCn":"请坐下等候医生。","level":"IELTS"},{"id":2196,"word":"post","phonetic":"/pәust/","pos":"n.","meaning":"柱；杆；准星；邮件","example":"I went to the post office to send a package.","exampleCn":"我去邮局寄了一个包裹。","level":"IELTS"},{"id":2197,"word":"spring","phonetic":"/spriŋ/","pos":"n.","meaning":"春天；弹簧；跳跃；弹性","example":"Flowers bloom everywhere when spring comes.","exampleCn":"春天来临时，鲜花到处盛开。","level":"IELTS"},{"id":2198,"word":"radio","phonetic":"/'reidiәu/","pos":"n.","meaning":"无线电；收音机；无线电报；无线电广播","example":"My grandfather listens to the radio every morning.","exampleCn":"我爷爷每天早上听收音机。","level":"IELTS"},{"id":2199,"word":"cultural","phonetic":"/'kʌltʃәrәl/","pos":"adj.","meaning":"文化的；教养的；修养的 培养的","example":"The city is famous for its rich cultural life.","exampleCn":"这座城市以丰富的文化生活而闻名。","level":"IELTS"},{"id":2200,"word":"october","phonetic":"/ɒk'tәubә/","pos":"n.","meaning":"十月","example":"The leaves turn red and gold in October.","exampleCn":"十月里树叶变成红色和金黄色。","level":"IELTS"},{"id":2201,"word":"fly","phonetic":"/flai/","pos":"n.","meaning":"苍蝇；两翼昆虫；飞行 vi. 飞；飞翔","example":"A fly kept buzzing around the kitchen table.","exampleCn":"一只苍蝇一直在厨房餐桌旁嗡嗡飞。","level":"IELTS"},{"id":2202,"word":"heavy","phonetic":"/'hevi/","pos":"adj.","meaning":"重的；巨大的；沉重的；笨重的","example":"This box is too heavy for me to lift.","exampleCn":"这个箱子太重了，我搬不动。","level":"IELTS"},{"id":2203,"word":"chair","phonetic":"/tʃєә/","pos":"n.","meaning":"椅子；显要的席位；主席 vt. 使入座；使就任要职","example":"Grandpa sat in his favorite chair by the window.","exampleCn":"爷爷坐在窗边他最喜欢的椅子上。","level":"IELTS"},{"id":2204,"word":"fish","phonetic":"/fiʃ/","pos":"n.","meaning":"鱼；鱼肉；鱼类；接合板 vt. 钓","example":"We had fresh fish for dinner last night.","exampleCn":"我们昨晚晚餐吃了新鲜的鱼。","level":"IELTS"},{"id":2205,"word":"holiday","phonetic":"/'hɒlәdi/","pos":"n.","meaning":"假日；假期；节日 vi. 度假","example":"We are planning a family holiday by the sea.","exampleCn":"我们正计划一次海边的家庭度假。","level":"IELTS"},{"id":2206,"word":"pupil","phonetic":"/'pju:pl/","pos":"n.","meaning":"学生；门生；未成年人；瞳孔 瞳孔","example":"Every pupil in the class raised their hand quickly.","exampleCn":"班上每个学生都迅速举起了手。","level":"IELTS"},{"id":2207,"word":"weight","phonetic":"/weit/","pos":"n.","meaning":"重；重量；体重；砝码","example":"The doctor checked my weight and height carefully.","exampleCn":"医生仔细测量了我的体重和身高。","level":"IELTS"},{"id":2208,"word":"trip","phonetic":"/trip/","pos":"n.","meaning":"旅行；绊倒；摔倒；失足","example":"We took a wonderful trip to the mountains last week.","exampleCn":"上周我们去山里进行了一次愉快的旅行。","level":"IELTS"},{"id":2209,"word":"september","phonetic":"/sep'tembә/","pos":"n.","meaning":"九月","example":"The new school year begins in September.","exampleCn":"新学年九月开始。","level":"IELTS"},{"id":2210,"word":"library","phonetic":"/'laibrәri/","pos":"n.","meaning":"图书馆；藏书；库 库","example":"I borrow books from the library every week.","exampleCn":"我每周从图书馆借书。","level":"IELTS"},{"id":2211,"word":"surface","phonetic":"/'sә:fis/","pos":"n.","meaning":"面；表面；水面；外表","example":"The surface of the lake is calm and smooth.","exampleCn":"湖面平静而光滑。","level":"IELTS"},{"id":2212,"word":"america","phonetic":"/ә'merikә/","pos":"n.","meaning":"美洲；美国","example":"She moved to America to study music last year.","exampleCn":"她去年搬到美国学习音乐。","level":"IELTS"},{"id":2213,"word":"trouble","phonetic":"/'trʌbl/","pos":"n.","meaning":"烦恼；麻烦；困难；动乱","example":"He had trouble finding the right address yesterday.","exampleCn":"他昨天费了很大劲才找到正确的地址。","level":"IELTS"},{"id":2214,"word":"january","phonetic":"/'dʒænjuәri/","pos":"n.","meaning":"一月","example":"January is usually the coldest month of the year.","exampleCn":"一月通常是一年中最冷的月份。","level":"IELTS"},{"id":2215,"word":"sunday","phonetic":"/'sʌndi/","pos":"n.","meaning":"星期日 a. 星期日的；业余的 vi. 度星期日","example":"We usually have a big family lunch on Sunday.","exampleCn":"我们通常在星期日吃一顿丰盛的家庭午餐。","level":"IELTS"},{"id":2216,"word":"beautiful","phonetic":"/'bju:tiful/","pos":"adj.","meaning":"美丽的","example":"The garden looks beautiful in the morning light.","exampleCn":"花园在晨光中显得很美丽。","level":"IELTS"},{"id":2217,"word":"text","phonetic":"/tekst/","pos":"n.","meaning":"文本；正文；课文；主题","example":"Please read the text carefully before answering the questions.","exampleCn":"回答问题前请仔细阅读课文。","level":"IELTS"},{"id":2218,"word":"western","phonetic":"/'westәn/","pos":"n.","meaning":"西方人；西部片；西部小说 a. 向西方的；来自西方的","example":"Many tourists visit the western part of the country.","exampleCn":"许多游客游览该国的西部地区。","level":"IELTS"},{"id":2219,"word":"york","phonetic":"/jɔ:k/","pos":"n.","meaning":"约克郡；约克王朝","example":"York is an old city with beautiful ancient walls.","exampleCn":"约克是一座有着美丽古城墙的古老城市。","level":"IELTS"},{"id":2220,"word":"beat","phonetic":"/bi:t/","pos":"n.","meaning":"心跳(声)；打；敲打声；拍子 v. 打","example":"I could hear the beat of my own heart.","exampleCn":"我能听到自己的心跳声。","level":"IELTS"},{"id":2221,"word":"fit","phonetic":"/fit/","pos":"n.","meaning":"适宜；合身；发作；痉挛 a. 适宜的","example":"This jacket is a perfect fit for you.","exampleCn":"这件夹克你穿正合身。","level":"IELTS"},{"id":2222,"word":"kitchen","phonetic":"/'kitʃin/","pos":"n.","meaning":"厨房；全套炊具 厨房","example":"Mom is cooking soup in the kitchen now.","exampleCn":"妈妈现在正在厨房里煮汤。","level":"IELTS"},{"id":2223,"word":"november","phonetic":"/nәu'vembә/","pos":"n.","meaning":"十一月","example":"The weather turns cold in late November here.","exampleCn":"这里十一月下旬天气转冷。","level":"IELTS"},{"id":2224,"word":"december","phonetic":"/di'sembә/","pos":"n.","meaning":"十二月","example":"We celebrate the new year at the end of December.","exampleCn":"我们在十二月底庆祝新年。","level":"IELTS"},{"id":2225,"word":"existing","phonetic":"/i^'zistiŋ/","pos":"adj.","meaning":"存在的；目前的；现存的；现有的 现成的","example":"The existing rules need to be updated soon.","exampleCn":"现有的规定需要尽快更新。","level":"IELTS"},{"id":2226,"word":"newspaper","phonetic":"/'nju:z.peipә/","pos":"n.","meaning":"报纸","example":"My father reads the newspaper with his morning coffee.","exampleCn":"我爸爸边喝早晨的咖啡边看报纸。","level":"IELTS"},{"id":2227,"word":"bear","phonetic":"/bєә/","pos":"n.","meaning":"熊 vt. 忍受；支承；产生；怀有","example":"We saw a big brown bear in the forest.","exampleCn":"我们在森林里看到一只大棕熊。","level":"IELTS"},{"id":2228,"word":"dinner","phonetic":"/'dinә/","pos":"n.","meaning":"晚餐；正餐；宴会","example":"We invited our neighbors to dinner on Saturday.","exampleCn":"我们邀请邻居周六来吃晚餐。","level":"IELTS"},{"id":2229,"word":"travel","phonetic":"/'trævl/","pos":"n.","meaning":"旅行；游历；行进 vi. 旅行；行进","example":"Air travel makes the world feel much smaller.","exampleCn":"航空旅行让世界显得小多了。","level":"IELTS"},{"id":2230,"word":"quarter","phonetic":"/'kwɒ:tә/","pos":"n.","meaning":"四分之一；一刻钟；季度；地区 vt. 四等分","example":"A quarter of the students come from other cities.","exampleCn":"四分之一的学生来自其他城市。","level":"IELTS"},{"id":2231,"word":"wind","phonetic":"/wind/","pos":"n.","meaning":"风；气息；气味；呼吸","example":"The cold wind blew strongly all night long.","exampleCn":"寒风刮了一整夜。","level":"IELTS"},{"id":2232,"word":"key","phonetic":"/ki:/","pos":"n.","meaning":"钥匙；键；解答；关键","example":"I left my key in the office again.","exampleCn":"我又把钥匙落在办公室了。","level":"IELTS"},{"id":2233,"word":"match","phonetic":"/mætʃ/","pos":"n.","meaning":"比赛；火柴；对手 vt. 使相配；使比赛","example":"We watched an exciting football match last night.","exampleCn":"昨晚我们观看了一场精彩的足球比赛。","level":"IELTS"},{"id":2234,"word":"railway","phonetic":"/'reilwei/","pos":"n.","meaning":"铁路；轨道 铁路","example":"The new railway connects the two big cities.","exampleCn":"新铁路连接了这两座大城市。","level":"IELTS"},{"id":2235,"word":"restaurant","phonetic":"/'restәrɒŋ/","pos":"n.","meaning":"餐馆；饭店","example":"This restaurant serves the best noodles in town.","exampleCn":"这家餐馆的面条是城里最好吃的。","level":"IELTS"},{"id":2236,"word":"credit","phonetic":"/'kredit/","pos":"n.","meaning":"信用；信任；荣誉；贷款","example":"He bought the new television on credit.","exampleCn":"他以赊账的方式买了那台新电视。","level":"IELTS"},{"id":2237,"word":"tea","phonetic":"/ti:/","pos":"n.","meaning":"茶；茶叶 茶；茶剂；浸剂","example":"My grandmother drinks green tea every afternoon.","exampleCn":"我奶奶每天下午喝绿茶。","level":"IELTS"},{"id":2238,"word":"saturday","phonetic":"/'sætәdi/","pos":"n.","meaning":"星期六","example":"We often go shopping together on Saturday morning.","exampleCn":"我们经常在星期六早上一起去购物。","level":"IELTS"},{"id":2239,"word":"perfect","phonetic":"/'pә:fikt/","pos":"n.","meaning":"完成时 a. 完美的；完好的；理想的；熟练的","example":"Today is a perfect day for a picnic.","exampleCn":"今天是野餐的完美日子。","level":"IELTS"},{"id":2240,"word":"conversation","phonetic":"/.kɒnvә'seiʃәn/","pos":"n.","meaning":"会话；说话；交谈 交谈；社交","example":"We had a pleasant conversation about our school days.","exampleCn":"我们围绕学生时代进行了一次愉快的交谈。","level":"IELTS"},{"id":2241,"word":"farm","phonetic":"/fɑ:m/","pos":"n.","meaning":"农场；农田 vt. 耕种 vi. 种田","example":"My uncle grows corn and rice on his farm.","exampleCn":"我叔叔在他的农场里种玉米和水稻。","level":"IELTS"},{"id":2242,"word":"oxford","phonetic":"/'ɒksfәd/","pos":"n.","meaning":"牛津；牛津大学","example":"Oxford is home to one of the oldest universities.","exampleCn":"牛津拥有世界上最古老的大学之一。","level":"IELTS"},{"id":2243,"word":"sleep","phonetic":"/sli:p/","pos":"n.","meaning":"睡眠；静止；昏迷；麻木","example":"Good sleep is very important for your health.","exampleCn":"良好的睡眠对健康非常重要。","level":"IELTS"},{"id":2244,"word":"copy","phonetic":"/'kɒpi/","pos":"n.","meaning":"副本；摹仿；一册 v. 复印；抄袭","example":"Please make a copy of this document for me.","exampleCn":"请帮我复印一份这份文件。","level":"IELTS"},{"id":2245,"word":"british","phonetic":"/'britiʃ/","pos":"adj.","meaning":"英国的 n. 英国人；英国英语","example":"The British weather changes quickly from sunny to rainy.","exampleCn":"英国的天气说变就变，一会儿晴一会儿雨。","level":"IELTS"},{"id":2246,"word":"train","phonetic":"/trein/","pos":"n.","meaning":"火车；列车；行列；长队","example":"The train to Beijing leaves at eight in the morning.","exampleCn":"开往北京的火车早上八点发车。","level":"IELTS"},{"id":2247,"word":"weekend","phonetic":"/'wi:kend/","pos":"n.","meaning":"周末；周末休假","example":"We are going camping in the mountains this weekend.","exampleCn":"这个周末我们要去山里露营。","level":"IELTS"},{"id":2248,"word":"pair","phonetic":"/pєә/","pos":"n.","meaning":"一双；一对；一副 v. (使)成对","example":"I bought a new pair of running shoes yesterday.","exampleCn":"我昨天买了一双新跑鞋。","level":"IELTS"},{"id":2249,"word":"chinese","phonetic":"/tʃai'ni:z/","pos":"n.","meaning":"中文；中国话；中国人 a. 中国的；中国话的","example":"She has studied Chinese for three years.","exampleCn":"她学中文已经三年了。","level":"IELTS"},{"id":2250,"word":"ship","phonetic":"/ʃip/","pos":"n.","meaning":"船；舰 vt. 以船运送；装船；运送 vi. 上船","example":"The big ship slowly left the busy port.","exampleCn":"那艘大船缓缓驶离繁忙的港口。","level":"IELTS"},{"id":2251,"word":"driver","phonetic":"/'draivә/","pos":"n.","meaning":"驾驶员；驱动器；驱动程序 驱动器","example":"The taxi driver knows every street in this city.","exampleCn":"这位出租车司机熟悉这座城市的每一条街道。","level":"IELTS"},{"id":2252,"word":"ice","phonetic":"/ais/","pos":"n.","meaning":"冰；冰淇淋；糖衣；冷若冰霜","example":"The lake is covered with thick ice in winter.","exampleCn":"冬天湖面上覆盖着厚厚的冰。","level":"IELTS"},{"id":2253,"word":"boat","phonetic":"/bәut/","pos":"n.","meaning":"船 vi. 乘船 vt. 以船运","example":"We took a small boat across the quiet river.","exampleCn":"我们乘一条小船渡过了平静的河。","level":"IELTS"},{"id":2254,"word":"exercise","phonetic":"/'eksәsaiz/","pos":"n.","meaning":"行使；执行；运动；练习","example":"Regular exercise keeps your body strong and healthy.","exampleCn":"经常运动能让身体强壮健康。","level":"IELTS"},{"id":2255,"word":"august","phonetic":"/ɒ:'gʌst. 'ɒ:gәst/","pos":"n.","meaning":"八月 a. 威严的；令人敬畏的","example":"We usually go to the seaside in August.","exampleCn":"我们通常在八月去海边。","level":"IELTS"},{"id":2256,"word":"mountain","phonetic":"/'mauntin/","pos":"n.","meaning":"山；山脉；大堆","example":"The highest mountain here is covered with snow all year.","exampleCn":"这里最高的山终年积雪。","level":"IELTS"},{"id":2257,"word":"regional","phonetic":"/'ri:dʒәnәl/","pos":"adj.","meaning":"地方的；地域性的 区的；部位的","example":"The regional government built new roads in the area.","exampleCn":"地方政府在该地区修建了新道路。","level":"IELTS"},{"id":2258,"word":"flower","phonetic":"/'flauә/","pos":"n.","meaning":"花；开花植物；精华；盛时 vi. 开花","example":"Every flower in the garden opens in early spring.","exampleCn":"园里的每一朵花都在早春绽放。","level":"IELTS"},{"id":2259,"word":"flight","phonetic":"/flait/","pos":"n.","meaning":"飞行；射程；逃走；飞跃","example":"Our flight to Paris leaves at six tomorrow morning.","exampleCn":"我们飞往巴黎的航班明早六点起飞。","level":"IELTS"},{"id":2260,"word":"guest","phonetic":"/gest/","pos":"n.","meaning":"客人；来宾；旅客 客体","example":"Every guest at the hotel received a warm welcome.","exampleCn":"旅馆的每位客人都受到了热情欢迎。","level":"IELTS"},{"id":2261,"word":"block","phonetic":"/blɒk/","pos":"n.","meaning":"街区；木块；石块；块 vt. 阻塞","example":"He lives just one block away from the school.","exampleCn":"他住的地方离学校只有一个街区。","level":"IELTS"},{"id":2262,"word":"clothes","phonetic":"/klәuðz/","pos":"n.","meaning":"衣服","example":"She packed some warm clothes for the winter trip.","exampleCn":"她为冬季旅行打包了一些保暖衣服。","level":"IELTS"},{"id":2263,"word":"telephone","phonetic":"/'telifәun/","pos":"n.","meaning":"电话；电话机 v. 打电话","example":"Please answer the telephone if it rings during dinner.","exampleCn":"晚饭时如果电话响了，请帮忙接一下。","level":"IELTS"},{"id":2264,"word":"warm","phonetic":"/wɒ:m/","pos":"adj.","meaning":"暖和的；暖的；温暖的；热烈的","example":"The room feels warm and comfortable in winter.","exampleCn":"冬天这个房间感觉温暖舒适。","level":"IELTS"},{"id":2265,"word":"french","phonetic":"/frentʃ/","pos":"n.","meaning":"法国人；法文；法式 a. 法国的；法国人的","example":"She speaks French fluently after living in Paris.","exampleCn":"在巴黎生活之后，她法语说得很流利。","level":"IELTS"},{"id":2266,"word":"coffee","phonetic":"/'kɒfi/","pos":"n.","meaning":"咖啡；咖啡色 咖啡；咖啡豆","example":"I always drink a cup of coffee before work.","exampleCn":"我上班前总要喝一杯咖啡。","level":"IELTS"},{"id":2267,"word":"bus","phonetic":"/bʌs/","pos":"n.","meaning":"公共汽车 总线；汇流条；母线","example":"He takes the bus to school every morning.","exampleCn":"他每天早上坐公共汽车上学。","level":"IELTS"},{"id":2268,"word":"meal","phonetic":"/mi:l/","pos":"n.","meaning":"一餐；膳食；粗粉 vi. 进餐","example":"We enjoyed a delicious meal at the new restaurant.","exampleCn":"我们在那家新餐馆享用了一顿美味的饭菜。","level":"IELTS"},{"id":2269,"word":"grade","phonetic":"/greid/","pos":"n.","meaning":"等级；年级；阶段；成绩","example":"She got the best grade in her math class.","exampleCn":"她在数学课上取得了最好的成绩。","level":"IELTS"},{"id":2270,"word":"bridge","phonetic":"/bridʒ/","pos":"n.","meaning":"桥；舰桥；桥梁；桥牌 vt. 架桥于","example":"The old stone bridge crosses the river near town.","exampleCn":"那座古老的石桥横跨镇边的河流。","level":"IELTS"},{"id":2271,"word":"dress","phonetic":"/dres/","pos":"n.","meaning":"服装；覆盖物 vi. 穿着 vt. 给...穿衣；整理","example":"She wore a beautiful red dress to the party.","exampleCn":"她穿着一条漂亮的红裙子去参加聚会。","level":"IELTS"},{"id":2272,"word":"housing","phonetic":"/'hausiŋ/","pos":"n.","meaning":"遮盖；住房供给；居留(处)；房屋","example":"The city needs more affordable housing for young families.","exampleCn":"这座城市需要为年轻家庭提供更多廉价住房。","level":"IELTS"},{"id":2273,"word":"famous","phonetic":"/'feimәs/","pos":"adj.","meaning":"出名的；极好的","example":"This small town is famous for its hot springs.","exampleCn":"这个小镇以温泉而闻名。","level":"IELTS"},{"id":2274,"word":"medicine","phonetic":"/'medisin/","pos":"n.","meaning":"药；医学；内科 vt. 给...用药","example":"Take this medicine twice a day after meals.","exampleCn":"这种药每天饭后服用两次。","level":"IELTS"},{"id":2275,"word":"classroom","phonetic":"/'klɑ:sru:m/","pos":"n.","meaning":"教室","example":"The students keep their classroom clean and tidy.","exampleCn":"学生们把教室保持得干净整洁。","level":"IELTS"},{"id":2276,"word":"factory","phonetic":"/'fæktәri/","pos":"n.","meaning":"工厂；产生地；代理店 工厂；代理店","example":"His father works in a car factory nearby.","exampleCn":"他父亲在附近一家汽车工厂工作。","level":"IELTS"},{"id":2277,"word":"clean","phonetic":"/kli:n/","pos":"adj.","meaning":"干净的；清白的；简洁的 adv. 清洁地；完全地 vt. 清理","example":"Please keep your hands clean before eating dinner.","exampleCn":"吃饭前请保持双手干净。","level":"IELTS"},{"id":2278,"word":"map","phonetic":"/mæp/","pos":"n.","meaning":"地图；天体图；映像 vt. 映射；绘制...地图","example":"We used a map to find the old castle.","exampleCn":"我们靠地图找到了那座古堡。","level":"IELTS"},{"id":2279,"word":"working","phonetic":"/'wә:kiŋ/","pos":"n.","meaning":"工作；运转；劳动 a. 工作的；劳动的","example":"Long working hours can harm your health.","exampleCn":"长时间工作会损害你的健康。","level":"IELTS"},{"id":2280,"word":"detailed","phonetic":"/'di:teild/","pos":"adj.","meaning":"详细的；复杂的 详细的；详尽的","example":"The report gives a detailed description of the accident.","exampleCn":"这份报告对事故作了详细的描述。","level":"IELTS"},{"id":2281,"word":"bedroom","phonetic":"/'bedrum/","pos":"n.","meaning":"卧室","example":"Her bedroom has a large window facing the garden.","exampleCn":"她的卧室有一扇朝向花园的大窗户。","level":"IELTS"},{"id":2282,"word":"ticket","phonetic":"/'tikit/","pos":"n.","meaning":"票；券；车票；标签","example":"I bought a train ticket to London yesterday.","exampleCn":"我昨天买了一张去伦敦的火车票。","level":"IELTS"},{"id":2283,"word":"expensive","phonetic":"/ik'spensiv/","pos":"adj.","meaning":"贵的；奢华的；费用浩大的；乱化钱的 高价的","example":"This watch is too expensive for me to buy.","exampleCn":"这块手表太贵了，我买不起。","level":"IELTS"},{"id":2284,"word":"lunch","phonetic":"/lʌntʃ/","pos":"n.","meaning":"午餐","example":"We had lunch together at a small cafe.","exampleCn":"我们一起在一家小咖啡馆吃了午餐。","level":"IELTS"},{"id":2285,"word":"educational","phonetic":"/.edju'keiʃәnl/","pos":"adj.","meaning":"教育的；教育性的","example":"The museum offers many educational programs for children.","exampleCn":"这家博物馆为孩子们提供许多教育项目。","level":"IELTS"},{"id":2286,"word":"sugar","phonetic":"/'ʃugә/","pos":"n.","meaning":"糖；糖块；甜言蜜语 vt. 加糖于；使甜蜜","example":"Would you like some sugar in your tea?","exampleCn":"你的茶里要加点糖吗？","level":"IELTS"},{"id":2287,"word":"weather","phonetic":"/'weðә/","pos":"n.","meaning":"天气；气象；处境 a. 迎风的 vt. 使受风吹雨打；侵蚀","example":"The weather today is perfect for a picnic.","exampleCn":"今天的天气非常适合野餐。","level":"IELTS"},{"id":2288,"word":"pleasure","phonetic":"/'pleʒә/","pos":"n.","meaning":"快乐；愉快；令人高兴的事；娱乐","example":"It is a great pleasure to meet you here.","exampleCn":"在这里见到你真是一件高兴的事。","level":"IELTS"},{"id":2289,"word":"friday","phonetic":"/'fraidi/","pos":"n.","meaning":"星期五","example":"We usually watch a movie together on Friday night.","exampleCn":"我们通常在星期五晚上一起看电影。","level":"IELTS"},{"id":2290,"word":"surprise","phonetic":"/sә'praiz/","pos":"n.","meaning":"惊奇；奇袭；诧异 vt. 使惊奇；撞见","example":"The birthday party was a wonderful surprise for her.","exampleCn":"这个生日聚会给了她一个美妙的惊喜。","level":"IELTS"},{"id":2291,"word":"double","phonetic":"/'dʌbl/","pos":"n.","meaning":"两倍 a. 两倍的；双重的 vt. 使加倍 vi. 加倍；代替；快步走 双精度型","example":"The price of the house is double what it was.","exampleCn":"这栋房子的价格是原来的两倍。","level":"IELTS"},{"id":2292,"word":"empty","phonetic":"/'empti/","pos":"adj.","meaning":"空的；空虚的；空腹的；空洞的 n. 空的东西","example":"The street was completely empty late at night.","exampleCn":"深夜的街道空无一人。","level":"IELTS"},{"id":2293,"word":"nurse","phonetic":"/nә:s/","pos":"n.","meaning":"护士；保姆；奶妈 vt. 看护；照顾","example":"The nurse takes care of patients with great patience.","exampleCn":"这位护士非常耐心地照顾病人。","level":"IELTS"},{"id":2294,"word":"desk","phonetic":"/desk/","pos":"n.","meaning":"书桌；办公桌；工作台","example":"He left his keys on the office desk again.","exampleCn":"他又把钥匙落在办公桌上了。","level":"IELTS"},{"id":2295,"word":"fruit","phonetic":"/fru:t/","pos":"n.","meaning":"水果；果类；结果 果实；种实","example":"Fresh fruit is good for your health every day.","exampleCn":"每天吃新鲜水果对健康有益。","level":"IELTS"},{"id":2296,"word":"yellow","phonetic":"/'jelәu/","pos":"n.","meaning":"黄色 a. 黄色的","example":"She painted the kitchen wall a bright yellow.","exampleCn":"她把厨房的墙刷成了明亮的黄色。","level":"IELTS"},{"id":2297,"word":"noise","phonetic":"/nɒiz/","pos":"n.","meaning":"噪音；杂音；响声；喧闹 vt. 谣传 vi. 喧闹 噪声","example":"The noise from the street kept me awake all night.","exampleCn":"街上的噪音让我整夜没睡着。","level":"IELTS"},{"id":2298,"word":"monday","phonetic":"/'mʌndi/","pos":"n.","meaning":"星期一","example":"The new store opens on Monday morning.","exampleCn":"这家新店星期一上午开业。","level":"IELTS"},{"id":2299,"word":"thinking","phonetic":"/'θiŋkiŋ/","pos":"n.","meaning":"思考；思想 a. 思考的；有理性的","example":"Careful thinking helps you avoid silly mistakes.","exampleCn":"仔细思考能帮你避免愚蠢的错误。","level":"IELTS"},{"id":2300,"word":"angry","phonetic":"/'æŋgri/","pos":"adj.","meaning":"生气的；愤怒的","example":"He was angry because the train was late again.","exampleCn":"火车又晚点了，他很生气。","level":"IELTS"},{"id":2301,"word":"hearing","phonetic":"/'hiәriŋ/","pos":"n.","meaning":"听；听觉；听讯 听；听觉","example":"Her hearing is excellent for someone of her age.","exampleCn":"以她的年纪来说，她的听觉非常好。","level":"IELTS"},{"id":2302,"word":"japanese","phonetic":"/.dʒæpә'ni:z/","pos":"n.","meaning":"日本人；日语 a. 日本的；日语的","example":"He has been learning Japanese for three years.","exampleCn":"他学日语已经三年了。","level":"IELTS"},{"id":2303,"word":"beauty","phonetic":"/'bju:ti/","pos":"n.","meaning":"美；美人","example":"The beauty of the sunset left us speechless.","exampleCn":"日落之美让我们说不出话来。","level":"IELTS"},{"id":2304,"word":"sick","phonetic":"/sik/","pos":"n.","meaning":"病人 a. 不舒服；有病的；恶心的；厌恶的","example":"She stayed home because she felt sick this morning.","exampleCn":"她今天早上感觉不舒服，所以待在家里。","level":"IELTS"},{"id":2305,"word":"airport","phonetic":"/'єәpɒ:t/","pos":"n.","meaning":"飞机场 航空站；机场","example":"We arrived at the airport two hours before the flight.","exampleCn":"我们在航班起飞前两小时到达机场。","level":"IELTS"},{"id":2306,"word":"suggestion","phonetic":"/sә'dʒestʃәn/","pos":"n.","meaning":"提议；意见 暗示","example":"Thank you for your helpful suggestion about the plan.","exampleCn":"谢谢你对这个计划提出的有益建议。","level":"IELTS"},{"id":2307,"word":"attractive","phonetic":"/ә'træktiv/","pos":"adj.","meaning":"吸引人的；有魅力的 有吸引力的；有迷惑力的","example":"The garden looks attractive with all the roses blooming.","exampleCn":"玫瑰盛开时，这座花园看起来非常迷人。","level":"IELTS"},{"id":2308,"word":"passage","phonetic":"/'pæsidʒ/","pos":"n.","meaning":"通道；通过；移居；航行","example":"A narrow passage leads to the back garden.","exampleCn":"一条狭窄的通道通向后花园。","level":"IELTS"},{"id":2309,"word":"meat","phonetic":"/mi:t/","pos":"n.","meaning":"肉；餐；食物 肉类","example":"Doctors advise us not to eat too much meat.","exampleCn":"医生建议我们不要吃太多肉。","level":"IELTS"},{"id":2310,"word":"effectively","phonetic":"/i'fektivli/","pos":"adv.","meaning":"有效地；有力地；实际上","example":"The new medicine works effectively against the disease.","exampleCn":"这种新药能有效地对抗这种疾病。","level":"IELTS"},{"id":2311,"word":"italy","phonetic":"/'itәli/","pos":"n.","meaning":"意大利","example":"Italy is famous for its art and delicious food.","exampleCn":"意大利以艺术和美食闻名。","level":"IELTS"},{"id":2312,"word":"lake","phonetic":"/leik/","pos":"n.","meaning":"湖；池；色淀 v. (使)血球溶解","example":"We went swimming in the lake last summer.","exampleCn":"去年夏天我们去湖里游泳。","level":"IELTS"},{"id":2313,"word":"gender","phonetic":"/'dʒendә/","pos":"n.","meaning":"性 vt. 产生","example":"Everyone deserves equal pay regardless of gender.","exampleCn":"不论性别，每个人都应获得同等报酬。","level":"IELTS"},{"id":2314,"word":"australia","phonetic":"/ɒ'streiljә/","pos":"n.","meaning":"澳洲；澳大利亚","example":"Australia is home to many unique animals like kangaroos.","exampleCn":"澳大利亚是袋鼠等许多独特动物的家园。","level":"IELTS"},{"id":2315,"word":"elderly","phonetic":"/'eldәli/","pos":"adj.","meaning":"过了中年的；稍老的","example":"An elderly man sat quietly on the park bench.","exampleCn":"一位老人静静地坐在公园的长椅上。","level":"IELTS"},{"id":2316,"word":"ocean","phonetic":"/'әuʃәn/","pos":"n.","meaning":"海洋；广阔；许多；一大片 海洋","example":"The ship sailed across the vast ocean for weeks.","exampleCn":"这艘船在浩瀚的海洋上航行了数周。","level":"IELTS"},{"id":2317,"word":"creation","phonetic":"/kri:'eiʃәn/","pos":"n.","meaning":"创造；创作物；发明 产生","example":"The creation of new jobs helped the local economy.","exampleCn":"新就业机会的创造促进了当地经济。","level":"IELTS"},{"id":2318,"word":"clause","phonetic":"/klɒ:z/","pos":"n.","meaning":"子句；条款 子句","example":"Please read every clause in the contract carefully.","exampleCn":"请仔细阅读合同中的每一项条款。","level":"IELTS"},{"id":2319,"word":"marketing","phonetic":"/'mɑ:kitiŋ/","pos":"n.","meaning":"行销；买卖 推销；在市场买卖；销售","example":"She works in the marketing department of a large company.","exampleCn":"她在一家大公司的市场营销部门工作。","level":"IELTS"},{"id":2320,"word":"coverage","phonetic":"/'kʌvәridʒ/","pos":"n.","meaning":"覆盖的范围；保险总额；新闻报导 可达范围；覆盖度","example":"The news coverage of the election lasted all week.","exampleCn":"对这次选举的新闻报道持续了一整周。","level":"IELTS"},{"id":2321,"word":"milk","phonetic":"/milk/","pos":"n.","meaning":"奶；乳状物 vt. 挤乳；榨取 vi. 产乳","example":"He drinks a glass of milk every morning.","exampleCn":"他每天早上喝一杯牛奶。","level":"IELTS"},{"id":2322,"word":"bind","phonetic":"/baind/","pos":"vt.","meaning":"绑；约束；装订；包扎","example":"Use this rope to bind the boxes together.","exampleCn":"用这根绳子把箱子捆在一起。","level":"IELTS"},{"id":2323,"word":"beach","phonetic":"/bi:tʃ/","pos":"n.","meaning":"海滩","example":"The children love playing on the sandy beach.","exampleCn":"孩子们喜欢在沙滩上玩耍。","level":"IELTS"},{"id":2324,"word":"vegetable","phonetic":"/'vedʒәtәbl/","pos":"n.","meaning":"蔬菜；植物；无精打采之人 a. 蔬菜的；植物的","example":"Eat at least one green vegetable with every meal.","exampleCn":"每餐至少吃一种绿色蔬菜。","level":"IELTS"},{"id":2325,"word":"palace","phonetic":"/'pælis/","pos":"n.","meaning":"宫；宫殿；华丽大厦","example":"The king lived in a magnificent palace by the river.","exampleCn":"国王住在河边一座宏伟的宫殿里。","level":"IELTS"},{"id":2326,"word":"abortion","phonetic":"/ә'bɒ:ʃәn/","pos":"n.","meaning":"流产；堕胎；失败；夭折","example":"The new law on abortion caused heated public debate.","exampleCn":"关于堕胎的新法律引发了激烈的公众争论。","level":"IELTS"},{"id":2327,"word":"mine","phonetic":"/main/","pos":"n.","meaning":"矿；矿藏；地雷 vt. 挖掘；开采","example":"Hundreds of workers go down the coal mine daily.","exampleCn":"数百名工人每天下到煤矿里工作。","level":"IELTS"},{"id":2328,"word":"wednesday","phonetic":"/'wenzdi/","pos":"n.","meaning":"星期三","example":"The meeting is scheduled for Wednesday afternoon.","exampleCn":"会议定于星期三下午举行。","level":"IELTS"},{"id":2329,"word":"grass","phonetic":"/græs/","pos":"n.","meaning":"草；草原；牧场 草；禾本","example":"The cows are eating fresh grass in the field.","exampleCn":"奶牛正在田野里吃新鲜的青草。","level":"IELTS"},{"id":2330,"word":"hat","phonetic":"/hæt/","pos":"n.","meaning":"帽子 vt. 给...戴帽子","example":"He wears a straw hat to protect against the sun.","exampleCn":"他戴着一顶草帽遮挡阳光。","level":"IELTS"},{"id":2331,"word":"breakfast","phonetic":"/'brekfәst/","pos":"n.","meaning":"早餐","example":"I usually have eggs and toast for breakfast.","exampleCn":"我早餐通常吃鸡蛋和吐司。","level":"IELTS"},{"id":2332,"word":"spain","phonetic":"/spein/","pos":"n.","meaning":"西班牙","example":"We spent two wonderful weeks in Spain last year.","exampleCn":"去年我们在西班牙度过了美好的两周。","level":"IELTS"},{"id":2333,"word":"fishing","phonetic":"/'fiʃiŋ/","pos":"n.","meaning":"钓鱼；鱼业 a. 钓鱼的","example":"My grandfather goes fishing by the river every weekend.","exampleCn":"我爷爷每个周末都去河边钓鱼。","level":"IELTS"},{"id":2334,"word":"licence","phonetic":"/'laisns/","pos":"n.","meaning":"执照；许可证；特许 vt. 许可；特许","example":"You need a driving licence to rent a car.","exampleCn":"租车需要驾驶执照。","level":"IELTS"},{"id":2335,"word":"database","phonetic":"/'deitәbeis/","pos":"n.","meaning":"数据库 数据库","example":"All customer records are stored in the database.","exampleCn":"所有客户记录都存储在数据库中。","level":"IELTS"},{"id":2336,"word":"fault","phonetic":"/fɒ:lt/","pos":"n.","meaning":"过错；故障；毛病 vt. 挑剔 vi. 产生断层；弄错 故障","example":"The accident was clearly not your fault.","exampleCn":"这起事故显然不是你的过错。","level":"IELTS"},{"id":2337,"word":"assistance","phonetic":"/ә'sistәns/","pos":"n.","meaning":"协助；援助 援助；帮助","example":"The old lady needs assistance to climb the stairs.","exampleCn":"这位老太太上楼梯需要人协助。","level":"IELTS"},{"id":2338,"word":"tension","phonetic":"/'tenʃәn/","pos":"n.","meaning":"紧张；不安；拉紧；张力","example":"You could feel the tension in the room before the exam.","exampleCn":"考试前你能感觉到房间里的紧张气氛。","level":"IELTS"},{"id":2339,"word":"russia","phonetic":"/'rʌʃә/","pos":"n.","meaning":"俄国；俄罗斯 俄罗斯；苏联","example":"Russia is the largest country in the world.","exampleCn":"俄罗斯是世界上面积最大的国家。","level":"IELTS"},{"id":2340,"word":"cheese","phonetic":"/tʃi:z/","pos":"n.","meaning":"乳酪 干酪","example":"She put some cheese on the fresh bread.","exampleCn":"她在新鲜面包上放了一些奶酪。","level":"IELTS"},{"id":2341,"word":"agenda","phonetic":"/ә'dʒendә/","pos":"n.","meaning":"pl. 议程；日常工作事项 待议事件","example":"The first item on the agenda is the budget report.","exampleCn":"议程的第一项是预算报告。","level":"IELTS"},{"id":2342,"word":"bother","phonetic":"/'bɒðә/","pos":"vt.","meaning":"烦扰；迷惑 vi. 烦恼；操心 n. 麻烦；纠纷","example":"Don't bother him while he is studying for exams.","exampleCn":"他在备考的时候不要去打扰他。","level":"IELTS"},{"id":2343,"word":"gene","phonetic":"/dʒi:n/","pos":"n.","meaning":"基因 基因(遗传因子)","example":"Scientists found a gene linked to this rare disease.","exampleCn":"科学家发现了一种与这种罕见疾病有关的基因。","level":"IELTS"},{"id":2344,"word":"boot","phonetic":"/bu:t/","pos":"n.","meaning":"长靴；踢；解雇；效用 vt. 使穿靴","example":"There is a small hole in my left boot.","exampleCn":"我的左靴子上有个小洞。","level":"IELTS"},{"id":2345,"word":"advertising","phonetic":"/'ædvәtaiziŋ/","pos":"n.","meaning":"广告业；广告 a. 广告的 发广告","example":"The company spends millions on advertising every year.","exampleCn":"这家公司每年在广告上花费数百万。","level":"IELTS"},{"id":2346,"word":"cop","phonetic":"/kɒp/","pos":"n.","meaning":"警官 vt. 抓住","example":"The cop stopped the car for speeding.","exampleCn":"警察因超速拦下了那辆车。","level":"IELTS"},{"id":2347,"word":"lock","phonetic":"/lɒk/","pos":"n.","meaning":"锁；刹车；水闸；一缕头发 vt. 锁","example":"The lock on the front door is broken again.","exampleCn":"前门的锁又坏了。","level":"IELTS"},{"id":2348,"word":"export","phonetic":"/ik'spɒ:t/","pos":"n.","meaning":"输出品；输出 vt. 输出；出口 vi. 输出物资 导出","example":"The country plans to export more rice next year.","exampleCn":"这个国家计划明年出口更多大米。","level":"IELTS"},{"id":2349,"word":"knife","phonetic":"/naif/","pos":"n.","meaning":"小刀；匕首 vt. 切割；伤害；切","example":"Be careful with that sharp knife in the kitchen.","exampleCn":"厨房里那把锋利的刀要小心使用。","level":"IELTS"},{"id":2350,"word":"countryside","phonetic":"/'kʌntrisaid/","pos":"n.","meaning":"乡下地方；乡下居民","example":"We drove through the beautiful countryside in autumn.","exampleCn":"秋天我们开车穿过美丽的乡村。","level":"IELTS"},{"id":2351,"word":"thursday","phonetic":"/'θә:zdi/","pos":"n.","meaning":"星期四","example":"The library stays open late on Thursday evenings.","exampleCn":"图书馆星期四晚上开放到很晚。","level":"IELTS"},{"id":2352,"word":"arrival","phonetic":"/ә'raivl/","pos":"n.","meaning":"到达；抵达；到达者 到达；到达物","example":"The arrival of the train was delayed by heavy snow.","exampleCn":"火车因大雪而延迟到达。","level":"IELTS"},{"id":2353,"word":"illness","phonetic":"/'ilnis/","pos":"n.","meaning":"疾病；恶意 病","example":"He missed two weeks of work because of illness.","exampleCn":"他因病缺勤了两周。","level":"IELTS"},{"id":2354,"word":"amazing","phonetic":"/ә'meiziŋ/","pos":"adj.","meaning":"令人惊异的","example":"The view from the top of the hill is amazing.","exampleCn":"从山顶看到的景色令人惊叹。","level":"IELTS"},{"id":2355,"word":"juice","phonetic":"/dʒu:s/","pos":"n.","meaning":"汁；活力；体液 vt. 挤出汁来；加汁","example":"She squeezed fresh orange juice for breakfast.","exampleCn":"她为早餐榨了新鲜的橙汁。","level":"IELTS"},{"id":2356,"word":"parking","phonetic":"/'pɑ:kiŋ/","pos":"n.","meaning":"停车 a. 停车的","example":"Finding a parking space downtown is always difficult.","exampleCn":"在市中心找停车位总是很难。","level":"IELTS"},{"id":2357,"word":"spending","phonetic":"/'spendiŋ/","pos":"n.","meaning":"经费；开销 开支；开销；经费","example":"The government plans to cut spending on defense.","exampleCn":"政府计划削减国防开支。","level":"IELTS"},{"id":2358,"word":"accomplish","phonetic":"/ә'kʌmpliʃ/","pos":"vt.","meaning":"完成；达到；实现；使完美","example":"With hard work, you can accomplish anything you want.","exampleCn":"只要努力，你就能实现任何目标。","level":"IELTS"},{"id":2359,"word":"tuesday","phonetic":"/'tju:zdi/","pos":"n.","meaning":"星期二","example":"The art class meets every Tuesday at three.","exampleCn":"美术课每周二下午三点上课。","level":"IELTS"},{"id":2360,"word":"anger","phonetic":"/'æŋgә/","pos":"n.","meaning":"忿怒 vt. 激怒；使发怒 vi. 发怒","example":"He tried hard to control his anger during the argument.","exampleCn":"争吵中他努力控制自己的愤怒。","level":"IELTS"},{"id":2361,"word":"chancellor","phonetic":"/'tʃɑ:nsәlә/","pos":"n.","meaning":"大臣；总理；首相；大使馆/领事馆的一等秘书","example":"The chancellor announced a new economic plan today.","exampleCn":"总理今天宣布了一项新的经济计划。","level":"IELTS"},{"id":2362,"word":"luck","phonetic":"/lʌk/","pos":"n.","meaning":"运气；幸运；好运；侥幸 vi. 靠好运成功","example":"With a little luck, we will finish the project early.","exampleCn":"运气好的话，我们会提前完成这个项目。","level":"IELTS"},{"id":2363,"word":"tourist","phonetic":"/'tuәrist/","pos":"n.","meaning":"观光客；旅行者 a. 旅游的","example":"Every tourist wants to take photos of the old tower.","exampleCn":"每个游客都想给这座古塔拍照。","level":"IELTS"},{"id":2364,"word":"cambridge","phonetic":"/'keimbridʒ/","pos":"n.","meaning":"剑桥","example":"She studied history at Cambridge for four years.","exampleCn":"她在剑桥学了四年历史。","level":"IELTS"},{"id":2365,"word":"bathroom","phonetic":"/'bɑ:θru:m/","pos":"n.","meaning":"浴室；厕所","example":"The bathroom is at the end of the hallway.","exampleCn":"浴室在走廊的尽头。","level":"IELTS"},{"id":2366,"word":"awareness","phonetic":"/ә'weәnis/","pos":"n.","meaning":"意识；认识 识别；议定；明白","example":"The campaign raised public awareness of climate change.","exampleCn":"这项活动提高了公众对气候变化的意识。","level":"IELTS"},{"id":2367,"word":"smoke","phonetic":"/smәuk/","pos":"n.","meaning":"烟；雾气；烟熏剂；抽烟","example":"Thick smoke rose from the burning building.","exampleCn":"浓烟从燃烧的大楼里升起。","level":"IELTS"},{"id":2368,"word":"fifth","phonetic":"/fifθ/","pos":"num.","meaning":"第五；五分之一","example":"Her office is on the fifth floor of the building.","exampleCn":"她的办公室在这栋楼的第五层。","level":"IELTS"},{"id":2369,"word":"designer","phonetic":"/di'zainә/","pos":"n.","meaning":"设计者；谋划者；制图者 设计员","example":"The designer created a simple logo for the company.","exampleCn":"这位设计师为公司设计了一个简洁的标志。","level":"IELTS"},{"id":2370,"word":"brilliant","phonetic":"/'briljәnt/","pos":"adj.","meaning":"光辉的；灿烂的；有才气的 亮的","example":"She came up with a brilliant idea for the project.","exampleCn":"她为这个项目想出了一个绝妙的主意。","level":"IELTS"},{"id":2371,"word":"recording","phonetic":"/ri'kɒ:diŋ/","pos":"adj.","meaning":"记录的；记录用的 n. 录音","example":"We listened to an old recording of his speech.","exampleCn":"我们听了一段他演讲的旧录音。","level":"IELTS"},{"id":2372,"word":"breach","phonetic":"/bri:tʃ/","pos":"n.","meaning":"裂口；违背；破坏；违反","example":"Selling the data was a clear breach of the contract.","exampleCn":"出售这些数据明显违反了合同。","level":"IELTS"},{"id":2373,"word":"enquiry","phonetic":"/in'kwaiәri/","pos":"n.","meaning":"询问 询价；询盘","example":"We received an enquiry about the price of the goods.","exampleCn":"我们收到了一份关于货物价格的询价。","level":"IELTS"},{"id":2374,"word":"administrator","phonetic":"/әd'ministreitә/","pos":"n.","meaning":"管理人；行政官 遗产管理人员","example":"The administrator manages the daily affairs of the school.","exampleCn":"这位管理人员负责学校的日常事务。","level":"IELTS"},{"id":2375,"word":"mail","phonetic":"/meil/","pos":"n.","meaning":"邮件；邮政；邮递；盔甲 vt. 邮寄","example":"I check my mail every morning before work.","exampleCn":"我每天上班前都会查看邮件。","level":"IELTS"},{"id":2376,"word":"buck","phonetic":"/bʌk/","pos":"n.","meaning":"元；雄鹿；纨绔子弟；鞍马","example":"The ticket only costs a buck at the corner store.","exampleCn":"这张票在街角小店只卖一美元。","level":"IELTS"},{"id":2377,"word":"favor","phonetic":"/'feivә/","pos":"n.","meaning":"好意；喜爱 vt. 赐予；支持；喜欢","example":"Could you do me a favor and close the window?","exampleCn":"你能帮我个忙把窗户关上吗？","level":"IELTS"},{"id":2378,"word":"birmingham","phonetic":"/'bә:miŋәm/","pos":"n.","meaning":"伯明翰","example":"Birmingham is one of the largest cities in England.","exampleCn":"伯明翰是英格兰最大的城市之一。","level":"IELTS"},{"id":2379,"word":"infection","phonetic":"/in'fekʃәn/","pos":"n.","meaning":"传染；影响；传染病 传染；感染","example":"Wash your hands often to prevent infection.","exampleCn":"勤洗手以预防感染。","level":"IELTS"},{"id":2380,"word":"clock","phonetic":"/klɒk/","pos":"n.","meaning":"时钟；计时器；(袜子上的)绣花边花 vt. 绣花样；记时","example":"The clock on the wall shows half past nine.","exampleCn":"墙上的时钟显示九点半。","level":"IELTS"},{"id":2381,"word":"demonstration","phonetic":"/.demәn'streiʃәn/","pos":"n.","meaning":"示范；实证 示教；实物教授","example":"The teacher gave a demonstration of the science experiment.","exampleCn":"老师对这个科学实验作了示范。","level":"IELTS"},{"id":2382,"word":"bath","phonetic":"/bæθ.bɑ:θ/","pos":"n.","meaning":"沐浴；浴室 浴","example":"She takes a hot bath after work every evening.","exampleCn":"她每天晚上下班后洗个热水澡。","level":"IELTS"},{"id":2383,"word":"advanced","phonetic":"/әd'vɑ:nst/","pos":"adj.","meaning":"在前的；高级的；先进的；年老的 预付的","example":"This course is designed for advanced students only.","exampleCn":"这门课程仅为高级水平的学生开设。","level":"IELTS"},{"id":2384,"word":"biological","phonetic":"/.baiәu'lɒdʒikәl/","pos":"adj.","meaning":"生物学的 生物学的","example":"The students study biological processes in the lab.","exampleCn":"学生们在实验室里研究生物学过程。","level":"IELTS"},{"id":2385,"word":"killer","phonetic":"/'kilә/","pos":"n.","meaning":"(非正式)杀人者；屠杀者；猛兽；致死(疾病)","example":"The police finally caught the killer after two years.","exampleCn":"警方两年后终于抓住了凶手。","level":"IELTS"},{"id":2386,"word":"chocolate","phonetic":"/'tʃɒkәlit/","pos":"n.","meaning":"巧克力 a. 巧克力制的","example":"She gave me a box of chocolate for my birthday.","exampleCn":"她送了我一盒巧克力作为生日礼物。","level":"IELTS"},{"id":2387,"word":"canadian","phonetic":"/kә'neidiәn/","pos":"adj.","meaning":"加拿大的","example":"He married a Canadian woman from Toronto.","exampleCn":"他娶了一位来自多伦多的加拿大女子。","level":"IELTS"},{"id":2388,"word":"clothing","phonetic":"/'klәuðiŋ/","pos":"n.","meaning":"衣服","example":"Warm clothing is necessary for the winter trip.","exampleCn":"冬季旅行需要保暖的衣物。","level":"IELTS"},{"id":2389,"word":"cooperation","phonetic":"/kәu.ɒpә'reiʃәn/","pos":"n.","meaning":"合作；协力；配合 合作","example":"The project succeeded thanks to close cooperation between teams.","exampleCn":"由于团队间的密切合作，这个项目取得了成功。","level":"IELTS"},{"id":2390,"word":"disabled","phonetic":"/dis'eibld/","pos":"adj.","meaning":"残废的；有缺陷的；失效的 失效的","example":"The hotel has special rooms for disabled guests.","exampleCn":"这家旅馆为残障客人设有专用房间。","level":"IELTS"},{"id":2391,"word":"practitioner","phonetic":"/præk'tiʃәnә/","pos":"n.","meaning":"从业者；开业者 行医者；医师","example":"She is a respected medical practitioner in this town.","exampleCn":"她是这个镇上一位受人尊敬的医师。","level":"IELTS"},{"id":2392,"word":"sheep","phonetic":"/ʃi:p/","pos":"n.","meaning":"羊；胆小者","example":"The farmer keeps over a hundred sheep on the hill.","exampleCn":"这位农夫在山上养了一百多只羊。","level":"IELTS"},{"id":2393,"word":"bet","phonetic":"/bet/","pos":"n.","meaning":"打赌；赌注 v. 打赌","example":"I bet he will win the race tomorrow.","exampleCn":"我打赌他明天会赢得比赛。","level":"IELTS"},{"id":2394,"word":"asia","phonetic":"/'eiʒә/","pos":"n.","meaning":"亚洲","example":"Asia is the largest continent on the earth.","exampleCn":"亚洲是地球上最大的洲。","level":"IELTS"},{"id":2395,"word":"genetic","phonetic":"/dʒi'netik/","pos":"adj.","meaning":"创始的；遗传的；起源的；遗传学的 生殖的","example":"Some diseases are caused by genetic factors.","exampleCn":"有些疾病是由遗传因素引起的。","level":"IELTS"},{"id":2396,"word":"related","phonetic":"/ri'leitid/","pos":"adj.","meaning":"讲述的；叙述的；有关系的；有关联的","example":"The two problems are closely related to each other.","exampleCn":"这两个问题彼此密切相关。","level":"IELTS"},{"id":2397,"word":"processing","phonetic":"/prәu'sesiŋ/","pos":"n.","meaning":"处理 加工","example":"The factory handles the processing of fresh fruit.","exampleCn":"这家工厂负责新鲜水果的加工。","level":"IELTS"},{"id":2398,"word":"olympic","phonetic":"/әu'limpik/","pos":"adj.","meaning":"奥林匹亚的；奥林匹斯山的；强有力的；巨大的","example":"She won a gold medal at the Olympic Games.","exampleCn":"她在奥运会上赢得了一枚金牌。","level":"IELTS"},{"id":2399,"word":"rice","phonetic":"/rais/","pos":"n.","meaning":"米；米饭；稻 vt. 将...压成米粒状","example":"People in southern China eat rice every day.","exampleCn":"中国南方人每天都吃米饭。","level":"IELTS"},{"id":2400,"word":"bible","phonetic":"/'baibl/","pos":"n.","meaning":"圣经","example":"He reads a passage from the Bible every night.","exampleCn":"他每天晚上读一段圣经。","level":"IELTS"},{"id":2401,"word":"tournament","phonetic":"/'tә:nәmәnt/","pos":"n.","meaning":"比赛；竞赛；锦标赛；联赛","example":"Our team reached the final of the tennis tournament.","exampleCn":"我们队打进了网球锦标赛的决赛。","level":"IELTS"},{"id":2402,"word":"hunting","phonetic":"/'hʌntiŋ/","pos":"n.","meaning":"狩猎；猎狐；探求 寻找平衡；寻找","example":"Hunting is strictly forbidden in this national park.","exampleCn":"这个国家公园严禁狩猎。","level":"IELTS"},{"id":2403,"word":"bristol","phonetic":"/'bristәl/","pos":"n.","meaning":"布里斯托尔(英国西部港口)","example":"Bristol is a lively port city in western England.","exampleCn":"布里斯托尔是英格兰西部一座充满活力的港口城市。","level":"IELTS"},{"id":2404,"word":"dialogue","phonetic":"/'daiәlɒg/","pos":"n.","meaning":"对话 vi. 对话 vt. 用对话表达","example":"The two countries began a dialogue to solve the dispute.","exampleCn":"两国开始对话以解决争端。","level":"IELTS"},{"id":2405,"word":"standing","phonetic":"/'stændiŋ/","pos":"n.","meaning":"起立；持续；身分 a. 立着的；不动的","example":"He has a high standing in the local community.","exampleCn":"他在当地社区享有很高的地位。","level":"IELTS"},{"id":2406,"word":"bake","phonetic":"/beik/","pos":"vt.","meaning":"烘焙；烤 vi. 烤面包 n. 烘焙；烤","example":"My mother taught me how to bake fresh bread.","exampleCn":"我妈妈教我如何烤新鲜面包。","level":"IELTS"},{"id":2407,"word":"announcement","phonetic":"/ә'naunsmәnt/","pos":"n.","meaning":"公告；发表；告知 通告；布告","example":"The company made an announcement about the new product.","exampleCn":"公司发布了关于新产品的公告。","level":"IELTS"},{"id":2408,"word":"tennis","phonetic":"/'tenis/","pos":"n.","meaning":"网球","example":"They play tennis together every Saturday morning.","exampleCn":"他们每周六早上一起打网球。","level":"IELTS"},{"id":2409,"word":"excitement","phonetic":"/ik'saitmәnt/","pos":"n.","meaning":"刺激；兴奋 兴奋；激动","example":"The children could not hide their excitement before the trip.","exampleCn":"出发旅行前，孩子们掩饰不住内心的兴奋。","level":"IELTS"},{"id":2410,"word":"deaf","phonetic":"/def/","pos":"adj.","meaning":"聋的 聋的","example":"The old man is deaf in one ear.","exampleCn":"这位老人一只耳朵聋了。","level":"IELTS"},{"id":2411,"word":"berlin","phonetic":"/bә:'lin/","pos":"n.","meaning":"柏林；(软质)柏林毛线","example":"Berlin is the capital and largest city of Germany.","exampleCn":"柏林是德国的首都和最大城市。","level":"IELTS"},{"id":2412,"word":"guardian","phonetic":"/'gɑ:diәn/","pos":"n.","meaning":"看守者；监护人；保护人 a. 保护的","example":"Her uncle became her legal guardian after the accident.","exampleCn":"事故后她的叔叔成了她的法定监护人。","level":"IELTS"},{"id":2413,"word":"dining","phonetic":"/'dainiŋ/","pos":"n.","meaning":"正餐；宴会","example":"The family gathered in the dining room for dinner.","exampleCn":"全家人聚在餐厅吃晚饭。","level":"IELTS"},{"id":2414,"word":"fantasy","phonetic":"/'fæntәsi/","pos":"n.","meaning":"幻想；想象的产物 幻想","example":"The novel is a fantasy about dragons and magic.","exampleCn":"这部小说是一个关于龙和魔法的幻想故事。","level":"IELTS"},{"id":2415,"word":"ongoing","phonetic":"/'ɒngәuiŋ/","pos":"adj.","meaning":"前进的；进行的；不间断的 n. 前进；发展","example":"The ongoing repairs will close the road for weeks.","exampleCn":"正在进行的维修将使这条路封闭数周。","level":"IELTS"},{"id":2416,"word":"guideline","phonetic":"/'gaidlain/","pos":"n.","meaning":"指导路线；方针；指标 指导路线；方针","example":"The new guideline explains how to handle customer complaints.","exampleCn":"新的指导方针说明了如何处理客户投诉。","level":"IELTS"},{"id":2417,"word":"alarm","phonetic":"/ә'lɑ:m/","pos":"n.","meaning":"惊恐；警报；警钟 vt. 使惊恐；警告 报警信号","example":"The fire alarm went off in the middle of the night.","exampleCn":"火警警报在半夜响了起来。","level":"IELTS"},{"id":2418,"word":"clever","phonetic":"/'klevә/","pos":"adj.","meaning":"聪明的；精明的","example":"The clever boy solved the puzzle in two minutes.","exampleCn":"这个聪明的男孩两分钟就解开了谜题。","level":"IELTS"},{"id":2419,"word":"flesh","phonetic":"/'fleʃ/","pos":"n.","meaning":"肉；肉体；肉欲；人性","example":"The flesh of this fish is white and tender.","exampleCn":"这种鱼的肉又白又嫩。","level":"IELTS"},{"id":2420,"word":"equivalent","phonetic":"/i'kwivәlәnt/","pos":"n.","meaning":"同等物；等价物；相等物 a. 相等的；相当的","example":"A mile is roughly equivalent to 1.6 kilometers.","exampleCn":"一英里大约相当于1.6公里。","level":"IELTS"},{"id":2421,"word":"scandal","phonetic":"/'skændәl/","pos":"n.","meaning":"丑闻；中伤；耻辱；反感","example":"The scandal forced the minister to resign from office.","exampleCn":"这桩丑闻迫使部长辞职下台。","level":"IELTS"},{"id":2422,"word":"dividend","phonetic":"/'dividend/","pos":"n.","meaning":"被除数；股利 被除数","example":"The company paid a large dividend to its shareholders.","exampleCn":"公司向股东支付了丰厚的股利。","level":"IELTS"},{"id":2423,"word":"rival","phonetic":"/'raivl/","pos":"n.","meaning":"对手；竞争者 a. 竞争的","example":"Our biggest rival won the championship last year.","exampleCn":"我们最大的对手去年赢得了冠军。","level":"IELTS"},{"id":2424,"word":"resemble","phonetic":"/ri'zembl/","pos":"vt.","meaning":"相似；类似","example":"The twins resemble each other in almost every way.","exampleCn":"这对双胞胎几乎在每个方面都很相像。","level":"IELTS"},{"id":2425,"word":"undergo","phonetic":"/.ʌndә'gәu/","pos":"vt.","meaning":"遭受；经历；忍受 经受；经历","example":"Patients must undergo a full examination before the operation.","exampleCn":"病人在手术前必须经历一次全面检查。","level":"IELTS"},{"id":2426,"word":"privacy","phonetic":"/'praivәsi/","pos":"n.","meaning":"隐私；隐居；秘密 个人保密权","example":"Everyone has the right to protect their privacy.","exampleCn":"每个人都有保护自己隐私的权利。","level":"IELTS"},{"id":2427,"word":"contest","phonetic":"/'kɒntest/","pos":"n.","meaning":"竞赛；争论 vt. 竞争；争取；争辩 vi. 竞争","example":"She entered a singing contest and won first prize.","exampleCn":"她参加了歌唱比赛并获得了一等奖。","level":"IELTS"},{"id":2428,"word":"charter","phonetic":"/'tʃɑ:tә/","pos":"n.","meaning":"特许状；执照；宪章 vt. 特许；发给特许执照","example":"The city received a royal charter five hundred years ago.","exampleCn":"这座城市五百年前获得了皇家特许状。","level":"IELTS"},{"id":2429,"word":"trick","phonetic":"/trik/","pos":"n.","meaning":"诡计；欺诈；谋略；恶作剧","example":"He played a clever trick on his younger brother.","exampleCn":"他对弟弟耍了一个聪明的恶作剧。","level":"IELTS"},{"id":2430,"word":"organic","phonetic":"/ɒ:'gænik/","pos":"adj.","meaning":"器官的；有机的；组织的；根本的 器官的","example":"She only buys organic vegetables from the local farm.","exampleCn":"她只买当地农场的有机蔬菜。","level":"IELTS"},{"id":2431,"word":"accounting","phonetic":"/ә'kauntiŋ/","pos":"n.","meaning":"会计学；帐单；清帐 帐户处理；记帐","example":"He studied accounting at university for four years.","exampleCn":"他在大学学了四年会计学。","level":"IELTS"},{"id":2432,"word":"specimen","phonetic":"/'spesimәn/","pos":"n.","meaning":"样品；标本；试料 试样","example":"The doctor sent the blood specimen to the laboratory.","exampleCn":"医生把血液标本送到了实验室。","level":"IELTS"},{"id":2433,"word":"taxation","phonetic":"/tæk'seiʃәn/","pos":"n.","meaning":"课税；征税；抽税；税款","example":"The government raised taxation on luxury goods last year.","exampleCn":"政府去年提高了奢侈品的税收。","level":"IELTS"},{"id":2434,"word":"myth","phonetic":"/miθ/","pos":"n.","meaning":"神话；虚构的事；虚构的人","example":"The ancient myth explains how the world began.","exampleCn":"这个古老的神话解释了世界的起源。","level":"IELTS"},{"id":2435,"word":"ideology","phonetic":"/.aidi'ɒlәdʒi/","pos":"n.","meaning":"思想体系；意识形态；观念学；空论 观念学","example":"The party's ideology shaped its economic policies.","exampleCn":"该党的意识形态影响了其经济政策。","level":"IELTS"},{"id":2436,"word":"format","phonetic":"/'fɒ:mæt/","pos":"n.","meaning":"开本；版式；形式；格式 vt. 格式化 格式","example":"Please save the document in PDF format.","exampleCn":"请将文档保存为PDF格式。","level":"IELTS"},{"id":2437,"word":"judicial","phonetic":"/dʒu:'diʃәl/","pos":"adj.","meaning":"法庭的；公正的；审判上的；司法的 司法的","example":"The judicial system protects the rights of all citizens.","exampleCn":"司法制度保护所有公民的权利。","level":"IELTS"},{"id":2438,"word":"barrel","phonetic":"/'bærәl/","pos":"n.","meaning":"桶 vt. 装入桶内","example":"The price of oil rose to ninety dollars a barrel.","exampleCn":"油价涨到了每桶九十美元。","level":"IELTS"},{"id":2439,"word":"sigh","phonetic":"/sai/","pos":"n.","meaning":"叹息 vi. 叹息；渴望 vt. 叹息着说","example":"She gave a deep sigh and closed the book.","exampleCn":"她深深地叹了口气，合上了书。","level":"IELTS"},{"id":2440,"word":"wise","phonetic":"/waiz/","pos":"adj.","meaning":"明智的；慎虑的；聪明的；博学的","example":"It was a wise decision to save money early.","exampleCn":"早早存钱是一个明智的决定。","level":"IELTS"},{"id":2441,"word":"controversial","phonetic":"/.kɒntrә'vә:ʃәl/","pos":"adj.","meaning":"争论的；论争的；被议论的","example":"The new policy is highly controversial among local residents.","exampleCn":"这项新政策在当地居民中极具争议。","level":"IELTS"},{"id":2442,"word":"ease","phonetic":"/i:z/","pos":"n.","meaning":"安乐；安逸；悠闲 vt. 使安乐；使安心","example":"After retirement, he lived a life of ease in the countryside.","exampleCn":"退休后他在乡下过着安逸的生活。","level":"IELTS"},{"id":2443,"word":"lifestyle","phonetic":"/'laifstail/","pos":"n.","meaning":"生活方式","example":"A healthy lifestyle includes good food and regular sleep.","exampleCn":"健康的生活方式包括良好的饮食和规律的睡眠。","level":"IELTS"},{"id":2444,"word":"collapse","phonetic":"/kә'læps/","pos":"n.","meaning":"崩溃；倒塌；虚脱 vi. 倒塌；崩溃","example":"The old bridge could collapse at any moment.","exampleCn":"这座旧桥随时可能倒塌。","level":"IELTS"},{"id":2445,"word":"bitter","phonetic":"/'bitә/","pos":"adj.","meaning":"苦的；痛苦的；怀恨的 adv. 刺骨 v. (使)变苦","example":"The medicine has a bitter taste but works well.","exampleCn":"这种药味道很苦，但效果很好。","level":"IELTS"},{"id":2446,"word":"narrative","phonetic":"/'nærәtiv/","pos":"n.","meaning":"叙述；故事 a. 叙述的；叙事的；故事体的","example":"The book gives a clear narrative of the war years.","exampleCn":"这本书对战争年代作了清晰的叙述。","level":"IELTS"},{"id":2447,"word":"petrol","phonetic":"/'petrәl/","pos":"n.","meaning":"汽油 汽油；挥发油；石油","example":"We stopped at the station to buy some petrol.","exampleCn":"我们在加油站停下来加了些汽油。","level":"IELTS"},{"id":2448,"word":"helicopter","phonetic":"/'helikɒptә/","pos":"n.","meaning":"直升机 vt. 由直升机运送 vi. 乘直升机","example":"A rescue helicopter landed on the hospital roof.","exampleCn":"一架救援直升机降落在医院屋顶上。","level":"IELTS"},{"id":2449,"word":"organ","phonetic":"/'ɒ:gәn/","pos":"n.","meaning":"风琴；器官；元件；机构","example":"The heart is the most important organ in the body.","exampleCn":"心脏是人体最重要的器官。","level":"IELTS"},{"id":2450,"word":"modest","phonetic":"/'mɒdist/","pos":"adj.","meaning":"谦逊的；羞怯的；端庄的；适度的 适当的","example":"Despite her great success, she remains modest and kind.","exampleCn":"尽管取得了巨大成功，她依然谦逊善良。","level":"IELTS"},{"id":2451,"word":"explode","phonetic":"/ik'splәud/","pos":"vi.","meaning":"爆炸；爆发；激增 vt. 使爆炸","example":"The old gas tank could explode if heated.","exampleCn":"这个旧油罐受热可能会爆炸。","level":"IELTS"},{"id":2452,"word":"anticipate","phonetic":"/æn'tisipeit/","pos":"vt.","meaning":"预期；占先；加速；提前使用 提前出现","example":"We anticipate strong demand for the new product.","exampleCn":"我们预期新产品会有很大的需求。","level":"IELTS"},{"id":2453,"word":"stroke","phonetic":"/strәuk/","pos":"n.","meaning":"笔划；打；中风；抚","example":"Her grandfather suffered a stroke last winter.","exampleCn":"她的祖父去年冬天中风了。","level":"IELTS"},{"id":2454,"word":"frequent","phonetic":"/'fri:kwәnt/","pos":"adj.","meaning":"时常发生的；频繁的；快速的 vt. 时常来访；常常聚集","example":"Heavy rain is frequent in this region during summer.","exampleCn":"夏季这个地区经常下大雨。","level":"IELTS"},{"id":2455,"word":"garage","phonetic":"/gә'rɑ:ʒ. 'gærɑ:ʒ/","pos":"n.","meaning":"车库；汽车修理厂；机库 vt. 把车送入修车场","example":"He parked the car in the garage and went inside.","exampleCn":"他把车停进车库后走进了屋里。","level":"IELTS"},{"id":2456,"word":"horizon","phonetic":"/hә'raizәn/","pos":"n.","meaning":"地平线；眼界；(天)视地平","example":"The sun slowly sank below the distant horizon.","exampleCn":"太阳缓缓沉到远处的地平线下。","level":"IELTS"},{"id":2457,"word":"prompt","phonetic":"/prɒmpt/","pos":"n.","meaning":"激励；提示；提醒物；提词","example":"The screen shows a prompt asking for your password.","exampleCn":"屏幕上显示一个提示，要求输入密码。","level":"IELTS"},{"id":2458,"word":"suspend","phonetic":"/sә'spend/","pos":"vt.","meaning":"悬；吊；使悬浮；暂停","example":"The school decided to suspend classes because of the storm.","exampleCn":"学校因暴风雨决定暂时停课。","level":"IELTS"},{"id":2459,"word":"downtown","phonetic":"/'daun'taun/","pos":"n.","meaning":"市中心区 a. 市中心的 adv. 往闹市区","example":"They opened a new bookstore downtown last month.","exampleCn":"上个月他们在市中心开了一家新书店。","level":"IELTS"},{"id":2460,"word":"undoubtedly","phonetic":"/ʌn'dajtidli/","pos":"adv.","meaning":"无疑；必定；确实地","example":"She is undoubtedly the best player on the team.","exampleCn":"她无疑是队里最优秀的球员。","level":"IELTS"},{"id":2461,"word":"slope","phonetic":"/slәup/","pos":"n.","meaning":"倾斜；斜坡；斜率；扛枪姿势 vt. 使倾斜","example":"The children rolled down the grassy slope laughing.","exampleCn":"孩子们笑着从长满草的斜坡上滚下来。","level":"IELTS"},{"id":2462,"word":"australian","phonetic":"/ɒ'streiljәn/","pos":"n.","meaning":"澳大利亚人 a. 澳大利亚的；澳洲的；澳洲人的","example":"The Australian athlete broke the world record yesterday.","exampleCn":"这位澳大利亚运动员昨天打破了世界纪录。","level":"IELTS"},{"id":2463,"word":"junction","phonetic":"/'dʒʌŋkʃәn/","pos":"n.","meaning":"连接；会合处；交叉点 接处；接点.界","example":"Turn left at the next junction to reach the station.","exampleCn":"在下一个交叉路口左转就到车站了。","level":"IELTS"},{"id":2464,"word":"motivation","phonetic":"/.mәuti'veiʃәn/","pos":"n.","meaning":"动机；刺激；推动 促动；推动","example":"Praise from teachers gives students strong motivation to learn.","exampleCn":"老师的表扬给学生强烈的学习动力。","level":"IELTS"},{"id":2465,"word":"flexible","phonetic":"/'fleksәbl/","pos":"adj.","meaning":"易曲的；灵活的；柔顺的；能变形的","example":"My work schedule is flexible, so I can meet anytime.","exampleCn":"我的工作时间很灵活，所以随时可以见面。","level":"IELTS"},{"id":2466,"word":"compose","phonetic":"/kәm'pәuz/","pos":"vt.","meaning":"组成；写作；作曲；使平静 vi. 创作","example":"He plans to compose a song for the wedding.","exampleCn":"他打算为婚礼创作一首歌曲。","level":"IELTS"},{"id":2467,"word":"assignment","phonetic":"/ә'sainmәnt/","pos":"n.","meaning":"分配；功课；任务；转让","example":"The teacher gave us a writing assignment for the weekend.","exampleCn":"老师给我们布置了周末的写作作业。","level":"IELTS"},{"id":2468,"word":"conversion","phonetic":"/kәn'vә:ʃәn/","pos":"n.","meaning":"转变；转换；改变宗教信仰；换位法 转换","example":"The conversion of the old factory into apartments took two years.","exampleCn":"把旧工厂改建成公寓用了两年时间。","level":"IELTS"},{"id":2469,"word":"imperial","phonetic":"/im'piәriәl/","pos":"adj.","meaning":"帝王的；宗主国的；至尊的；壮丽的 n. 特等品","example":"The imperial palace attracts thousands of visitors every day.","exampleCn":"这座皇宫每天吸引成千上万的游客。","level":"IELTS"},{"id":2470,"word":"assurance","phonetic":"/ә'ʃuәrәns/","pos":"n.","meaning":"保证；把握；信心；保险 保证","example":"He gave me his assurance that the work would be finished.","exampleCn":"他向我保证这项工作一定会完成。","level":"IELTS"},{"id":2471,"word":"registration","phonetic":"/.redʒi'streiʃәn/","pos":"n.","meaning":"登记；挂号；注册 登记；定位","example":"Student registration begins next Monday at nine.","exampleCn":"学生注册下周一九点开始。","level":"IELTS"},{"id":2472,"word":"disc","phonetic":"/disk/","pos":"n.","meaning":"圆盘；唱片 vt. 灌唱片","example":"He keeps his old music on a compact disc.","exampleCn":"他把旧音乐存在一张光盘上。","level":"IELTS"},{"id":2473,"word":"cotton","phonetic":"/'kɒtn/","pos":"n.","meaning":"棉花 vi. 和谐；有好感；理解","example":"This comfortable shirt is made of pure cotton.","exampleCn":"这件舒适的衬衫是纯棉做的。","level":"IELTS"},{"id":2474,"word":"sue","phonetic":"/su:/","pos":"vt.","meaning":"控告；起诉；请求 vi. 提出诉讼；提出请求","example":"She decided to sue the company for unfair dismissal.","exampleCn":"她决定起诉这家公司不公正解雇。","level":"IELTS"},{"id":2475,"word":"terrace","phonetic":"/'terәs/","pos":"n.","meaning":"阶地；梯田；房屋之平顶；阳台","example":"We drank tea on the terrace overlooking the sea.","exampleCn":"我们在俯瞰大海的露台上喝茶。","level":"IELTS"},{"id":2476,"word":"rat","phonetic":"/ræt/","pos":"n.","meaning":"鼠；卑鄙的人；破坏者；变节者 vi. 捕鼠","example":"A large rat ran across the kitchen floor.","exampleCn":"一只大老鼠跑过厨房的地板。","level":"IELTS"},{"id":2477,"word":"overlook","phonetic":"/.әuvә'luk/","pos":"vt.","meaning":"俯瞰；远眺；没注意到 n. 眺望；俯瞰到的景色","example":"The hotel rooms overlook the beautiful blue bay.","exampleCn":"旅馆的房间俯瞰着美丽的蓝色海湾。","level":"IELTS"},{"id":2478,"word":"float","phonetic":"/flәut/","pos":"n.","meaning":"漂流物；浮舟；漂浮；浮萍","example":"Empty bottles float on the surface of the lake.","exampleCn":"空瓶子漂浮在湖面上。","level":"IELTS"},{"id":2479,"word":"discount","phonetic":"/'diskaunt/","pos":"n.","meaning":"折扣；贴现率 vt. 打折扣 vi. 贴现","example":"The store offers a ten percent discount this weekend.","exampleCn":"这家商店本周末提供九折优惠。","level":"IELTS"},{"id":2480,"word":"resignation","phonetic":"/.rezig'neiʃәn/","pos":"n.","meaning":"辞职；辞呈；听从 辞职","example":"The manager handed in his resignation after the scandal.","exampleCn":"丑闻发生后，经理递交了辞呈。","level":"IELTS"},{"id":2481,"word":"assert","phonetic":"/ә'sә:t/","pos":"vt.","meaning":"主张；坚称；断言 宣称；断言","example":"She continued to assert that she was innocent.","exampleCn":"她坚称自己是无辜的。","level":"IELTS"},{"id":2482,"word":"experimental","phonetic":"/ik.speri'mentәl/","pos":"adj.","meaning":"实验的；根据实验的 实验的","example":"The experimental drug showed promising results in early tests.","exampleCn":"这种实验性药物在早期试验中显示出良好效果。","level":"IELTS"},{"id":2483,"word":"innovation","phonetic":"/.inәu'veiʃәn/","pos":"n.","meaning":"改革；创新 创新；改革；刷新","example":"Technological innovation drives the growth of modern industry.","exampleCn":"技术创新推动着现代工业的发展。","level":"IELTS"},{"id":2484,"word":"cabin","phonetic":"/'kæbin/","pos":"n.","meaning":"小屋；客舱 vt. 关在小屋","example":"They spent the holiday in a wooden cabin by the lake.","exampleCn":"他们在湖边的小木屋里度假。","level":"IELTS"},{"id":2485,"word":"bite","phonetic":"/bait/","pos":"n.","meaning":"咬；一口 v. 咬；刺痛；穿透","example":"Be careful, that dog may bite strangers.","exampleCn":"小心，那只狗可能会咬陌生人。","level":"IELTS"},{"id":2486,"word":"particle","phonetic":"/'pɑ:tikl/","pos":"n.","meaning":"颗粒；粒子；质点；极小量 粒子","example":"Every particle of dust was removed from the lens.","exampleCn":"镜头上的每一粒灰尘都被清除了。","level":"IELTS"},{"id":2487,"word":"remedy","phonetic":"/'remidi/","pos":"n.","meaning":"药物；治疗法；治疗；补救","example":"Hot lemon tea is a good remedy for a cold.","exampleCn":"热柠檬茶是治疗感冒的良方。","level":"IELTS"},{"id":2488,"word":"pine","phonetic":"/pain/","pos":"n.","meaning":"松树；松木 vi. 消瘦；憔悴；痛苦","example":"A tall pine stands at the gate of the village.","exampleCn":"一棵高大的松树矗立在村口。","level":"IELTS"},{"id":2489,"word":"applicant","phonetic":"/'æplikәnt/","pos":"n.","meaning":"申请者 申请人；请求人；谋事人","example":"Each applicant must submit a resume before Friday.","exampleCn":"每位申请者必须在星期五之前提交简历。","level":"IELTS"},{"id":2490,"word":"versus","phonetic":"/'vә:sәs/","pos":"prep.","meaning":"对... 诉；对；相形","example":"Tonight's big match is Brazil versus Germany.","exampleCn":"今晚的大赛是巴西对德国。","level":"IELTS"},{"id":2491,"word":"emperor","phonetic":"/'empәrә/","pos":"n.","meaning":"皇帝；君主","example":"The emperor ruled the vast country for forty years.","exampleCn":"这位皇帝统治这个辽阔的国家长达四十年。","level":"IELTS"},{"id":2492,"word":"grin","phonetic":"/grin/","pos":"n.","meaning":"露齿笑 v. 露齿而笑","example":"He looked at me with a friendly grin.","exampleCn":"他咧着嘴友好地朝我笑。","level":"IELTS"},{"id":2493,"word":"boom","phonetic":"/bu:m/","pos":"n.","meaning":"繁荣；隆隆声 vi. 急速发展；发隆隆声 vt. 使兴旺；发隆隆声","example":"The city enjoyed an economic boom after the war.","exampleCn":"战后这座城市经历了经济繁荣。","level":"IELTS"},{"id":2494,"word":"audit","phonetic":"/'ɒ:dit/","pos":"n.","meaning":"审计；查帐 vt. 查(帐)；旁听 vi. 查账 查帐；审查","example":"The company hires outside experts to audit its accounts.","exampleCn":"公司聘请外部专家审计账目。","level":"IELTS"},{"id":2495,"word":"bound","phonetic":"/baund/","pos":"n.","meaning":"跃；回跳；范围；边界 a. 受约束的","example":"The deer cleared the fence in a single bound.","exampleCn":"那只鹿一跃就跳过了栅栏。","level":"IELTS"},{"id":2496,"word":"reverse","phonetic":"/ri'vә:s/","pos":"n.","meaning":"相反；背面；倒退；挫折","example":"The result was the exact reverse of what we expected.","exampleCn":"结果与我们的预期恰恰相反。","level":"IELTS"},{"id":2497,"word":"heritage","phonetic":"/'heritidʒ/","pos":"n.","meaning":"遗产；祖先遗留物；继承物 遗传性","example":"The old town is part of our cultural heritage.","exampleCn":"这座古城是我们文化遗产的一部分。","level":"IELTS"},{"id":2498,"word":"generous","phonetic":"/'dʒenәrәs/","pos":"adj.","meaning":"慷慨的；有雅量的；大量的；丰富的","example":"She is generous and always shares food with neighbors.","exampleCn":"她很慷慨，总是和邻居分享食物。","level":"IELTS"},{"id":2499,"word":"lemon","phonetic":"/'lemәn/","pos":"n.","meaning":"柠檬；柠檬树；柠檬色 柠檬","example":"Add a slice of lemon to your iced tea.","exampleCn":"在你的冰茶里加一片柠檬。","level":"IELTS"},{"id":2500,"word":"excuse","phonetic":"/ik'skju:z/","pos":"vt.","meaning":"原谅；申辩；做为...的托辞 n. 致歉；理由","example":"Please excuse me for arriving late this morning.","exampleCn":"请原谅我今天早上迟到了。","level":"IELTS"},{"id":2501,"word":"cancel","phonetic":"/'kænsәl/","pos":"n.","meaning":"取消；撤消；盖销(邮票) vt. 取消；删去","example":"Please cancel my hotel reservation for next weekend.","exampleCn":"请取消我下周末的酒店预订。","level":"IELTS"},{"id":2502,"word":"automatic","phonetic":"/.ɒ:tә'mætik/","pos":"n.","meaning":"自动手枪；自动机械 a. 自动的；机械的；必然的","example":"The automatic doors open when you walk near them.","exampleCn":"自动门会在你走近时打开。","level":"IELTS"},{"id":2503,"word":"naked","phonetic":"/'neikid/","pos":"adj.","meaning":"裸体的；无装饰的；无保护的；赤贫的 裸露的","example":"You can see the comet with the naked eye tonight.","exampleCn":"今晚你可以用肉眼看到那颗彗星。","level":"IELTS"},{"id":2504,"word":"ambition","phonetic":"/æm'biʃәn/","pos":"n.","meaning":"野心；志向","example":"Her ambition is to become a famous surgeon someday.","exampleCn":"她的志向是有朝一日成为著名的外科医生。","level":"IELTS"},{"id":2505,"word":"weekly","phonetic":"/'wi:kli/","pos":"n.","meaning":"周刊；周报 a. 每周的；一周一次的；周刊的 adv. 每周","example":"We hold a weekly meeting every Monday morning.","exampleCn":"我们每周一上午开一次例会。","level":"IELTS"},{"id":2506,"word":"electrical","phonetic":"/i'lektrikәl/","pos":"adj.","meaning":"电的；有关电的 电的","example":"An electrical fault caused the fire in the factory.","exampleCn":"一处电路故障引发了工厂的火灾。","level":"IELTS"},{"id":2507,"word":"logic","phonetic":"/'lɒdʒik/","pos":"n.","meaning":"逻辑；逻辑学；推理的方法；推理","example":"There is no logic in his strange argument at all.","exampleCn":"他那奇怪的论点毫无逻辑可言。","level":"IELTS"},{"id":2508,"word":"battery","phonetic":"/'bætәri/","pos":"n.","meaning":"电池；殴打 蓄电池","example":"My phone battery dies before the end of the day.","exampleCn":"我的手机电池不到一天就没电了。","level":"IELTS"},{"id":2509,"word":"inspection","phonetic":"/in'spekʃәn/","pos":"n.","meaning":"检验；检查；视察 检查；视察","example":"The bridge must pass a safety inspection every year.","exampleCn":"这座桥每年都必须通过安全检查。","level":"IELTS"},{"id":2510,"word":"flame","phonetic":"/fleim/","pos":"n.","meaning":"火焰；火舌；热情；光辉 vt. 焚烧","example":"A single flame lit up the dark little room.","exampleCn":"一束火焰照亮了那间昏暗的小屋。","level":"IELTS"},{"id":2511,"word":"legitimate","phonetic":"/li'dʒitimәt/","pos":"adj.","meaning":"合法的；正当的；婚生的 vt. 认为正当；立为嫡嗣","example":"The company has a legitimate claim to this land.","exampleCn":"这家公司对这块土地拥有合法的所有权。","level":"IELTS"},{"id":2512,"word":"bare","phonetic":"/bєә/","pos":"adj.","meaning":"赤裸的；缺少的；无遮蔽的；坦率的 vt. 使赤裸","example":"He walked across the cold floor with bare feet.","exampleCn":"他光着脚走过冰冷的地板。","level":"IELTS"},{"id":2513,"word":"orientation","phonetic":"/.ɒ:rien'teiʃәn/","pos":"n.","meaning":"定方位；适应；向东方 n. 方向 方向","example":"New students attend an orientation during their first week.","exampleCn":"新生在第一周要参加入学指导活动。","level":"IELTS"},{"id":2514,"word":"gross","phonetic":"/grәus/","pos":"n.","meaning":"总数；总量 a. 总共的；未打折扣的；恶劣的","example":"The film earned a gross of two million dollars.","exampleCn":"这部电影的总收入达到两百万美元。","level":"IELTS"},{"id":2515,"word":"cluster","phonetic":"/'klʌstә/","pos":"n.","meaning":"串；丛；群；簇 vi. 成串","example":"A cluster of grapes hung from the old vine.","exampleCn":"一串葡萄挂在老藤上。","level":"IELTS"},{"id":2516,"word":"shower","phonetic":"/'ʃauә/","pos":"n.","meaning":"阵雨；淋浴；一阵；展出者","example":"I always take a hot shower after the gym.","exampleCn":"我健身后总会洗个热水澡。","level":"IELTS"},{"id":2517,"word":"depict","phonetic":"/di'pikt/","pos":"vt.","meaning":"描述；描写","example":"The novel tries to depict life in a small village.","exampleCn":"这部小说试图描绘小村庄里的生活。","level":"IELTS"},{"id":2518,"word":"rubbish","phonetic":"/'rʌbiʃ/","pos":"n.","meaning":"废物；垃圾；胡说","example":"Please throw the rubbish into the bin outside.","exampleCn":"请把垃圾扔到外面的垃圾桶里。","level":"IELTS"},{"id":2519,"word":"disposal","phonetic":"/dis'pәuzәl/","pos":"n.","meaning":"丢掉；处理；排列；销毁","example":"Safe disposal of chemical waste protects the environment.","exampleCn":"安全处理化学废料能保护环境。","level":"IELTS"},{"id":2520,"word":"fibre","phonetic":"/'faibә/","pos":"n.","meaning":"纤维；构造；纤维制品 纤维","example":"This shirt is made from natural cotton fibre.","exampleCn":"这件衬衫由天然棉纤维制成。","level":"IELTS"},{"id":2521,"word":"comedy","phonetic":"/'kɒmidi/","pos":"n.","meaning":"喜剧；有趣的事情","example":"We watched a romantic comedy at the cinema last night.","exampleCn":"我们昨晚在电影院看了一部爱情喜剧。","level":"IELTS"},{"id":2522,"word":"sanction","phonetic":"/'sæŋkʃәn/","pos":"n.","meaning":"核准；制裁；处罚；约束力 vt. 制定制裁规则","example":"The council voted to impose a trade sanction on them.","exampleCn":"委员会投票决定对他们实施贸易制裁。","level":"IELTS"},{"id":2523,"word":"inadequate","phonetic":"/in'ædikwәt/","pos":"adj.","meaning":"不充分的；不适当的 不充分的；不适当的","example":"The hospital closed because of inadequate funding.","exampleCn":"这家医院因资金不足而关闭。","level":"IELTS"},{"id":2524,"word":"civilian","phonetic":"/si'viljәn/","pos":"n.","meaning":"平民；民法专家 a. 平民的；百姓的；民用的","example":"Not a single civilian was hurt during the operation.","exampleCn":"行动中没有一名平民受伤。","level":"IELTS"},{"id":2525,"word":"devise","phonetic":"/di'vaiz/","pos":"vt.","meaning":"设计；发明；图谋；遗赠给 n. 遗赠","example":"Engineers had to devise a cheaper way to build it.","exampleCn":"工程师们必须设计一种更省钱的建造方法。","level":"IELTS"},{"id":2526,"word":"grain","phonetic":"/grein/","pos":"n.","meaning":"谷粒；颗粒；谷类；纹理","example":"Every grain of rice comes from a farmer's hard work.","exampleCn":"每一粒米都来自农民的辛勤劳动。","level":"IELTS"},{"id":2527,"word":"condemn","phonetic":"/kәn'dem/","pos":"vt.","meaning":"判刑；责备；谴责 定罪；判刑","example":"World leaders were quick to condemn the violent attack.","exampleCn":"各国领导人迅速谴责了这次暴力袭击。","level":"IELTS"},{"id":2528,"word":"swear","phonetic":"/swєә/","pos":"vt.","meaning":"发誓；咒骂；使宣誓 vi. 发誓；诅咒 n. 诅咒","example":"I swear I will never tell anyone your secret.","exampleCn":"我发誓绝不会把你的秘密告诉任何人。","level":"IELTS"},{"id":2529,"word":"devote","phonetic":"/di'vәut/","pos":"vt.","meaning":"投入于；献身","example":"She decided to devote her life to helping the poor.","exampleCn":"她决定毕生致力于帮助穷人。","level":"IELTS"},{"id":2530,"word":"declaration","phonetic":"/.deklә'reiʃәn/","pos":"n.","meaning":"宣告；说明；宣布 说明","example":"The president signed a declaration of independence that morning.","exampleCn":"那天早上总统签署了独立宣言。","level":"IELTS"},{"id":2531,"word":"identification","phonetic":"/ai.dentifi'keiʃәn/","pos":"n.","meaning":"识别；身份证明；认同 鉴定；鉴别","example":"Please show some identification before entering the building.","exampleCn":"进入大楼前请出示身份证明。","level":"IELTS"},{"id":2532,"word":"correspond","phonetic":"/.kɒri'spɒnd/","pos":"vi.","meaning":"符合；通信；相当 符合；一致","example":"His words do not correspond with his actual actions.","exampleCn":"他的言辞与他的实际行动不符。","level":"IELTS"},{"id":2533,"word":"odds","phonetic":"/ɒdz/","pos":"n.","meaning":"可能性；几率；机会；胜算","example":"The odds of winning the lottery are extremely small.","exampleCn":"中彩票的几率极小。","level":"IELTS"},{"id":2534,"word":"modify","phonetic":"/'mɒdifai/","pos":"vt.","meaning":"修正；变更；修饰；缓和","example":"We may need to modify the design to cut costs.","exampleCn":"我们可能需要修改设计以降低成本。","level":"IELTS"},{"id":2535,"word":"chapel","phonetic":"/'tʃæpәl/","pos":"n.","meaning":"小教堂；礼拜式","example":"The couple got married in a small village chapel.","exampleCn":"这对新人在乡村的一座小教堂里结了婚。","level":"IELTS"},{"id":2536,"word":"youngster","phonetic":"/'jʌŋstә/","pos":"n.","meaning":"小孩；年轻人；少年 儿童；少年","example":"Every youngster in the team dreams of playing professionally.","exampleCn":"队里的每个少年都梦想成为职业球员。","level":"IELTS"},{"id":2537,"word":"rational","phonetic":"/'ræʃәnl/","pos":"adj.","meaning":"理性的；合理的 n. 有理数","example":"Try to make a rational decision, not an emotional one.","exampleCn":"尽量做出理性的决定，而不是感情用事。","level":"IELTS"},{"id":2538,"word":"physically","phonetic":"/'fizikli/","pos":"adv.","meaning":"按自然规律；完全地；实际上；真正地","example":"The two offices are physically separate but share one system.","exampleCn":"这两个办公室实际上是分开的，但共用一套系统。","level":"IELTS"},{"id":2539,"word":"conception","phonetic":"/kɒn'sepʃәn/","pos":"n.","meaning":"观念；概念 妊娠；受孕；概念","example":"He has no conception of how hard farmers work.","exampleCn":"他对农民的辛劳毫无概念。","level":"IELTS"},{"id":2540,"word":"attribute","phonetic":"/ә'tribju:t/","pos":"n.","meaning":"属性；标志；定语 vt. 把...归于；认为...属于 属性","example":"Patience is an important attribute of a good teacher.","exampleCn":"耐心是好老师的一项重要特质。","level":"IELTS"},{"id":2541,"word":"acute","phonetic":"/ә'kju:t/","pos":"adj.","meaning":"尖锐的；敏锐的；激烈的；严重的","example":"The city faces an acute shortage of clean water.","exampleCn":"这座城市面临严重的清洁水短缺。","level":"IELTS"},{"id":2542,"word":"artistic","phonetic":"/ɑ:'tistik/","pos":"adj.","meaning":"艺术的；艺术家的；富有艺术性的","example":"The old bridge has great artistic value to the town.","exampleCn":"这座古桥对小镇有极高的艺术价值。","level":"IELTS"},{"id":2543,"word":"dose","phonetic":"/dәus/","pos":"n.","meaning":"剂量；服用量 vt. 给药；(用药)医治 vi. 服药","example":"Take one dose of this medicine after each meal.","exampleCn":"每餐饭后服用一剂这种药。","level":"IELTS"},{"id":2544,"word":"stimulus","phonetic":"/'stimjulәs/","pos":"n.","meaning":"刺激；激励；刺激品 刺激特；刺激","example":"Lower taxes can act as a stimulus to the economy.","exampleCn":"降低税收可以对经济起到刺激作用。","level":"IELTS"},{"id":2545,"word":"federation","phonetic":"/fedә'reiʃәn/","pos":"n.","meaning":"联邦；联合；联盟 联邦；联盟","example":"The two unions merged to form a national federation.","exampleCn":"两个工会合并成立了一个全国性联合会。","level":"IELTS"},{"id":2546,"word":"ugly","phonetic":"/'ʌgli/","pos":"adj.","meaning":"丑陋的；邪恶的；险恶的；不祥的 n. 丑陋的人(或物)","example":"An ugly scar ran across the side of his face.","exampleCn":"一道难看的伤疤横在他的脸侧。","level":"IELTS"},{"id":2547,"word":"portray","phonetic":"/pɒ:'trei/","pos":"vt.","meaning":"描绘；描写；描绘...的肖像","example":"The movie tries to portray the artist as a hero.","exampleCn":"这部电影试图把这位艺术家刻画成英雄。","level":"IELTS"},{"id":2548,"word":"moderate","phonetic":"/'mɒdәrәt/","pos":"adj.","meaning":"适度的；稳健的；中等的；节制的 vt. 节制","example":"Doctors recommend moderate exercise three times a week.","exampleCn":"医生建议每周进行三次适度的锻炼。","level":"IELTS"},{"id":2549,"word":"hypothesis","phonetic":"/hai'pɒθәsis/","pos":"n.","meaning":"假设 假设","example":"The experiment was designed to test a new hypothesis.","exampleCn":"这个实验旨在检验一个新假设。","level":"IELTS"},{"id":2550,"word":"molecule","phonetic":"/'mɒlikju:l/","pos":"n.","meaning":"分子；些微 分子","example":"A water molecule contains two hydrogen atoms and one oxygen atom.","exampleCn":"一个水分子包含两个氢原子和一个氧原子。","level":"IELTS"},{"id":2551,"word":"cooking","phonetic":"/'kukiŋ/","pos":"n.","meaning":"烹饪 熬炼；热炼；蒸煮","example":"My grandmother taught me the basics of Chinese cooking.","exampleCn":"我奶奶教会了我中式烹饪的基础。","level":"IELTS"},{"id":2552,"word":"carrier","phonetic":"/'kæriә/","pos":"n.","meaning":"运送者；邮递员；带菌者 载波","example":"The letter carrier delivers our mail every morning.","exampleCn":"邮递员每天早上给我们送信。","level":"IELTS"},{"id":2553,"word":"reliable","phonetic":"/ri'laiәbl/","pos":"adj.","meaning":"可靠的；可信赖的 可靠的；可信赖的；确实的","example":"We need a reliable car for the long journey.","exampleCn":"我们需要一辆可靠的汽车来跑长途。","level":"IELTS"},{"id":2554,"word":"disturb","phonetic":"/dis'tә:b/","pos":"vt.","meaning":"扰乱；妨碍；使不安 滋扰；扰乱","example":"Please do not disturb me while I am studying.","exampleCn":"我学习的时候请不要打扰我。","level":"IELTS"},{"id":2555,"word":"identical","phonetic":"/ai'dentikәl/","pos":"adj.","meaning":"同一的；恒等的；完全相同的 同一的；同等的","example":"The twins wore identical dresses to the party.","exampleCn":"这对双胞胎穿着一模一样的裙子去参加聚会。","level":"IELTS"},{"id":2556,"word":"isle","phonetic":"/ail/","pos":"n.","meaning":"小岛；群岛 vt. 使成为岛状 vi. 住在岛屿上","example":"They spent the summer on a quiet isle in Greece.","exampleCn":"他们在希腊一座宁静的小岛上度过了夏天。","level":"IELTS"},{"id":2557,"word":"sole","phonetic":"/sәul/","pos":"n.","meaning":"脚掌；鞋底；底部 a. 唯一的；仅有的","example":"She is the sole owner of this small bookshop.","exampleCn":"她是这家小书店的唯一所有者。","level":"IELTS"},{"id":2558,"word":"advertisement","phonetic":"/.ædvә'taizmәnt/","pos":"n.","meaning":"广告；启事；广告宣传 广告；公告","example":"I saw an advertisement for the new phone on television.","exampleCn":"我在电视上看到了那款新手机的广告。","level":"IELTS"},{"id":2559,"word":"kit","phonetic":"/kit/","pos":"n.","meaning":"装备；工具箱；成套工具 成套部件；成套零件","example":"Every car should carry a first aid kit.","exampleCn":"每辆汽车都应该配备一个急救工具箱。","level":"IELTS"},{"id":2560,"word":"pet","phonetic":"/pet/","pos":"n.","meaning":"宠物；受宠爱的人；宠坏的孩子；不悦","example":"My daughter wants a rabbit as a pet.","exampleCn":"我女儿想养一只兔子当宠物。","level":"IELTS"},{"id":2561,"word":"miracle","phonetic":"/'mirәkl/","pos":"n.","meaning":"奇迹；奇事","example":"It was a miracle that everyone survived the crash.","exampleCn":"所有人都在事故中幸存下来，真是个奇迹。","level":"IELTS"},{"id":2562,"word":"rhythm","phonetic":"/'riðәm/","pos":"n.","meaning":"旋律；节奏；韵律；匀称","example":"The dancers moved to the rhythm of the drums.","exampleCn":"舞者们随着鼓的节奏舞动。","level":"IELTS"},{"id":2563,"word":"accountant","phonetic":"/ә'kauntәnt/","pos":"n.","meaning":"会计人员；会计师 会计师；会计人员","example":"Our accountant checks the company books every month.","exampleCn":"我们的会计每个月核对公司账目。","level":"IELTS"},{"id":2564,"word":"tide","phonetic":"/taid/","pos":"n.","meaning":"潮；潮汐；趋势；潮流","example":"The fishing boats return before the tide goes out.","exampleCn":"渔船在退潮之前返回。","level":"IELTS"},{"id":2565,"word":"script","phonetic":"/skript/","pos":"n.","meaning":"手迹；手稿；正本；手写体 vt. 改编为演出本 手写体","example":"The actor forgot his lines and checked the script.","exampleCn":"演员忘了台词，于是看了看剧本。","level":"IELTS"},{"id":2566,"word":"tactic","phonetic":"/'tæktik/","pos":"n.","meaning":"一项战术；一条策略 a. 战术的；顺序的；排列的","example":"Cutting prices is a common tactic to attract customers.","exampleCn":"降价是吸引顾客的常见策略。","level":"IELTS"},{"id":2567,"word":"swallow","phonetic":"/'swɒlәu/","pos":"n.","meaning":"燕子；吞咽；喉 vt. 咽；淹没","example":"A swallow built its nest under our roof this spring.","exampleCn":"今年春天一只燕子在我们屋檐下筑了巢。","level":"IELTS"},{"id":2568,"word":"farming","phonetic":"/'fɑ:miŋ/","pos":"n.","meaning":"农业；耕作","example":"Organic farming is becoming popular in this region.","exampleCn":"有机农业在这个地区越来越流行。","level":"IELTS"},{"id":2569,"word":"piano","phonetic":"/pi'ɑ:nәu/","pos":"n.","meaning":"钢琴","example":"She practices the piano for two hours every day.","exampleCn":"她每天练两个小时钢琴。","level":"IELTS"},{"id":2570,"word":"liable","phonetic":"/'laiәbl/","pos":"adj.","meaning":"有义务的；应负责的；有...倾向的 有责任的；可受处理的","example":"Drivers are liable for any damage they cause.","exampleCn":"司机要对自己造成的任何损失负责。","level":"IELTS"},{"id":2571,"word":"removal","phonetic":"/ri'mu:vl/","pos":"n.","meaning":"移动；移居；迁移；排除","example":"The removal of the old statue caused a public debate.","exampleCn":"拆除那座旧雕像引发了公众争论。","level":"IELTS"},{"id":2572,"word":"blanket","phonetic":"/'blæŋkit/","pos":"n.","meaning":"毛毯；毯子 vt. 掩盖；覆盖 a. 总共的","example":"She wrapped the sleeping baby in a soft blanket.","exampleCn":"她用一条柔软的毯子裹住熟睡的婴儿。","level":"IELTS"},{"id":2573,"word":"cloth","phonetic":"/klɒ:θ. klɒθ/","pos":"n.","meaning":"布料；织品；布 布","example":"This shop sells fine cloth for making suits.","exampleCn":"这家店出售做西装用的上等布料。","level":"IELTS"},{"id":2574,"word":"interior","phonetic":"/in'tiәriә/","pos":"n.","meaning":"内部；内政 a. 内部的；心灵的；内地的","example":"The interior of the old church is beautifully decorated.","exampleCn":"这座古老教堂的内部装饰得很精美。","level":"IELTS"},{"id":2575,"word":"concrete","phonetic":"/'kɒnkri:t/","pos":"n.","meaning":"凝结物；混凝土 a. 具体的；实在的；混凝土的 v. (使)凝结","example":"Please give me a concrete example of your plan.","exampleCn":"请给我举一个你计划的具体例子。","level":"IELTS"},{"id":2576,"word":"prescription","phonetic":"/pri'skripʃәn/","pos":"n.","meaning":"处方；命令；指定 处方；药方","example":"You cannot buy this medicine without a doctor's prescription.","exampleCn":"没有医生的处方你买不到这种药。","level":"IELTS"},{"id":2577,"word":"chase","phonetic":"/tʃeis/","pos":"n.","meaning":"追求；狩猎；追逐 vt. 追捕；追逐","example":"The police gave chase to the stolen car.","exampleCn":"警察对那辆被盗的汽车展开了追捕。","level":"IELTS"},{"id":2578,"word":"recruit","phonetic":"/ri'kru:t/","pos":"n.","meaning":"新兵；新手；新会员；补给品 vt. 恢复","example":"The young recruit completed his first month of training.","exampleCn":"这名新兵完成了第一个月的训练。","level":"IELTS"},{"id":2579,"word":"render","phonetic":"/'rendә/","pos":"vt.","meaning":"回报；给于；付给；汇报","example":"Volunteers render valuable help to flood victims every year.","exampleCn":"志愿者们每年都为洪灾受害者提供宝贵的帮助。","level":"IELTS"},{"id":2580,"word":"taxi","phonetic":"/'tæksi/","pos":"n.","meaning":"出租车 vi. 乘出租车 vt. 用出租车送","example":"We took a taxi from the airport to the hotel.","exampleCn":"我们从机场打车去了酒店。","level":"IELTS"},{"id":2581,"word":"consensus","phonetic":"/kәn'sensәs/","pos":"n.","meaning":"合意；一致；同感 合意","example":"After hours of debate, the committee finally reached a consensus.","exampleCn":"经过数小时的辩论，委员会终于达成了一致意见。","level":"IELTS"},{"id":2582,"word":"colonial","phonetic":"/kә'lәunjәl/","pos":"adj.","meaning":"殖民的；殖民地的 殖民地居民","example":"Many buildings here date back to the colonial period.","exampleCn":"这里的许多建筑可以追溯到殖民时期。","level":"IELTS"},{"id":2583,"word":"cinema","phonetic":"/'sinәmә/","pos":"n.","meaning":"电影院；电影","example":"Let's go to the cinema to see the new film.","exampleCn":"我们去电影院看那部新电影吧。","level":"IELTS"},{"id":2584,"word":"pie","phonetic":"/pai/","pos":"n.","meaning":"馅饼；财富；总额；贪污受贿","example":"Grandma baked an apple pie for the family dinner.","exampleCn":"奶奶为家庭晚餐烤了一个苹果馅饼。","level":"IELTS"},{"id":2585,"word":"induce","phonetic":"/in'dju:s/","pos":"vt.","meaning":"引诱；招致；归纳出；感应 诱导","example":"Nothing could induce him to change his final decision.","exampleCn":"什么都无法诱使他改变最终决定。","level":"IELTS"},{"id":2586,"word":"clue","phonetic":"/klu:/","pos":"n.","meaning":"线索；暗示 vt. 暗示；提供线索","example":"The detective found an important clue at the scene.","exampleCn":"侦探在现场发现了一条重要线索。","level":"IELTS"},{"id":2587,"word":"slice","phonetic":"/slais/","pos":"n.","meaning":"薄的切片；一部分；菜刀 vt. 切成薄片；切下 vi. 切 片","example":"He put a slice of cheese on the bread.","exampleCn":"他在面包上放了一片奶酪。","level":"IELTS"},{"id":2588,"word":"underlying","phonetic":"/.ʌndә'laiiŋ/","pos":"adj.","meaning":"在下面的 优先的；基础的；放在下面的","example":"Doctors are still studying the underlying cause of the disease.","exampleCn":"医生们仍在研究这种疾病的根本原因。","level":"IELTS"},{"id":2589,"word":"sacred","phonetic":"/'seikrid/","pos":"adj.","meaning":"神圣的；献给上帝的；庄严的；祭祀的 神圣的","example":"This mountain is sacred to the local people.","exampleCn":"这座山对当地人来说是神圣的。","level":"IELTS"},{"id":2590,"word":"lamp","phonetic":"/læmp/","pos":"n.","meaning":"灯 vt. 照亮 逻辑模拟分析系统","example":"She turned on the lamp and began to read.","exampleCn":"她打开台灯，开始读书。","level":"IELTS"},{"id":2591,"word":"cognitive","phonetic":"/'kɒgnitiv/","pos":"adj.","meaning":"认知的；认识的","example":"Reading aloud helps develop a child's cognitive skills.","exampleCn":"大声朗读有助于培养孩子的认知能力。","level":"IELTS"},{"id":2592,"word":"domain","phonetic":"/dәu'mein/","pos":"n.","meaning":"领域；领土；产业；范围 域","example":"She is a leading expert in the domain of medicine.","exampleCn":"她是医学领域的顶尖专家。","level":"IELTS"},{"id":2593,"word":"namely","phonetic":"/'neimli/","pos":"adv.","meaning":"即；就是；换句话说","example":"Only one student passed, namely the youngest girl.","exampleCn":"只有一名学生通过了，也就是那个最小的女孩。","level":"IELTS"},{"id":2594,"word":"knit","phonetic":"/nit/","pos":"v.","meaning":"编织；结合","example":"My mother loves to knit sweaters for the whole family.","exampleCn":"我妈妈喜欢给全家人织毛衣。","level":"IELTS"},{"id":2595,"word":"integrate","phonetic":"/'intigreit/","pos":"vt.","meaning":"综合；使完整；使成整体 vi. 成一体 a. 完整的；完全的","example":"The school plans to integrate technology into every classroom.","exampleCn":"学校计划把科技融入每一间教室。","level":"IELTS"},{"id":2596,"word":"fragment","phonetic":"/'frægmәnt/","pos":"n.","meaning":"碎片；破片；片段 段落；片段","example":"She kept a small fragment of the broken vase.","exampleCn":"她保留了破碎花瓶的一小块碎片。","level":"IELTS"},{"id":2597,"word":"equity","phonetic":"/'ekwiti/","pos":"n.","meaning":"公平；公正 权益；产权","example":"The new law aims to promote equity in education.","exampleCn":"新法律旨在促进教育公平。","level":"IELTS"},{"id":2598,"word":"fitness","phonetic":"/'fitnis/","pos":"n.","meaning":"适合；合宜；合理；恰当","example":"Regular exercise greatly improves your physical fitness.","exampleCn":"经常锻炼能大大提高你的身体素质。","level":"IELTS"},{"id":2599,"word":"grave","phonetic":"/greiv/","pos":"n.","meaning":"墓穴；坟墓；终结；死亡 a. 庄重的","example":"Fresh flowers were placed on the soldier's grave.","exampleCn":"士兵的坟墓上摆放着鲜花。","level":"IELTS"},{"id":2600,"word":"statute","phonetic":"/'stætju:t/","pos":"n.","meaning":"法令；成文法律；法规；章程","example":"The new statute protects workers from unfair dismissal.","exampleCn":"这项新法令保护工人免遭不公平解雇。","level":"IELTS"},{"id":2601,"word":"lap","phonetic":"/læp/","pos":"n.","meaning":"膝盖；舔；一圈；下摆","example":"The cat curled up and slept on her lap.","exampleCn":"猫蜷成一团，睡在她的膝盖上。","level":"IELTS"},{"id":2602,"word":"marginal","phonetic":"/'mɑ:dʒinәl/","pos":"adj.","meaning":"边缘的；最低限度的；有旁注的 缘的","example":"The new policy will have only a marginal effect on prices.","exampleCn":"新政策对物价只会产生微小的影响。","level":"IELTS"},{"id":2603,"word":"container","phonetic":"/kәn'teinә/","pos":"n.","meaning":"容器；集装箱 集装箱；贮存箱；容器(任何一种)","example":"Store the rice in an airtight container to keep it fresh.","exampleCn":"把米存放在密封容器里以保持新鲜。","level":"IELTS"},{"id":2604,"word":"murmur","phonetic":"/'mә:mә/","pos":"n.","meaning":"低语；低声的怨言 vi. 低语；低声而言 vt. 低声说","example":"She spoke in a soft murmur so nobody would hear.","exampleCn":"她低声细语，以免被人听到。","level":"IELTS"},{"id":2605,"word":"sheer","phonetic":"/ʃiә/","pos":"adj.","meaning":"绝对的；全然的；纯粹的；透明的","example":"They won the game through sheer hard work.","exampleCn":"他们完全靠苦干赢得了比赛。","level":"IELTS"},{"id":2606,"word":"bulk","phonetic":"/bʌlk/","pos":"n.","meaning":"大小；体积；大块；大多数 vt. 显得大","example":"The bulk of the work was finished before noon.","exampleCn":"大部分工作在中午之前就完成了。","level":"IELTS"},{"id":2607,"word":"decrease","phonetic":"/'di:kri:s/","pos":"n.","meaning":"减少；减少量 v. 减少","example":"The new policy led to a decrease in traffic accidents.","exampleCn":"新政策使交通事故有所减少。","level":"IELTS"},{"id":2608,"word":"experienced","phonetic":"/ik'spiәriәnst/","pos":"adj.","meaning":"富有经验的；老练的；熟练的","example":"An experienced guide led us safely through the mountains.","exampleCn":"一位经验丰富的向导带我们安全穿过了群山。","level":"IELTS"},{"id":2609,"word":"trap","phonetic":"/træp/","pos":"n.","meaning":"圈套；陷阱；诡计；存水弯 vi. 设圈套","example":"The farmer set a trap to catch the fox.","exampleCn":"农夫设了一个陷阱来捉狐狸。","level":"IELTS"},{"id":2610,"word":"anniversary","phonetic":"/æni'vә:sәri/","pos":"n.","meaning":"周年纪念","example":"They celebrated their tenth wedding anniversary in Paris.","exampleCn":"他们在巴黎庆祝了结婚十周年纪念日。","level":"IELTS"},{"id":2611,"word":"couch","phonetic":"/kautʃ/","pos":"n.","meaning":"长沙发；睡椅；卧榻 vt. 横躺；表达 vi. 躺下","example":"He fell asleep on the couch watching television.","exampleCn":"他看着电视在沙发上睡着了。","level":"IELTS"},{"id":2612,"word":"grip","phonetic":"/grip/","pos":"n.","meaning":"紧握；柄；握力；握手方式","example":"Keep a firm grip on the rope while climbing.","exampleCn":"攀爬时要紧紧抓住绳子。","level":"IELTS"},{"id":2613,"word":"exclusive","phonetic":"/ik'sklu:siv/","pos":"adj.","meaning":"排外的；独占的；唯一的 独占的","example":"The reporter got an exclusive interview with the singer.","exampleCn":"这名记者获得了对那位歌手的独家专访。","level":"IELTS"},{"id":2614,"word":"mess","phonetic":"/mes/","pos":"n.","meaning":"食堂；伙食；用膳；一份食品","example":"The soldiers eat together in the army mess every evening.","exampleCn":"士兵们每天晚上在军队食堂一起用餐。","level":"IELTS"},{"id":2615,"word":"legend","phonetic":"/'ledʒәnd/","pos":"n.","meaning":"传说；传奇文学；图例 图例","example":"According to legend, a dragon once lived in this lake.","exampleCn":"传说这个湖里曾住着一条龙。","level":"IELTS"},{"id":2616,"word":"nursery","phonetic":"/'nә:sәri/","pos":"n.","meaning":"托儿所；苗圃；温床 婴儿室；托儿所","example":"She drops her son at the nursery before work.","exampleCn":"她上班前把儿子送到托儿所。","level":"IELTS"},{"id":2617,"word":"regulate","phonetic":"/'regjuleit/","pos":"vt.","meaning":"管理；控制；调节；调整","example":"New laws will regulate the sale of online games.","exampleCn":"新法律将对网络游戏的销售进行管理。","level":"IELTS"},{"id":2618,"word":"superb","phonetic":"/sju'pә:b/","pos":"adj.","meaning":"极度的；华丽的；极好的","example":"The hotel offers a superb view of the harbour.","exampleCn":"这家酒店可以欣赏到极好的海港景色。","level":"IELTS"},{"id":2619,"word":"norm","phonetic":"/nɒ:m/","pos":"n.","meaning":"基准；模范；标准；准则","example":"Working from home has become the norm in many companies.","exampleCn":"居家办公在许多公司已成为常态。","level":"IELTS"},{"id":2620,"word":"upset","phonetic":"/ʌp'set/","pos":"adj.","meaning":"弄翻的；混乱的；心烦的 vt. 弄翻；颠覆","example":"She was deeply upset by the bad news from home.","exampleCn":"家里传来的坏消息让她非常难过。","level":"IELTS"},{"id":2621,"word":"forgive","phonetic":"/fә'giv/","pos":"vt.","meaning":"原谅；宽恕；免除 免除；宽恕","example":"I will never forgive him for breaking his promise.","exampleCn":"我永远不会原谅他违背诺言。","level":"IELTS"},{"id":2622,"word":"ritual","phonetic":"/'ritʃuәl/","pos":"n.","meaning":"仪式；典礼；宗教仪式 a. 仪式的；依仪式进行的","example":"Drinking tea at dawn is a daily ritual for him.","exampleCn":"清晨喝茶是他每天的固定仪式。","level":"IELTS"},{"id":2623,"word":"accommodate","phonetic":"/ә'kɒmәdeit/","pos":"vt.","meaning":"使适应；调和；通融；容纳","example":"The new hall can accommodate up to five hundred guests.","exampleCn":"新大厅最多可容纳五百名宾客。","level":"IELTS"},{"id":2624,"word":"insect","phonetic":"/'insekt/","pos":"n.","meaning":"昆虫；卑鄙的人 昆虫","example":"A small insect landed quietly on the white flower.","exampleCn":"一只小昆虫悄悄落在白花上。","level":"IELTS"},{"id":2625,"word":"shortage","phonetic":"/'ʃɒ:tidʒ/","pos":"n.","meaning":"不足；缺乏 缺额","example":"The drought caused a serious shortage of fresh water.","exampleCn":"干旱造成了淡水的严重短缺。","level":"IELTS"},{"id":2626,"word":"desirable","phonetic":"/di'zairәbl/","pos":"adj.","meaning":"令人想望的；可取的","example":"A quiet office is desirable for this kind of work.","exampleCn":"对这种工作来说，安静的办公室是再好不过的。","level":"IELTS"},{"id":2627,"word":"undermine","phonetic":"/.ʌndә'main/","pos":"vt.","meaning":"在...下面挖；渐渐破坏；暗地里破坏 暗中破坏；以阴谋中伤伤害","example":"Constant criticism can undermine a child's confidence.","exampleCn":"不断的批评会逐渐削弱孩子的自信心。","level":"IELTS"},{"id":2628,"word":"superior","phonetic":"/sju:'piәriә/","pos":"n.","meaning":"长者；占优势的人；上级 a. 上级的；出众的","example":"Report any safety problems to your immediate superior.","exampleCn":"有任何安全问题都要向你的直属上级报告。","level":"IELTS"},{"id":2629,"word":"magic","phonetic":"/'mædʒik/","pos":"n.","meaning":"魔术；魔法 a. 魔术的；有魔力的；不可思议的","example":"The children watched the magic show with wide eyes.","exampleCn":"孩子们睁大眼睛看着魔术表演。","level":"IELTS"},{"id":2630,"word":"combat","phonetic":"/'kɒmbæt/","pos":"n.","meaning":"争斗；战斗 vi. 战斗；争斗 vt. 与...战斗；与...斗争","example":"The government launched a campaign to combat air pollution.","exampleCn":"政府发起了一场对抗空气污染的行动。","level":"IELTS"},{"id":2631,"word":"surgeon","phonetic":"/'sә:dʒәn/","pos":"n.","meaning":"外科医生；军医；船医 外科医师","example":"The surgeon performed a five-hour operation on his heart.","exampleCn":"外科医生为他做了一台五个小时的心脏手术。","level":"IELTS"},{"id":2632,"word":"stem","phonetic":"/stem/","pos":"n.","meaning":"茎；干；柄；船首","example":"Cut the stem of the rose at an angle.","exampleCn":"把玫瑰的茎斜着剪断。","level":"IELTS"},{"id":2633,"word":"fleet","phonetic":"/fli:t/","pos":"n.","meaning":"舰队；港湾；小河 a. 快速的；敏捷的","example":"The fishing fleet returned to port before the storm.","exampleCn":"渔船队在暴风雨来临前返回了港口。","level":"IELTS"},{"id":2634,"word":"counsel","phonetic":"/'kaunsәl/","pos":"n.","meaning":"商议；忠告；法律顾问 v. 商议；劝告","example":"He sought legal counsel before signing the contract.","exampleCn":"签合同之前他咨询了法律顾问。","level":"IELTS"},{"id":2635,"word":"crystal","phonetic":"/'kristl/","pos":"n.","meaning":"水晶；水晶装饰品；结晶 a. 水晶的；水晶一样的","example":"The crystal glasses sparkled under the bright lights.","exampleCn":"水晶杯在明亮的灯光下闪闪发光。","level":"IELTS"},{"id":2636,"word":"hunt","phonetic":"/hʌnt/","pos":"n.","meaning":"狩猎；追捕；搜寻；猎区 vt. 狩猎","example":"Owls hunt small animals at night in the forest.","exampleCn":"猫头鹰夜间在森林里捕猎小动物。","level":"IELTS"},{"id":2637,"word":"jeans","phonetic":"/dʒi:nz/","pos":"n.","meaning":"工装裤；牛仔裤","example":"He wore an old pair of jeans to the picnic.","exampleCn":"他穿着一条旧牛仔裤去野餐。","level":"IELTS"},{"id":2638,"word":"initiate","phonetic":"/i'niʃieit/","pos":"n.","meaning":"入会；开始 a. 新加入的 vt. 开始；传授基本知识给","example":"The city will initiate a recycling program next month.","exampleCn":"该市下个月将启动一项回收计划。","level":"IELTS"},{"id":2639,"word":"log","phonetic":"/lɒg/","pos":"n.","meaning":"记录；圆木；日志；计程仪 vt. 伐木","example":"The captain keeps a daily log of the ship's position.","exampleCn":"船长每天记录船只位置的日志。","level":"IELTS"},{"id":2640,"word":"echo","phonetic":"/'ekәu/","pos":"n.","meaning":"回声；回音；回波 vi. 发回声；随声附和 vt. 摹仿","example":"His shout produced a loud echo in the empty hall.","exampleCn":"他的喊声在空荡的大厅里产生了响亮的回声。","level":"IELTS"},{"id":2641,"word":"leap","phonetic":"/li:p/","pos":"n.","meaning":"跳跃；剧增；急变；被越过之物 vi. 跳跃","example":"The cat made a sudden leap onto the table.","exampleCn":"猫猛地一跃跳上了桌子。","level":"IELTS"},{"id":2642,"word":"sculpture","phonetic":"/'skʌlptʃә/","pos":"n.","meaning":"雕刻；雕塑 vt. 雕刻；雕塑 vi. 当雕刻师","example":"A bronze sculpture of a horse stands in the square.","exampleCn":"广场上立着一座马的青铜雕塑。","level":"IELTS"},{"id":2643,"word":"raid","phonetic":"/reid/","pos":"n.","meaning":"袭击；突袭；搜捕 v. 奇袭；搜捕 廉价磁盘冗余阵列","example":"Police carried out a raid on the illegal factory.","exampleCn":"警方对那家非法工厂进行了突击搜查。","level":"IELTS"},{"id":2644,"word":"compound","phonetic":"/kәm'paund/","pos":"n.","meaning":"混合物；复合词；化合物；院子 a. 复合的","example":"Water is a compound of hydrogen and oxygen.","exampleCn":"水是氢和氧的化合物。","level":"IELTS"},{"id":2645,"word":"flour","phonetic":"/'flauә/","pos":"n.","meaning":"面粉；粉沫；碎粉 面粉；麦粉","example":"Mix the flour with eggs and milk to make pancakes.","exampleCn":"把面粉和鸡蛋、牛奶混合做成薄饼。","level":"IELTS"},{"id":2646,"word":"subtle","phonetic":"/'sʌtl/","pos":"adj.","meaning":"敏锐的；精细的；狡猾的；稀薄的","example":"There is a subtle difference between these two colours.","exampleCn":"这两种颜色之间有细微的差别。","level":"IELTS"},{"id":2647,"word":"hardware","phonetic":"/'hɑ:dwєә/","pos":"n.","meaning":"硬件；五金器具；零件 硬件","example":"The new software runs well on older hardware.","exampleCn":"这款新软件在较旧的硬件上也运行良好。","level":"IELTS"},{"id":2648,"word":"drinking","phonetic":"/'driŋkiŋ/","pos":"n.","meaning":"喝；喝酒","example":"Heavy drinking can cause serious damage to your liver.","exampleCn":"酗酒会对肝脏造成严重损害。","level":"IELTS"},{"id":2649,"word":"comply","phonetic":"/kәm'plai/","pos":"vi.","meaning":"顺从；依从 遵守；承诺；照做","example":"All factories must comply with the new safety rules.","exampleCn":"所有工厂都必须遵守新的安全规定。","level":"IELTS"},{"id":2650,"word":"colony","phonetic":"/'kɒlәni/","pos":"n.","meaning":"殖民地；移民队 菌(集)落；菌丛；移民区","example":"The island was once a French colony for many years.","exampleCn":"这座岛曾经多年是法国的殖民地。","level":"IELTS"},{"id":2651,"word":"pump","phonetic":"/pʌmp/","pos":"n.","meaning":"抽水机；打气筒；泵；抽吸 vt. 用唧筒抽水","example":"We used a pump to remove water from the basement.","exampleCn":"我们用水泵把地下室的水抽了出去。","level":"IELTS"},{"id":2652,"word":"monopoly","phonetic":"/mә'nɒpәli/","pos":"n.","meaning":"垄断；专卖权；独占事业 垄断；专利品","example":"The company holds a monopoly on the local phone service.","exampleCn":"这家公司垄断了当地的电话业务。","level":"IELTS"},{"id":2653,"word":"banking","phonetic":"/'bæŋkiŋ/","pos":"n.","meaning":"银行业务 银行业；银行事务","example":"Online banking lets you pay bills from your phone.","exampleCn":"网上银行让你可以用手机支付账单。","level":"IELTS"},{"id":2654,"word":"temple","phonetic":"/templ/","pos":"n.","meaning":"圣堂；庙宇；教堂；礼拜堂","example":"Tourists visit the ancient temple on the mountain every day.","exampleCn":"游客们每天都去参观山上的古庙。","level":"IELTS"},{"id":2655,"word":"medal","phonetic":"/'medl/","pos":"n.","meaning":"奖牌；勋章 vt. 授勋予","example":"She won a gold medal in the swimming competition.","exampleCn":"她在游泳比赛中获得了金牌。","level":"IELTS"},{"id":2656,"word":"sponsor","phonetic":"/'spɒnsә/","pos":"n.","meaning":"保证人；赞助者；发起者；倡议者","example":"A local bank became the main sponsor of the marathon.","exampleCn":"一家当地银行成为了马拉松赛的主要赞助商。","level":"IELTS"},{"id":2657,"word":"slam","phonetic":"/slæm/","pos":"n.","meaning":"砰然声；猛然；猛烈的抨击 vt. 猛然关上；砰地关上","example":"He shut the door with an angry slam.","exampleCn":"他愤怒地砰的一声关上了门。","level":"IELTS"},{"id":2658,"word":"specification","phonetic":"/.spesifi'keiʃәn/","pos":"n.","meaning":"规格；详述；详细说明书 规范；形式说明","example":"The parts were built exactly to the customer's specification.","exampleCn":"这些零件完全按照客户的规格制造。","level":"IELTS"},{"id":2659,"word":"midnight","phonetic":"/'midnait/","pos":"n.","meaning":"午夜；子夜；半夜 a. 午夜的；半夜的","example":"The train arrives at the station just before midnight.","exampleCn":"火车在午夜前到达车站。","level":"IELTS"},{"id":2660,"word":"integrity","phonetic":"/in'tegriti/","pos":"n.","meaning":"正直；廉正；完整 完整性","example":"A judge must be a person of great integrity.","exampleCn":"法官必须是非常正直的人。","level":"IELTS"},{"id":2661,"word":"oral","phonetic":"/'ɒ:rәl/","pos":"n.","meaning":"口试 a. 口头的；口述的；口部的","example":"Each student must pass an oral exam in English.","exampleCn":"每个学生都必须通过英语口试。","level":"IELTS"},{"id":2662,"word":"essence","phonetic":"/'esns/","pos":"n.","meaning":"实质；本质；香精 香精","example":"The essence of his speech was that change takes time.","exampleCn":"他演讲的实质是变革需要时间。","level":"IELTS"},{"id":2663,"word":"harsh","phonetic":"/hɑ:ʃ/","pos":"adj.","meaning":"粗糙的；刺耳的；严厉的 粗糙的；严厉的","example":"The coach was criticized for his harsh training methods.","exampleCn":"这位教练因训练方法严苛而受到批评。","level":"IELTS"},{"id":2664,"word":"closet","phonetic":"/'klɒzit/","pos":"n.","meaning":"壁橱；小室 a. 秘密的；空谈的 vt. 把...关入小室","example":"She hung her winter coats in the bedroom closet.","exampleCn":"她把冬衣挂在卧室的壁橱里。","level":"IELTS"},{"id":2665,"word":"retail","phonetic":"/'ri:teil/","pos":"n.","meaning":"零售 a. 零售的 vt. 零售；详述；传播 vi. 零售","example":"These shoes sell at a retail price of fifty dollars.","exampleCn":"这些鞋的零售价是五十美元。","level":"IELTS"},{"id":2666,"word":"mutter","phonetic":"/'mʌtә/","pos":"n.","meaning":"喃喃低语 vi. 喃喃自语；作低沉声 vt. 出怨言；抱怨地说","example":"He answered with an angry mutter and walked away.","exampleCn":"他愤愤地嘟囔了一句就走开了。","level":"IELTS"},{"id":2667,"word":"straightforward","phonetic":"/streit'fɒ:wәd/","pos":"adj.","meaning":"笔直的；率直的；明确的；简单的","example":"The instructions are straightforward and easy to follow.","exampleCn":"这些说明简单明了，容易照做。","level":"IELTS"},{"id":2668,"word":"hint","phonetic":"/hint/","pos":"n.","meaning":"暗示；提示 v. 暗示；示意","example":"She gave me a hint about my birthday present.","exampleCn":"她暗示了我生日礼物是什么。","level":"IELTS"},{"id":2669,"word":"convenient","phonetic":"/kәn'vi:njәnt/","pos":"adj.","meaning":"方便的；合宜的 适当的；合理而可行的；方便的","example":"The hotel is convenient for both shopping and transport.","exampleCn":"这家酒店购物和交通都很方便。","level":"IELTS"},{"id":2670,"word":"rumour","phonetic":"/'ru:mә/","pos":"n.","meaning":"谣言；传闻 vt. 谣传","example":"There is a rumour that the factory will close soon.","exampleCn":"有传言说这家工厂不久就要关闭。","level":"IELTS"},{"id":2671,"word":"artificial","phonetic":"/.ɑ:ti'fiʃәl/","pos":"adj.","meaning":"人造的；假的；非原地产的 人工的；人造的","example":"The lake in the park is actually artificial.","exampleCn":"公园里的那个湖其实是人工的。","level":"IELTS"},{"id":2672,"word":"flash","phonetic":"/flæʃ/","pos":"n.","meaning":"闪光；闪现；一瞬间 vi. 闪光；闪现","example":"A flash of lightning lit up the night sky.","exampleCn":"一道闪电照亮了夜空。","level":"IELTS"},{"id":2673,"word":"humanity","phonetic":"/hju:'mæniti/","pos":"n.","meaning":"人性；人类；博爱","example":"The discovery of fire changed the history of humanity.","exampleCn":"火的发现改变了人类的历史。","level":"IELTS"},{"id":2674,"word":"attendance","phonetic":"/ә'tendәns/","pos":"n.","meaning":"出席；出席的人数；照料 管理；照料","example":"Attendance at the morning lecture was surprisingly high.","exampleCn":"上午讲座的出席人数高得惊人。","level":"IELTS"},{"id":2675,"word":"fraction","phonetic":"/'frækʃәn/","pos":"n.","meaning":"小部分；破片；分数 部分；成分","example":"Only a small fraction of students passed the difficult test.","exampleCn":"只有一小部分学生通过了这次难度很大的考试。","level":"IELTS"},{"id":2676,"word":"reluctant","phonetic":"/ri'lʌktәnt/","pos":"adj.","meaning":"不情愿的；勉强的 不愿的；勉强的；难以处理的","example":"He was reluctant to lend his new car to anyone.","exampleCn":"他不愿意把新车借给任何人。","level":"IELTS"},{"id":2677,"word":"elbow","phonetic":"/'elbәu/","pos":"n.","meaning":"手肘；弯头；扶手 v. 用手肘推开；推挤","example":"She rested her elbow on the table while reading.","exampleCn":"她看书时把手肘支在桌子上。","level":"IELTS"},{"id":2678,"word":"deadly","phonetic":"/'dedli/","pos":"adj.","meaning":"致命的；致死的 adv. 非常；如死一般地","example":"This snake carries a deadly poison in its bite.","exampleCn":"这种蛇的咬伤带有致命的毒液。","level":"IELTS"},{"id":2679,"word":"confuse","phonetic":"/kәn'fju:z/","pos":"vt.","meaning":"使混乱；使狼狈；使困惑 混淆","example":"These similar road signs often confuse new drivers.","exampleCn":"这些相似的路标常常让新司机感到困惑。","level":"IELTS"},{"id":2680,"word":"drift","phonetic":"/drift/","pos":"n.","meaning":"漂流物；漂流；动向 v. (使)漂流","example":"The empty boat began to drift toward the open sea.","exampleCn":"那只空船开始向外海漂去。","level":"IELTS"},{"id":2681,"word":"plead","phonetic":"/pli:d/","pos":"vi.","meaning":"辩护；恳求 vt. 为...辩护；提出...借口；托称","example":"The lawyer advised him to plead not guilty in court.","exampleCn":"律师建议他在法庭上作无罪辩护。","level":"IELTS"},{"id":2682,"word":"harbour","phonetic":"/'hɑ:bә/","pos":"n.","meaning":"港；避难所 v. 庇护；藏匿；(使)入港停泊","example":"The ship stayed in the harbour during the storm.","exampleCn":"暴风雨期间，船停泊在港口里。","level":"IELTS"},{"id":2683,"word":"sandwich","phonetic":"/'sændwitʃ/","pos":"n.","meaning":"三明治；夹心面包；夹层板 vt. 插入；夹入","example":"I made a cheese sandwich for lunch today.","exampleCn":"我今天午餐做了一个奶酪三明治。","level":"IELTS"},{"id":2684,"word":"dock","phonetic":"/dɒk/","pos":"n.","meaning":"码头；船坞；被告席；尾巴的骨肉部分 vt. 使靠码头","example":"The ferry arrived at the dock right on time.","exampleCn":"渡轮准时抵达了码头。","level":"IELTS"},{"id":2685,"word":"suburb","phonetic":"/'sʌbә:b/","pos":"n.","meaning":"市郊住宅区；郊区；边缘","example":"They moved to a quiet suburb outside the city.","exampleCn":"他们搬到了城外一个安静的郊区。","level":"IELTS"},{"id":2686,"word":"trunk","phonetic":"/trʌŋk/","pos":"n.","meaning":"树干；干线；躯干；主干","example":"The old oak has a trunk two metres wide.","exampleCn":"这棵老橡树的树干有两米宽。","level":"IELTS"},{"id":2687,"word":"magnificent","phonetic":"/mæg'nifisnt/","pos":"adj.","meaning":"华丽的；高尚的；宏伟的","example":"The palace looks magnificent in the evening light.","exampleCn":"宫殿在暮色中显得宏伟壮丽。","level":"IELTS"},{"id":2688,"word":"motivate","phonetic":"/'mәutiveit/","pos":"vt.","meaning":"给与动机；刺激；提高...的学习欲望；促动 促动","example":"Good teachers know how to motivate their students to learn.","exampleCn":"好老师懂得如何激发学生的学习动力。","level":"IELTS"},{"id":2689,"word":"seemingly","phonetic":"/'si:miŋli/","pos":"adv.","meaning":"看来似乎；表面上看来","example":"The seemingly simple question took hours to answer.","exampleCn":"这个看似简单的问题花了几个小时才回答出来。","level":"IELTS"},{"id":2690,"word":"lens","phonetic":"/lenz/","pos":"n.","meaning":"透镜；镜头；镜片；晶状体 vt. 给...摄影","example":"He cleaned the camera lens before taking the photo.","exampleCn":"拍照前他擦干净了相机镜头。","level":"IELTS"},{"id":2691,"word":"proposition","phonetic":"/.prɒpә'ziʃәn/","pos":"n.","meaning":"建议；命题；主张 vt. 向...提议；向...提出猥亵的要求","example":"The committee rejected the proposition to raise ticket prices.","exampleCn":"委员会否决了提高票价的提议。","level":"IELTS"},{"id":2692,"word":"theft","phonetic":"/θeft/","pos":"n.","meaning":"盗窃；失窃；盗窃罪；赃物 盗窃行为","example":"He reported the theft of his bicycle to the police.","exampleCn":"他向警方报告了自行车被盗的事。","level":"IELTS"},{"id":2693,"word":"enforce","phonetic":"/in'fɒ:s/","pos":"vt.","meaning":"强迫；执行；坚持 予以强制执行","example":"The police will strictly enforce the new parking rules.","exampleCn":"警方将严格执行新的停车规定。","level":"IELTS"},{"id":2694,"word":"triumph","phonetic":"/'traiәmf/","pos":"n.","meaning":"凯旋；胜利；欢欣 vi. 得胜；成功","example":"Winning the championship was a great triumph for the team.","exampleCn":"夺得冠军是这支球队的巨大胜利。","level":"IELTS"},{"id":2695,"word":"cliff","phonetic":"/klif/","pos":"n.","meaning":"悬崖；绝壁","example":"The white house stands on a cliff above the sea.","exampleCn":"那座白房子矗立在海边的悬崖上。","level":"IELTS"},{"id":2696,"word":"fraud","phonetic":"/frɒ:d/","pos":"n.","meaning":"欺骗；欺诈；诡计；骗子 欺诈","example":"The manager was arrested for tax fraud last week.","exampleCn":"那位经理上周因税务欺诈被捕。","level":"IELTS"},{"id":2697,"word":"contend","phonetic":"/kәn'tend/","pos":"vi.","meaning":"奋斗；斗争；竞争 vt. 为...斗争","example":"Several companies will contend for the building contract.","exampleCn":"几家公司将竞争这份建筑合同。","level":"IELTS"},{"id":2698,"word":"array","phonetic":"/ә'rei/","pos":"n.","meaning":"排列；衣服；大批；军队 vt. 布署","example":"The shop displayed an impressive array of fresh fruits.","exampleCn":"店里陈列着一大批令人眼花缭乱的新鲜水果。","level":"IELTS"},{"id":2699,"word":"chemistry","phonetic":"/'kemistri/","pos":"n.","meaning":"化学；化学过程 化学","example":"She is studying chemistry at a famous university.","exampleCn":"她在一所名牌大学学习化学。","level":"IELTS"},{"id":2700,"word":"assemble","phonetic":"/ә'sembl/","pos":"vt.","meaning":"集合；收集；装配 vi. 集合 汇编","example":"Workers assemble the cars on a long production line.","exampleCn":"工人们在长长的生产线上组装汽车。","level":"IELTS"},{"id":2701,"word":"champagne","phonetic":"/ʃæm'pein/","pos":"n.","meaning":"香槟酒；香槟酒色 香槟酒","example":"They opened a bottle of champagne to celebrate the victory.","exampleCn":"他们开了一瓶香槟庆祝胜利。","level":"IELTS"},{"id":2702,"word":"provoke","phonetic":"/prә'vәuk/","pos":"vt.","meaning":"激怒；惹起；诱导 刺激；煽动","example":"His rude remarks were meant to provoke an argument.","exampleCn":"他粗鲁的话就是为了挑起争吵。","level":"IELTS"},{"id":2703,"word":"stimulate","phonetic":"/'stimjuleit/","pos":"vt.","meaning":"刺激；激励；鼓舞 vi. 起刺激作用","example":"Lower interest rates may stimulate spending and investment.","exampleCn":"降低利率可能会刺激消费和投资。","level":"IELTS"},{"id":2704,"word":"cave","phonetic":"/keiv/","pos":"n.","meaning":"洞；穴 vi. 凹陷；塌落 vt. 挖洞；使凹陷","example":"The bears sleep in a cave during the winter.","exampleCn":"熊在冬天睡在洞穴里。","level":"IELTS"},{"id":2705,"word":"refusal","phonetic":"/ri'fju:zl/","pos":"n.","meaning":"拒绝；推却；优先决定权 拒绝；谢绝","example":"Her refusal to sign the contract surprised everyone.","exampleCn":"她拒绝签合同让所有人都很吃惊。","level":"IELTS"},{"id":2706,"word":"monster","phonetic":"/'mɒnstә/","pos":"n.","meaning":"怪物；恶人；巨物 畸胎","example":"The children drew a green monster with three eyes.","exampleCn":"孩子们画了一个长着三只眼睛的绿色怪物。","level":"IELTS"},{"id":2707,"word":"diplomatic","phonetic":"/.diplә'mætik/","pos":"adj.","meaning":"外交的；老练的 外交的；外交上的；文献上的","example":"The two countries restored diplomatic relations last year.","exampleCn":"两国去年恢复了外交关系。","level":"IELTS"},{"id":2708,"word":"whereby","phonetic":"/(h)weә'bai/","pos":"adv.","meaning":"靠什么；如何；为何；靠那个","example":"They signed a deal whereby each side shares the cost.","exampleCn":"他们签署了一项协议，据此双方分摊费用。","level":"IELTS"},{"id":2709,"word":"facilitate","phonetic":"/fә'siliteit/","pos":"vt.","meaning":"使容易；促进；帮助 使容易；使便利","example":"The new bridge will facilitate trade between the two towns.","exampleCn":"新桥将促进两镇之间的贸易。","level":"IELTS"},{"id":2710,"word":"obstacle","phonetic":"/'ɒbstәkl/","pos":"n.","meaning":"障碍；妨害物；阻碍","example":"Lack of money is the biggest obstacle to his plan.","exampleCn":"缺钱是他计划的最大障碍。","level":"IELTS"},{"id":2711,"word":"leaflet","phonetic":"/'li:flit/","pos":"n.","meaning":"小叶；传单 小叶","example":"A volunteer handed me a leaflet about the concert.","exampleCn":"一位志愿者递给我一张音乐会的传单。","level":"IELTS"},{"id":2712,"word":"rip","phonetic":"/rip/","pos":"n.","meaning":"裂痕；破绽；拉裂；浪子","example":"There was a long rip in the side of the tent.","exampleCn":"帐篷侧面有一道长长的裂口。","level":"IELTS"},{"id":2713,"word":"herb","phonetic":"/hә:b/","pos":"n.","meaning":"药草；香草 草；草本；草药","example":"This herb is often used to make traditional medicine.","exampleCn":"这种药草常被用来制作传统药物。","level":"IELTS"},{"id":2714,"word":"indicator","phonetic":"/'indikeitә/","pos":"n.","meaning":"指示器；指示剂；指标 指示器","example":"Unemployment is a key indicator of economic health.","exampleCn":"失业率是经济健康状况的重要指标。","level":"IELTS"},{"id":2715,"word":"filter","phonetic":"/'filtә/","pos":"n.","meaning":"滤波器；过滤器；滤光器；过滤嘴","example":"Change the water filter every three months for safety.","exampleCn":"为了安全起见，每三个月更换一次滤水器。","level":"IELTS"},{"id":2716,"word":"marine","phonetic":"/mә'ri:n/","pos":"n.","meaning":"舰队；水兵；海景画 a. 海的；海产的","example":"Pollution is a serious threat to marine life.","exampleCn":"污染对海洋生物是一个严重威胁。","level":"IELTS"},{"id":2717,"word":"spectrum","phonetic":"/'spektrәm/","pos":"n.","meaning":"光谱；范围；系列 光谱","example":"The survey covered a wide spectrum of political opinions.","exampleCn":"这项调查涵盖了范围广泛的政治观点。","level":"IELTS"},{"id":2718,"word":"nightmare","phonetic":"/'naitmєә/","pos":"n.","meaning":"梦魇；恶梦；可怕的事物(或情景、人物) 梦魇；恶梦","example":"The long traffic jam turned our trip into a nightmare.","exampleCn":"长时间的堵车把我们的旅行变成了一场噩梦。","level":"IELTS"},{"id":2719,"word":"supervisor","phonetic":"/.sju:pә'vaizә/","pos":"n.","meaning":"管理者；监督者；指导者；视导员 管理程序","example":"Ask your supervisor before leaving work early today.","exampleCn":"今天想早退要先问问你的主管。","level":"IELTS"},{"id":2720,"word":"arena","phonetic":"/ә'ri:nә/","pos":"n.","meaning":"角斗场；舞台；场地 尿沉渣；尿沙","example":"Thousands of fans filled the arena before the match.","exampleCn":"比赛开始前，数千名球迷挤满了赛场。","level":"IELTS"},{"id":2721,"word":"skirt","phonetic":"/skә:t/","pos":"n.","meaning":"裙子；下摆；边缘；郊区 vt. 位于...边缘","example":"She wore a long blue skirt to the wedding.","exampleCn":"她穿着一条蓝色长裙参加婚礼。","level":"IELTS"},{"id":2722,"word":"hierarchy","phonetic":"/'haiәrɑ:ki/","pos":"n.","meaning":"等级制度；僧侣统治；等级体系 分级结构；分层结构","example":"He slowly rose through the company hierarchy to manager.","exampleCn":"他在公司的等级体系中慢慢升到了经理。","level":"IELTS"},{"id":2723,"word":"mathematics","phonetic":"/.mæθә'mætiks/","pos":"n.","meaning":"数学 数学","example":"She teaches mathematics at the local high school.","exampleCn":"她在当地的高中教数学。","level":"IELTS"},{"id":2724,"word":"wildlife","phonetic":"/'waildlaif/","pos":"n.","meaning":"野生动植物","example":"The new park protects wildlife from illegal hunting.","exampleCn":"新公园保护野生动物免遭非法捕猎。","level":"IELTS"},{"id":2725,"word":"basement","phonetic":"/'beismәnt/","pos":"n.","meaning":"地下室；墙脚 地下室","example":"We store old furniture in the basement of our house.","exampleCn":"我们把旧家具存放在房子的地下室里。","level":"IELTS"},{"id":2726,"word":"drain","phonetic":"/drein/","pos":"n.","meaning":"排水沟；消耗；排水 vt. 排出；喝光","example":"Heavy rain blocked the drain outside our house.","exampleCn":"大雨堵塞了我们房子外面的排水沟。","level":"IELTS"},{"id":2727,"word":"productivity","phonetic":"/.prәudʌk'tiviti/","pos":"n.","meaning":"生产力 生产率；生产能力","example":"New machines greatly increased the factory's productivity.","exampleCn":"新机器大大提高了工厂的生产率。","level":"IELTS"},{"id":2728,"word":"doctrine","phonetic":"/'dɒktrin/","pos":"n.","meaning":"教条；学说 学说","example":"The professor explained the central doctrine of the theory.","exampleCn":"教授讲解了该理论的核心学说。","level":"IELTS"},{"id":2729,"word":"questionnaire","phonetic":"/kwestʃә'nєә/","pos":"n.","meaning":"调查表；问卷 调查表","example":"Please fill in the questionnaire before you leave.","exampleCn":"离开前请填写这份调查问卷。","level":"IELTS"},{"id":2730,"word":"bacteria","phonetic":"/bæk'tiәriә/","pos":"n.","meaning":"pl. 细菌 细菌；杆菌","example":"Washing your hands removes harmful bacteria from your skin.","exampleCn":"洗手能去除皮肤上的有害细菌。","level":"IELTS"},{"id":2731,"word":"sociology","phonetic":"/.sәusi'ɒlәdʒi/","pos":"n.","meaning":"社会学 社会学","example":"She studied sociology to understand how societies change.","exampleCn":"她学习社会学以了解社会是如何变迁的。","level":"IELTS"},{"id":2732,"word":"spare","phonetic":"/spєә/","pos":"n.","meaning":"剩余；备用品；备件；备用零件","example":"Always keep a spare key in a safe place.","exampleCn":"一定要在安全的地方放一把备用钥匙。","level":"IELTS"},{"id":2733,"word":"suck","phonetic":"/sʌk/","pos":"vt.","meaning":"吸；吮；吸入；吮吸","example":"Babies naturally suck their thumbs to comfort themselves.","exampleCn":"婴儿会自然地吮吸拇指来安抚自己。","level":"IELTS"},{"id":2734,"word":"random","phonetic":"/'rændәm/","pos":"n.","meaning":"随意；随机 a. 任意的；随便的；胡乱的","example":"The winners were chosen at random from all entries.","exampleCn":"获奖者是从所有参赛者中随机选出的。","level":"IELTS"},{"id":2735,"word":"intelligent","phonetic":"/in'telidʒәnt/","pos":"adj.","meaning":"聪明的；智能的；了解的","example":"Dolphins are highly intelligent animals that learn quickly.","exampleCn":"海豚是学习能力很强的高智商动物。","level":"IELTS"},{"id":2736,"word":"unfair","phonetic":"/.ʌn'fєә/","pos":"adj.","meaning":"不公平的；不正直的；不正当的 不正直的；不公平的","example":"The workers protested against the unfair pay system.","exampleCn":"工人们抗议不公平的薪酬制度。","level":"IELTS"},{"id":2737,"word":"weird","phonetic":"/wiәd/","pos":"adj.","meaning":"怪异的；超自然的；不可思议的 n. 命运；预言","example":"A weird noise came from the empty house at night.","exampleCn":"夜里那座空房子里传来奇怪的声音。","level":"IELTS"},{"id":2738,"word":"ridiculous","phonetic":"/ri'dikjulәs/","pos":"adj.","meaning":"荒谬的；可笑的","example":"It is ridiculous to pay so much for a coffee.","exampleCn":"花这么多钱买一杯咖啡太荒谬了。","level":"IELTS"},{"id":2739,"word":"receipt","phonetic":"/ri'si:t/","pos":"n.","meaning":"收据；收入；收到 vt. 开...的收据","example":"Keep the receipt in case you want to return it.","exampleCn":"保留好收据，以防你想退货。","level":"IELTS"},{"id":2740,"word":"avenue","phonetic":"/'ævәnju:/","pos":"n.","meaning":"大街；途径；林荫路","example":"Their office is on a busy avenue downtown.","exampleCn":"他们的办公室位于市中心一条繁忙的大街上。","level":"IELTS"},{"id":2741,"word":"walking","phonetic":"/'wɒ:kiŋ/","pos":"n.","meaning":"步行；步态 a. 步行的；步行用的","example":"The hotel is within walking distance of the beach.","exampleCn":"酒店离海滩只有步行的距离。","level":"IELTS"},{"id":2742,"word":"dump","phonetic":"/dʌmp/","pos":"n.","meaning":"垃圾场 vt. 倾倒；倾销 vi. 倒垃圾；倾销商品 转出；转储","example":"Trucks dump waste at the site outside the city.","exampleCn":"卡车把废料倾倒在城外的场地上。","level":"IELTS"},{"id":2743,"word":"uncomfortable","phonetic":"/.ʌn'kʌmfәtәbl/","pos":"adj.","meaning":"不舒服的；不自在的；不安的","example":"The long silence made everyone feel uncomfortable.","exampleCn":"长时间的沉默让每个人都感到不自在。","level":"IELTS"},{"id":2744,"word":"merit","phonetic":"/'merit/","pos":"n.","meaning":"优点；功绩；价值；功过","example":"The great merit of this plan is its low cost.","exampleCn":"这个计划的最大优点是成本低。","level":"IELTS"},{"id":2745,"word":"execute","phonetic":"/'eksikju:t/","pos":"vt.","meaning":"执行；实行；完成；处死","example":"The team will execute the plan early next week.","exampleCn":"团队将于下周初执行该计划。","level":"IELTS"},{"id":2746,"word":"limb","phonetic":"/lim/","pos":"n.","meaning":"四肢；枝干；翼；边缘 vt. 切断...之手足","example":"He broke a limb when he fell from the tree.","exampleCn":"他从树上摔下来摔断了一条腿。","level":"IELTS"},{"id":2747,"word":"spectacular","phonetic":"/spek'tækjulә/","pos":"adj.","meaning":"公开展示的；惊人的；壮观的 n. 奇观；惊人之举","example":"The fireworks gave a spectacular show over the river.","exampleCn":"烟花在河面上空呈现出壮观的景象。","level":"IELTS"},{"id":2748,"word":"tune","phonetic":"/tju:n/","pos":"n.","meaning":"歌曲；主旋律；心情；声调","example":"She hummed a cheerful tune while cooking dinner.","exampleCn":"她一边做晚饭一边哼着欢快的曲子。","level":"IELTS"},{"id":2749,"word":"nasty","phonetic":"/'nɑ:sti/","pos":"adj.","meaning":"污秽的；下流的；险恶的","example":"He left a nasty comment under the photo.","exampleCn":"他在照片下留了一条恶毒的评论。","level":"IELTS"},{"id":2750,"word":"chronic","phonetic":"/'krɒnik/","pos":"adj.","meaning":"慢性的；习惯性的 n. 慢性病患者","example":"Years of stress gave him a chronic back problem.","exampleCn":"多年的压力使他患上了慢性背疾。","level":"IELTS"},{"id":2751,"word":"residence","phonetic":"/'rezidәns/","pos":"n.","meaning":"住宅；居留；驻扎；居住期间 住房","example":"The story treated the residence as an important detail.","exampleCn":"这个故事把住宅当作一个重要细节。","level":"IELTS"},{"id":2752,"word":"administer","phonetic":"/әd'ministә/","pos":"vt.","meaning":"管理；料理；执行 vi. 执行遗产管理人的职责；给予帮助","example":"Nurses administer the medicine twice a day.","exampleCn":"护士每天两次给药。","level":"IELTS"},{"id":2753,"word":"heading","phonetic":"/'hediŋ/","pos":"n.","meaning":"标题；起始字；方向 上标题","example":"The team focused on the heading during the meeting.","exampleCn":"团队在会议中重点关注了标题。","level":"IELTS"},{"id":2754,"word":"dancer","phonetic":"/'dɑ:nsә/","pos":"n.","meaning":"舞蹈演员；跳舞者","example":"She noticed the dancer while reviewing the notes.","exampleCn":"她复习笔记时注意到了舞蹈演员。","level":"IELTS"},{"id":2755,"word":"pad","phonetic":"/pæd/","pos":"n.","meaning":"填补；衬垫；印色盒；路 vt. 填补","example":"The story treated the pad as an important detail.","exampleCn":"这个故事把填补当作一个重要细节。","level":"IELTS"},{"id":2756,"word":"transmission","phonetic":"/træns'miʃәn/","pos":"n.","meaning":"传输；传送；变速器 传输","example":"The report explained the transmission in simple language.","exampleCn":"这份报告用简单语言解释了传输。","level":"IELTS"},{"id":2757,"word":"trigger","phonetic":"/'trigә/","pos":"n.","meaning":"触发器；扳机 vt. 触发；发射；引起 vi. 松开扳柄 切换开关","example":"The team focused on the trigger during the meeting.","exampleCn":"团队在会议中重点关注了触发器。","level":"IELTS"},{"id":2758,"word":"isolation","phonetic":"/.aisә'leiʃәn/","pos":"n.","meaning":"隔绝；孤立；隔离 分离；生物分离","example":"She noticed the isolation while reviewing the notes.","exampleCn":"她复习笔记时注意到了隔绝。","level":"IELTS"},{"id":2759,"word":"spill","phonetic":"/spil/","pos":"n.","meaning":"溢出；溅出；摔下；溢出量","example":"The story treated the spill as an important detail.","exampleCn":"这个故事把溢出当作一个重要细节。","level":"IELTS"},{"id":2760,"word":"twist","phonetic":"/twist/","pos":"n.","meaning":"一扭；扭曲；曲折；歪曲","example":"The report explained the twist in simple language.","exampleCn":"这份报告用简单语言解释了一扭。","level":"IELTS"},{"id":2761,"word":"virtual","phonetic":"/'vә:tʃuәl/","pos":"adj.","meaning":"实际上起作用的；虚的；实质的；有效的","example":"Her response sounded virtual in that situation.","exampleCn":"在那种情况下，她的回应显得很实际上起作用的。","level":"IELTS"},{"id":2762,"word":"fluid","phonetic":"/'flu:id/","pos":"n.","meaning":"液体；分泌液；流体 a. 流动的；可改变的","example":"She noticed the fluid while reviewing the notes.","exampleCn":"她复习笔记时注意到了液体。","level":"IELTS"},{"id":2763,"word":"convict","phonetic":"/kәn'vikt/","pos":"n.","meaning":"囚犯；罪犯 vt. 宣告有罪；使知罪","example":"The story treated the convict as an important detail.","exampleCn":"这个故事把囚犯当作一个重要细节。","level":"IELTS"},{"id":2764,"word":"indigenous","phonetic":"/in'didʒinәs/","pos":"adj.","meaning":"本土的；国产的；固有的 原产的；本土的","example":"The forest is home to many indigenous plants.","exampleCn":"这片森林有许多本土植物。","level":"IELTS"},{"id":2765,"word":"directory","phonetic":"/di'rektәri/","pos":"n.","meaning":"目录；工商名录；指南 目录","example":"The team focused on the directory during the meeting.","exampleCn":"团队在会议中重点关注了目录。","level":"IELTS"},{"id":2766,"word":"decent","phonetic":"/'di:sәnt/","pos":"adj.","meaning":"有分寸的；得体的；大方的","example":"He found a decent apartment near school.","exampleCn":"他在学校附近找到了一套不错的公寓。","level":"IELTS"},{"id":2767,"word":"towel","phonetic":"/'tauәl/","pos":"n.","meaning":"手巾；毛巾 v. 擦干身子","example":"The story treated the towel as an important detail.","exampleCn":"这个故事把手巾当作一个重要细节。","level":"IELTS"},{"id":2768,"word":"convey","phonetic":"/kәn'vei/","pos":"vt.","meaning":"传达；运输；转让 转让(财产等)；搬运","example":"Her letter failed to convey her real feelings.","exampleCn":"她的信没能传达她真实的感受。","level":"IELTS"},{"id":2769,"word":"compromise","phonetic":"/'kɒmprәmaiz/","pos":"n.","meaning":"妥协；折中；折中方案；和解 vi. 妥协处理 vt. 危害","example":"The team focused on the compromise during the meeting.","exampleCn":"团队在会议中重点关注了妥协。","level":"IELTS"},{"id":2770,"word":"fetch","phonetic":"/fetʃ/","pos":"n.","meaning":"取得；拿；诡计；魂 vt. 接来","example":"She noticed the fetch while reviewing the notes.","exampleCn":"她复习笔记时注意到了取得。","level":"IELTS"},{"id":2771,"word":"boost","phonetic":"/bu:st/","pos":"n.","meaning":"推进；吹捧 vt. 推进；提高；宣扬","example":"The story treated the boost as an important detail.","exampleCn":"这个故事把推进当作一个重要细节。","level":"IELTS"},{"id":2772,"word":"cupboard","phonetic":"/'kʌpbɒ:d/","pos":"n.","meaning":"食橱；碗柜；餐具柜","example":"The report explained the cupboard in simple language.","exampleCn":"这份报告用简单语言解释了食橱。","level":"IELTS"},{"id":2773,"word":"faint","phonetic":"/feint/","pos":"n.","meaning":"昏厥；昏倒 a. 模糊的；微弱的；无力的 vi. 昏倒","example":"The team focused on the faint during the meeting.","exampleCn":"团队在会议中重点关注了昏厥。","level":"IELTS"},{"id":2774,"word":"duration","phonetic":"/dju'reiʃәn/","pos":"n.","meaning":"持续时间；持续 持续时间","example":"She noticed the duration while reviewing the notes.","exampleCn":"她复习笔记时注意到了持续时间。","level":"IELTS"},{"id":2775,"word":"breeding","phonetic":"/'bri:diŋ/","pos":"n.","meaning":"教养；生育；饲养 生育；繁殖","example":"The story treated the breeding as an important detail.","exampleCn":"这个故事把教养当作一个重要细节。","level":"IELTS"},{"id":2776,"word":"succession","phonetic":"/sәk'seʃәn/","pos":"n.","meaning":"连续；继承权；继位；演替","example":"The report explained the succession in simple language.","exampleCn":"这份报告用简单语言解释了连续。","level":"IELTS"},{"id":2777,"word":"web","phonetic":"/web/","pos":"n.","meaning":"网；蛛丝；蹼；织物","example":"The team focused on the web during the meeting.","exampleCn":"团队在会议中重点关注了网。","level":"IELTS"},{"id":2778,"word":"ballot","phonetic":"/'bælәt/","pos":"n.","meaning":"投票；投票用纸；抽签 vi. 投票；抽签 vt. 投票选出","example":"She noticed the ballot while reviewing the notes.","exampleCn":"她复习笔记时注意到了投票。","level":"IELTS"},{"id":2779,"word":"justification","phonetic":"/.dʒʌstifi'keiʃәn/","pos":"n.","meaning":"辩护；证明正当；释罪 调整","example":"The story treated the justification as an important detail.","exampleCn":"这个故事把辩护当作一个重要细节。","level":"IELTS"},{"id":2780,"word":"dean","phonetic":"/di:n/","pos":"n.","meaning":"院长；主持牧师 外交团长；学院院长；教务长","example":"The report explained the dean in simple language.","exampleCn":"这份报告用简单语言解释了院长。","level":"IELTS"},{"id":2781,"word":"driving","phonetic":"/'draiviŋ/","pos":"n.","meaning":"赶；操纵；驾驶 a. 推进的；强劲的","example":"The team focused on the driving during the meeting.","exampleCn":"团队在会议中重点关注了赶。","level":"IELTS"},{"id":2782,"word":"rhetoric","phonetic":"/'retәrik/","pos":"n.","meaning":"修辞；修辞学；雄辩(术)","example":"She noticed the rhetoric while reviewing the notes.","exampleCn":"她复习笔记时注意到了修辞。","level":"IELTS"},{"id":2783,"word":"wilderness","phonetic":"/'wildәnis/","pos":"n.","meaning":"荒野；荒地；大量","example":"The story treated wilderness as an important detail.","exampleCn":"这个故事把荒野当作一个重要细节。","level":"IELTS"},{"id":2784,"word":"breed","phonetic":"/bri:d/","pos":"n.","meaning":"种类；品种 v. 养育；引起；饲养","example":"The report explained the breed in simple language.","exampleCn":"这份报告用简单语言解释了种类。","level":"IELTS"},{"id":2785,"word":"explicit","phonetic":"/ik'splisit/","pos":"adj.","meaning":"详述的；清楚的；直言的","example":"Her response sounded explicit in that situation.","exampleCn":"在那种情况下，她的回应显得很详述的。","level":"IELTS"},{"id":2786,"word":"mandate","phonetic":"/'mændeit/","pos":"n.","meaning":"命令；指令；要求 vt. 委任统治","example":"She noticed the mandate while reviewing the notes.","exampleCn":"她复习笔记时注意到了命令。","level":"IELTS"},{"id":2787,"word":"seminar","phonetic":"/'seminɑ:/","pos":"n.","meaning":"研究班；专题讨论会 讨论会；专家讨论会","example":"The story treated the seminar as an important detail.","exampleCn":"这个故事把研究班当作一个重要细节。","level":"IELTS"},{"id":2788,"word":"chaos","phonetic":"/'keiɒs/","pos":"n.","meaning":"大混乱；混沌 混沌；浑沌","example":"The report explained chaos in simple language.","exampleCn":"这份报告用简单语言解释了大混乱。","level":"IELTS"},{"id":2789,"word":"abstract","phonetic":"/'æbstrækt/","pos":"adj.","meaning":"抽象的；深奥的 n. 摘要；抽象概念 vt. 摘要；提炼","example":"Her response sounded abstract in that situation.","exampleCn":"在那种情况下，她的回应显得很抽象的。","level":"IELTS"},{"id":2790,"word":"delegate","phonetic":"/'deligeit/","pos":"n.","meaning":"代表 vt. 委派...为代表","example":"She noticed the delegate while reviewing the notes.","exampleCn":"她复习笔记时注意到了代表。","level":"IELTS"},{"id":2791,"word":"canvas","phonetic":"/'kænvәs/","pos":"n.","meaning":"帆布；画布；油画 帆布","example":"The story treated canvas as an important detail.","exampleCn":"这个故事把帆布当作一个重要细节。","level":"IELTS"},{"id":2792,"word":"portfolio","phonetic":"/pɒ:t'fәuliәu/","pos":"n.","meaning":"皮包；公文包；部长职务；有价证券财产目录","example":"The report explained the portfolio in simple language.","exampleCn":"这份报告用简单语言解释了皮包。","level":"IELTS"},{"id":2793,"word":"profound","phonetic":"/prә'faund/","pos":"adj.","meaning":"极深的；深厚的；深刻的；渊博的","example":"Her response sounded profound in that situation.","exampleCn":"在那种情况下，她的回应显得很极深的。","level":"IELTS"},{"id":2794,"word":"lobby","phonetic":"/'lɒbi/","pos":"n.","meaning":"大厅；休息室；游说议员者 vi. 游说议员；游说 vt. 游说","example":"She noticed the lobby while reviewing the notes.","exampleCn":"她复习笔记时注意到了大厅。","level":"IELTS"},{"id":2795,"word":"abolish","phonetic":"/ә'bɒliʃ/","pos":"vt.","meaning":"废止；革除；消灭 废除；取消","example":"The country voted to abolish the old law.","exampleCn":"该国投票废除了旧法律。","level":"IELTS"},{"id":2796,"word":"trait","phonetic":"/treit/","pos":"n.","meaning":"特征；特性；一笔；少许","example":"The report explained the trait in simple language.","exampleCn":"这份报告用简单语言解释了特征。","level":"IELTS"},{"id":2797,"word":"allege","phonetic":"/ә'ledʒ/","pos":"vt.","meaning":"宣称；主张；提出；断言 断言","example":"Please allege the document carefully before you send it.","exampleCn":"发送之前，请仔细宣称这份文件。","level":"IELTS"},{"id":2798,"word":"beam","phonetic":"/bi:m/","pos":"n.","meaning":"横梁；杆；光线；容光焕发 vi. 用梁支承","example":"She noticed the beam while reviewing the notes.","exampleCn":"她复习笔记时注意到了横梁。","level":"IELTS"},{"id":2799,"word":"comparable","phonetic":"/'kɒmpәrәbl/","pos":"adj.","meaning":"可比较的；比得上的","example":"The result was comparable enough for everyone to notice.","exampleCn":"结果足够可比较的，大家都注意到了。","level":"IELTS"},{"id":2800,"word":"premium","phonetic":"/'pri:miәm/","pos":"n.","meaning":"额外补贴；奖金；奖赏；保险费 保险费","example":"The report explained the premium in simple language.","exampleCn":"这份报告用简单语言解释了额外补贴。","level":"IELTS"},{"id":2801,"word":"thumb","phonetic":"/θʌm/","pos":"n.","meaning":"拇指 vt. 以拇指拨弄；笨拙地摆弄；用拇指翻旧；迅速翻阅","example":"The team focused on the thumb during the meeting.","exampleCn":"团队在会议中重点关注了拇指。","level":"IELTS"},{"id":2802,"word":"appendix","phonetic":"/ә'pendiks/","pos":"n.","meaning":"附录；附加物；阑尾 增补","example":"She noticed the appendix while reviewing the notes.","exampleCn":"她复习笔记时注意到了附录。","level":"IELTS"},{"id":2803,"word":"horrible","phonetic":"/'hɒrәbl/","pos":"adj.","meaning":"可怕的；遭透的；极讨厌的","example":"The result was horrible enough for everyone to notice.","exampleCn":"结果足够可怕的，大家都注意到了。","level":"IELTS"},{"id":2804,"word":"scatter","phonetic":"/'skætә/","pos":"n.","meaning":"消散；分散；散播；散射","example":"The report explained the scatter in simple language.","exampleCn":"这份报告用简单语言解释了消散。","level":"IELTS"},{"id":2805,"word":"forum","phonetic":"/'fɒ:rәm/","pos":"n.","meaning":"论坛；公开讨论的广场；法庭；讨论会 讨论会","example":"The team focused on the forum during the meeting.","exampleCn":"团队在会议中重点关注了论坛。","level":"IELTS"},{"id":2806,"word":"frown","phonetic":"/fraun/","pos":"n.","meaning":"皱眉 vi. 皱眉头 vt. 皱眉表示","example":"She noticed the frown while reviewing the notes.","exampleCn":"她复习笔记时注意到了皱眉。","level":"IELTS"},{"id":2807,"word":"signature","phonetic":"/'signәtʃә/","pos":"n.","meaning":"签字；识别标志；调号 签名附件","example":"The story treated the signature as an important detail.","exampleCn":"这个故事把签字当作一个重要细节。","level":"IELTS"},{"id":2808,"word":"delicate","phonetic":"/'delikәt/","pos":"adj.","meaning":"细致优雅的；微妙的；美味的 柔弱的","example":"The glass bowl is beautiful but delicate.","exampleCn":"这个玻璃碗很漂亮但易碎。","level":"IELTS"},{"id":2809,"word":"panic","phonetic":"/'pænik/","pos":"n.","meaning":"恐慌；惊慌 a. 惊慌的；没有理由的；恐慌的 vt. 使惊慌","example":"The team focused on the panic during the meeting.","exampleCn":"团队在会议中重点关注了恐慌。","level":"IELTS"},{"id":2810,"word":"spouse","phonetic":"/spauz/","pos":"n.","meaning":"配偶","example":"She noticed the spouse while reviewing the notes.","exampleCn":"她复习笔记时注意到了配偶。","level":"IELTS"},{"id":2811,"word":"bonus","phonetic":"/'bәunәs/","pos":"n.","meaning":"奖金；红利 奖金；红利；额外补贴","example":"The story treated bonus as an important detail.","exampleCn":"这个故事把奖金当作一个重要细节。","level":"IELTS"},{"id":2812,"word":"resume","phonetic":"/ri'zju:m/","pos":"vt.","meaning":"重新开始；取回；恢复 vi. 再开始 n. 摘要；个人简历 继续执行","example":"The train service will resume tomorrow.","exampleCn":"列车服务将于明天恢复。","level":"IELTS"},{"id":2813,"word":"casual","phonetic":"/'kæʒjuәl/","pos":"adj.","meaning":"偶然的；不经意的；便装的 n. 临时工；待命士兵","example":"Her response sounded casual in that situation.","exampleCn":"在那种情况下，她的回应显得很偶然的。","level":"IELTS"},{"id":2814,"word":"riot","phonetic":"/'raiәt/","pos":"n.","meaning":"暴动；喧闹；放纵 vi. 发动；暴动","example":"She noticed the riot while reviewing the notes.","exampleCn":"她复习笔记时注意到了暴动。","level":"IELTS"},{"id":2815,"word":"persist","phonetic":"/pә'sist/","pos":"vi.","meaning":"坚持；固执；持续；坚称 持续","example":"The group continued to persist until the work was done.","exampleCn":"这个小组继续坚持，直到工作完成。","level":"IELTS"},{"id":2816,"word":"inherit","phonetic":"/in'herit/","pos":"vt.","meaning":"继承；遗传 vi. 接受遗产","example":"He will inherit the family business.","exampleCn":"他将继承家族企业。","level":"IELTS"},{"id":2817,"word":"extract","phonetic":"/ik'strækt/","pos":"n.","meaning":"榨出物；精汁；摘录；选段 vt. (费力地)取出","example":"The team focused on the extract during the meeting.","exampleCn":"团队在会议中重点关注了榨出物。","level":"IELTS"},{"id":2818,"word":"bounce","phonetic":"/bauns/","pos":"n.","meaning":"跳；跳跃；弹力；撞击 vi. 反跳","example":"She noticed the bounce while reviewing the notes.","exampleCn":"她复习笔记时注意到了跳。","level":"IELTS"},{"id":2819,"word":"steep","phonetic":"/sti:p/","pos":"n.","meaning":"浸渍；悬崖 a. 险峻的；陡峭的；急剧升降的","example":"The story treated the steep as an important detail.","exampleCn":"这个故事把浸渍当作一个重要细节。","level":"IELTS"},{"id":2820,"word":"click","phonetic":"/klik/","pos":"n.","meaning":"咔哒声；啪嗒声 vi. 作咔哒声 vt. 使发咔哒声 单击","example":"The report explained the click in simple language.","exampleCn":"这份报告用简单语言解释了咔哒声。","level":"IELTS"},{"id":2821,"word":"insert","phonetic":"/in'sә:t/","pos":"n.","meaning":"插入物 vt. 插入；把(人造卫星)射入(轨道)；添写 vi. 附着 插入","example":"The team focused on the insert during the meeting.","exampleCn":"团队在会议中重点关注了插入物。","level":"IELTS"},{"id":2822,"word":"dull","phonetic":"/dʌl/","pos":"adj.","meaning":"钝的；无趣的；呆滞的；阴暗的 vt. 使迟钝","example":"The lecture was long and dull.","exampleCn":"这场讲座又长又乏味。","level":"IELTS"},{"id":2823,"word":"dedicate","phonetic":"/'dedikeit/","pos":"vt.","meaning":"献出；贡献","example":"She will dedicate the book to her parents.","exampleCn":"她会把这本书献给父母。","level":"IELTS"},{"id":2824,"word":"carve","phonetic":"/kɑ:v/","pos":"v.","meaning":"雕刻；切开","example":"The artist can carve animals from wood.","exampleCn":"这位艺术家能用木头雕刻动物。","level":"IELTS"},{"id":2825,"word":"partial","phonetic":"/'pɑ:ʃәl/","pos":"adj.","meaning":"部分的；偏袒的；偏爱的 n. 分音","example":"Her response sounded partial in that situation.","exampleCn":"在那种情况下，她的回应显得很部分的。","level":"IELTS"},{"id":2826,"word":"belly","phonetic":"/'beli/","pos":"n.","meaning":"腹部；食欲 vt. 使鼓起 vi. 鼓起；匍匐前进","example":"She noticed the belly while reviewing the notes.","exampleCn":"她复习笔记时注意到了腹部。","level":"IELTS"},{"id":2827,"word":"conceive","phonetic":"/kәn'si:v/","pos":"vt.","meaning":"构思；认为 vi. 怀孕","example":"They conceived a new plan overnight.","exampleCn":"他们一夜之间构思了一个新计划。","level":"IELTS"},{"id":2828,"word":"cater","phonetic":"/'keitә/","pos":"v.","meaning":"提供饮食及服务；投合；迎合","example":"The hotel can cater for large conferences.","exampleCn":"这家酒店可以承办大型会议餐饮。","level":"IELTS"},{"id":2829,"word":"shuttle","phonetic":"/'ʃʌtl/","pos":"n.","meaning":"穿梭；梭子；往返移动之物 v. (使)穿梭移动；往返运送","example":"The team focused on the shuttle during the meeting.","exampleCn":"团队在会议中重点关注了穿梭。","level":"IELTS"},{"id":2830,"word":"invisible","phonetic":"/in'vizәbl/","pos":"adj.","meaning":"看不见的；无形的 无形的；表面上看不见的；未列在公开帐目的","example":"The virus is invisible to the naked eye.","exampleCn":"这种病毒肉眼看不见。","level":"IELTS"},{"id":2831,"word":"engagement","phonetic":"/in'geidʒdmәnt/","pos":"n.","meaning":"诺言；约会；婚约；交战 衔接","example":"The story treated the engagement as an important detail.","exampleCn":"这个故事把诺言当作一个重要细节。","level":"IELTS"},{"id":2832,"word":"ankle","phonetic":"/'æŋkl/","pos":"n.","meaning":"踝 踝；踝关节","example":"The report explained the ankle in simple language.","exampleCn":"这份报告用简单语言解释了踝。","level":"IELTS"},{"id":2833,"word":"swimming","phonetic":"/'swimiŋ/","pos":"n.","meaning":"游泳；眩晕","example":"The team focused on the swimming during the meeting.","exampleCn":"团队在会议中重点关注了游泳。","level":"IELTS"},{"id":2834,"word":"rescue","phonetic":"/'reskju:/","pos":"n.","meaning":"援救；解救；营救 vt. 援救；救出","example":"She noticed the rescue while reviewing the notes.","exampleCn":"她复习笔记时注意到了援救。","level":"IELTS"},{"id":2835,"word":"counterpart","phonetic":"/'kauntәpɑ:t/","pos":"n.","meaning":"副本；复本；配对物；相应物 副本","example":"The story treated the counterpart as an important detail.","exampleCn":"这个故事把副本当作一个重要细节。","level":"IELTS"},{"id":2836,"word":"neat","phonetic":"/ni:t/","pos":"adj.","meaning":"整洁的；巧妙的；匀称的；简洁的 n. 牛","example":"She keeps her desk neat and organized.","exampleCn":"她把书桌保持得整洁有序。","level":"IELTS"},{"id":2837,"word":"opt","phonetic":"/ɒpt/","pos":"vi.","meaning":"选择","example":"The situation may opt if no one takes action.","exampleCn":"如果没人采取行动，情况可能会选择。","level":"IELTS"},{"id":2838,"word":"amid","phonetic":"/ә'mid/","pos":"prep.","meaning":"在其间；在其中 在...中","example":"She noticed the amid while reviewing the notes.","exampleCn":"她复习笔记时注意到了在其间。","level":"IELTS"},{"id":2839,"word":"intensive","phonetic":"/in'tensiv/","pos":"adj.","meaning":"加强的；内涵的；集中的 n. 加强器","example":"The result was intensive enough for everyone to notice.","exampleCn":"结果足够加强的，大家都注意到了。","level":"IELTS"},{"id":2840,"word":"isolate","phonetic":"/'aisәleit/","pos":"vt.","meaning":"使隔离；使孤立；使绝缘 n. 隔离种群","example":"Doctors had to isolate the patient.","exampleCn":"医生不得不隔离这名病人。","level":"IELTS"},{"id":2841,"word":"diagnose","phonetic":"/'daiәgnәuz/","pos":"v.","meaning":"诊断","example":"The method can diagnose when conditions are right.","exampleCn":"条件合适时，这种方法可以诊断。","level":"IELTS"},{"id":2842,"word":"envisage","phonetic":"/in'vizidʒ/","pos":"vt.","meaning":"面对；正视；想象","example":"It is hard to envisage life without phones.","exampleCn":"很难想象没有手机的生活。","level":"IELTS"},{"id":2843,"word":"elegant","phonetic":"/'eligәnt/","pos":"adj.","meaning":"优雅的；端庄的；高雅的","example":"The result was elegant enough for everyone to notice.","exampleCn":"结果足够优雅的，大家都注意到了。","level":"IELTS"},{"id":2844,"word":"poster","phonetic":"/'pәustә/","pos":"n.","meaning":"海报；招贴；驿马","example":"The report explained the poster in simple language.","exampleCn":"这份报告用简单语言解释了海报。","level":"IELTS"},{"id":2845,"word":"concession","phonetic":"/kәn'seʃәn/","pos":"n.","meaning":"特许；让步；认可 核准；许可","example":"The team focused on the concession during the meeting.","exampleCn":"团队在会议中重点关注了特许。","level":"IELTS"},{"id":2846,"word":"crawl","phonetic":"/krɒ:l/","pos":"n.","meaning":"爬行；匍匐而行；养鱼池 v. 爬行","example":"She noticed the crawl while reviewing the notes.","exampleCn":"她复习笔记时注意到了爬行。","level":"IELTS"},{"id":2847,"word":"handsome","phonetic":"/'hænsәm/","pos":"adj.","meaning":"英俊的；大方的；慷慨的；相当可观的","example":"The result was handsome enough for everyone to notice.","exampleCn":"结果足够英俊的，大家都注意到了。","level":"IELTS"},{"id":2848,"word":"tutor","phonetic":"/'tju:tә/","pos":"n.","meaning":"家庭教师；导师；助教；监护人 vt. 当...的教师","example":"The report explained the tutor in simple language.","exampleCn":"这份报告用简单语言解释了家庭教师。","level":"IELTS"},{"id":2849,"word":"instinct","phonetic":"/'instiŋkt/","pos":"n.","meaning":"本能；直觉 a. 充满着的","example":"The team focused on the instinct during the meeting.","exampleCn":"团队在会议中重点关注了本能。","level":"IELTS"},{"id":2850,"word":"promising","phonetic":"/'prɒmisiŋ/","pos":"adj.","meaning":"有希望的；前途有望的 有希望的","example":"The young player has a promising future.","exampleCn":"这位年轻球员前途很有希望。","level":"IELTS"},{"id":2851,"word":"damp","phonetic":"/dæmp/","pos":"n.","meaning":"潮湿；湿气 a. 潮湿的 vt. 使潮湿；使阻尼；抑止 vi. 变潮湿","example":"The story treated the damp as an important detail.","exampleCn":"这个故事把潮湿当作一个重要细节。","level":"IELTS"},{"id":2852,"word":"eagle","phonetic":"/'i:gl/","pos":"n.","meaning":"鹰；鹰状标饰","example":"The report explained the eagle in simple language.","exampleCn":"这份报告用简单语言解释了鹰。","level":"IELTS"},{"id":2853,"word":"preliminary","phonetic":"/pri'liminәri/","pos":"n.","meaning":"初步做法；初步措施；预试；预选赛 a. 初步的","example":"The team focused on the preliminary during the meeting.","exampleCn":"团队在会议中重点关注了初步做法。","level":"IELTS"},{"id":2854,"word":"diagram","phonetic":"/'daiәɡræm/","pos":"n.","meaning":"图表；图解","example":"She noticed the diagram while reviewing the notes.","exampleCn":"她复习笔记时注意到了图表。","level":"IELTS"},{"id":2855,"word":"vertical","phonetic":"/'vә:tikl/","pos":"adj.","meaning":"垂直的；直立的 垂直的；顶的；头顶的","example":"The result was vertical enough for everyone to notice.","exampleCn":"结果足够垂直的，大家都注意到了。","level":"IELTS"},{"id":2856,"word":"hug","phonetic":"/hʌg/","pos":"n.","meaning":"紧抱；拥抱 vt. 紧抱；坚持；使沾沾自喜","example":"The report explained the hug in simple language.","exampleCn":"这份报告用简单语言解释了紧抱。","level":"IELTS"},{"id":2857,"word":"fancy","phonetic":"/'fænsi/","pos":"n.","meaning":"想象力；幻想；喜好 a. 想象的；精美的","example":"The team focused on the fancy during the meeting.","exampleCn":"团队在会议中重点关注了想象力。","level":"IELTS"},{"id":2858,"word":"ambulance","phonetic":"/'æmbjulәns/","pos":"n.","meaning":"救护车 救护车","example":"She noticed the ambulance while reviewing the notes.","exampleCn":"她复习笔记时注意到了救护车。","level":"IELTS"},{"id":2859,"word":"pavement","phonetic":"/'peivmәnt/","pos":"n.","meaning":"路面；人行道；铺面路；铺路材料","example":"The story treated the pavement as an important detail.","exampleCn":"这个故事把路面当作一个重要细节。","level":"IELTS"},{"id":2860,"word":"concede","phonetic":"/kәn'si:d/","pos":"vt.","meaning":"承认；退让 vi. 让步","example":"He refused to concede defeat.","exampleCn":"他拒绝承认失败。","level":"IELTS"},{"id":2861,"word":"sphere","phonetic":"/sfiә/","pos":"n.","meaning":"球；球面；球体；天体","example":"The team focused on the sphere during the meeting.","exampleCn":"团队在会议中重点关注了球。","level":"IELTS"},{"id":2862,"word":"reign","phonetic":"/rein/","pos":"v.","meaning":"为王；为君；当政；统治 n. 为王","example":"She wanted to reign without wasting time.","exampleCn":"她想不浪费时间地为王。","level":"IELTS"},{"id":2863,"word":"parallel","phonetic":"/'pærәlel/","pos":"n.","meaning":"平行；对比；相匹敌之物 a. 平行的；相似的 vt. 与...平行","example":"The story treated the parallel as an important detail.","exampleCn":"这个故事把平行当作一个重要细节。","level":"IELTS"},{"id":2864,"word":"elevator","phonetic":"/'eliveitә/","pos":"n.","meaning":"电梯；升降机 提升机","example":"The report explained the elevator in simple language.","exampleCn":"这份报告用简单语言解释了电梯。","level":"IELTS"},{"id":2865,"word":"statue","phonetic":"/'stætju/","pos":"vt.","meaning":"以雕像装饰 n. 雕像","example":"Please statue the document carefully before you send it.","exampleCn":"发送之前，请仔细以雕像装饰这份文件。","level":"IELTS"},{"id":2866,"word":"clash","phonetic":"/klæʃ/","pos":"n.","meaning":"冲突；撞击声；抵触 vi. 冲突；抵触 vt. 使发出撞击声 对撞","example":"She noticed the clash while reviewing the notes.","exampleCn":"她复习笔记时注意到了冲突。","level":"IELTS"},{"id":2867,"word":"pursuit","phonetic":"/pә'sju:t/","pos":"n.","meaning":"追踪；追求；追赶；娱乐","example":"The story treated the pursuit as an important detail.","exampleCn":"这个故事把追踪当作一个重要细节。","level":"IELTS"},{"id":2868,"word":"entity","phonetic":"/'entiti/","pos":"n.","meaning":"实体；实存物；存在 实体","example":"The report explained the entity in simple language.","exampleCn":"这份报告用简单语言解释了实体。","level":"IELTS"},{"id":2869,"word":"gym","phonetic":"/dʒim/","pos":"n.","meaning":"+体育馆；体育训练；体育课；体操","example":"The team focused on the gym during the meeting.","exampleCn":"团队在会议中重点关注了+体育馆。","level":"IELTS"},{"id":2870,"word":"disclose","phonetic":"/dis'klәuz/","pos":"vt.","meaning":"揭露；透露 揭发；揭露；公开","example":"The company refused to disclose the details.","exampleCn":"公司拒绝透露细节。","level":"IELTS"},{"id":2871,"word":"fist","phonetic":"/fist/","pos":"n.","meaning":"拳头；手 vt. 拳打；握成拳；紧握","example":"The story treated the fist as an important detail.","exampleCn":"这个故事把拳头当作一个重要细节。","level":"IELTS"},{"id":2872,"word":"destination","phonetic":"/.desti'neiʃәn/","pos":"n.","meaning":"目的地；目标；目的 目的文件；目的单元","example":"The report explained the destination in simple language.","exampleCn":"这份报告用简单语言解释了目的地。","level":"IELTS"},{"id":2873,"word":"update","phonetic":"/ʌp'deit/","pos":"vt.","meaning":"更新；使现代化 n. 更新 更新","example":"Please update the document carefully before you send it.","exampleCn":"发送之前，请仔细更新这份文件。","level":"IELTS"},{"id":2874,"word":"endorse","phonetic":"/in'dɒ:s/","pos":"vt.","meaning":"支持；赞同；背书于；签署 赞成","example":"Several experts endorse this method.","exampleCn":"几位专家支持这种方法。","level":"IELTS"},{"id":2875,"word":"thesis","phonetic":"/'θi:sis/","pos":"n.","meaning":"论题；论文","example":"The story treated thesis as an important detail.","exampleCn":"这个故事把论题当作一个重要细节。","level":"IELTS"},{"id":2876,"word":"feedback","phonetic":"/'fi:dbæk/","pos":"n.","meaning":"反馈；反应 反馈","example":"The report explained the feedback in simple language.","exampleCn":"这份报告用简单语言解释了反馈。","level":"IELTS"},{"id":2877,"word":"commonwealth","phonetic":"/'kɔmәnwelθ/","pos":"n.","meaning":"共和国；联邦；国民整体","example":"The team focused on the commonwealth during the meeting.","exampleCn":"团队在会议中重点关注了共和国。","level":"IELTS"},{"id":2878,"word":"sunlight","phonetic":"/'sʌnlait/","pos":"n.","meaning":"日光 日光；太阳光","example":"She noticed the sunlight while reviewing the notes.","exampleCn":"她复习笔记时注意到了日光。","level":"IELTS"},{"id":2879,"word":"laser","phonetic":"/'leizә/","pos":"n.","meaning":"激光 激光器","example":"The story treated the laser as an important detail.","exampleCn":"这个故事把激光当作一个重要细节。","level":"IELTS"},{"id":2880,"word":"bold","phonetic":"/bәuld/","pos":"adj.","meaning":"大胆的 n. 粗体 粗体","example":"She made a bold decision to start over.","exampleCn":"她大胆决定重新开始。","level":"IELTS"},{"id":2881,"word":"starting","phonetic":"/'stɑ:tiŋ/","pos":"n.","meaning":"开端；开始；出发；起动","example":"The team focused on the starting during the meeting.","exampleCn":"团队在会议中重点关注了开端。","level":"IELTS"},{"id":2882,"word":"practically","phonetic":"/'præktikli/","pos":"adv.","meaning":"几乎；差不多；事实上","example":"The room was practically empty by noon.","exampleCn":"到中午时房间几乎空了。","level":"IELTS"},{"id":2883,"word":"subsidiary","phonetic":"/sәb'sidiәri/","pos":"n.","meaning":"子公司；附件；辅助者 a. 辅助的；次要的","example":"The story treated the subsidiary as an important detail.","exampleCn":"这个故事把子公司当作一个重要细节。","level":"IELTS"},{"id":2884,"word":"incidence","phonetic":"/'insidәns/","pos":"n.","meaning":"发生；发生率；影响；负担者","example":"The report explained the incidence in simple language.","exampleCn":"这份报告用简单语言解释了发生。","level":"IELTS"},{"id":2885,"word":"parade","phonetic":"/pә'reid/","pos":"n.","meaning":"游行；炫耀；阅兵 v. 游行；炫耀","example":"The team focused on the parade during the meeting.","exampleCn":"团队在会议中重点关注了游行。","level":"IELTS"},{"id":2886,"word":"subsidy","phonetic":"/'sʌbsidi/","pos":"n.","meaning":"补助金；津贴 补助金；津贴；补贴","example":"She noticed the subsidy while reviewing the notes.","exampleCn":"她复习笔记时注意到了补助金。","level":"IELTS"},{"id":2887,"word":"autonomy","phonetic":"/ɒ:'tɒnәmi/","pos":"n.","meaning":"自治；自治权 自主性","example":"The story treated the autonomy as an important detail.","exampleCn":"这个故事把自治当作一个重要细节。","level":"IELTS"},{"id":2888,"word":"realm","phonetic":"/relm/","pos":"n.","meaning":"王国；领土；领域 领域","example":"The report explained the realm in simple language.","exampleCn":"这份报告用简单语言解释了王国。","level":"IELTS"},{"id":2889,"word":"organism","phonetic":"/'ɒ:gәnizm/","pos":"n.","meaning":"生物；有机体；社会组织 生物；机体","example":"The team focused on the organism during the meeting.","exampleCn":"团队在会议中重点关注了生物。","level":"IELTS"},{"id":2890,"word":"blend","phonetic":"/blend/","pos":"vt.","meaning":"混合 n. 混合","example":"Blend the flour and milk until smooth.","exampleCn":"把面粉和牛奶混合至顺滑。","level":"IELTS"},{"id":2891,"word":"therapist","phonetic":"/'θerәpist/","pos":"n.","meaning":"治疗学家 治疗学家","example":"The story treated the therapist as an important detail.","exampleCn":"这个故事把治疗学家当作一个重要细节。","level":"IELTS"},{"id":2892,"word":"recipient","phonetic":"/ri'sipiәnt/","pos":"adj.","meaning":"领受的；容易接受的；感受性强的 n. 领受者；容纳者","example":"Each recipient received a confirmation email.","exampleCn":"每位收件人都收到了一封确认邮件。","level":"IELTS"},{"id":2893,"word":"peel","phonetic":"/pi:l/","pos":"n.","meaning":"皮；外壳 vt. 削...皮；剥去...的壳 vi. 蜕皮；剥落","example":"The team focused on the peel during the meeting.","exampleCn":"团队在会议中重点关注了皮。","level":"IELTS"},{"id":2894,"word":"flip","phonetic":"/flip/","pos":"vt.","meaning":"掷；弹；轻击；空翻 vi. 用指轻弹","example":"Flip the card to see the answer.","exampleCn":"翻转卡片查看答案。","level":"IELTS"},{"id":2895,"word":"bias","phonetic":"/'baiәs/","pos":"n.","meaning":"偏见；斜纹 a. 偏斜的 adv. 偏斜 vt. 使有偏见 偏流；偏压；偏磁","example":"The story treated bias as an important detail.","exampleCn":"这个故事把偏见当作一个重要细节。","level":"IELTS"},{"id":2896,"word":"metaphor","phonetic":"/'metәfә/","pos":"n.","meaning":"隐喻","example":"The report explained the metaphor in simple language.","exampleCn":"这份报告用简单语言解释了隐喻。","level":"IELTS"},{"id":2897,"word":"candle","phonetic":"/'kændl/","pos":"n.","meaning":"蜡烛 vt. 对着光检查","example":"The team focused on the candle during the meeting.","exampleCn":"团队在会议中重点关注了蜡烛。","level":"IELTS"},{"id":2898,"word":"striking","phonetic":"/'straikiŋ/","pos":"adj.","meaning":"醒目的；惊人的；打击的；罢工的 罢工的","example":"The painting uses striking colors.","exampleCn":"这幅画使用了醒目的色彩。","level":"IELTS"},{"id":2899,"word":"fierce","phonetic":"/fiәs/","pos":"adj.","meaning":"凶猛的；猛烈的；热烈的；暴躁的","example":"The result was fierce enough for everyone to notice.","exampleCn":"结果足够凶猛的，大家都注意到了。","level":"IELTS"},{"id":2900,"word":"fascinating","phonetic":"/'fæsineitiŋ/","pos":"adj.","meaning":"迷人的；吸引人的；使人神魂颠倒的","example":"The lecture was full of fascinating stories.","exampleCn":"这场讲座充满了引人入胜的故事。","level":"IELTS"},{"id":2901,"word":"garbage","phonetic":"/'gɑ:bidʒ/","pos":"n.","meaning":"垃圾；废物 无用信息","example":"The team focused on the garbage during the meeting.","exampleCn":"团队在会议中重点关注了垃圾。","level":"IELTS"},{"id":2902,"word":"edit","phonetic":"/'edit/","pos":"vt.","meaning":"编辑；编校；修订；剪辑 编辑","example":"She will edit the article tonight.","exampleCn":"她今晚会编辑这篇文章。","level":"IELTS"},{"id":2903,"word":"casualty","phonetic":"/'kæʒjuәlti/","pos":"n.","meaning":"意外事故；伤亡；受害者 事故","example":"The story treated the casualty as an important detail.","exampleCn":"这个故事把意外事故当作一个重要细节。","level":"IELTS"},{"id":2904,"word":"chin","phonetic":"/tʃin/","pos":"n.","meaning":"下巴；颏 颏","example":"The report explained the chin in simple language.","exampleCn":"这份报告用简单语言解释了下巴。","level":"IELTS"},{"id":2905,"word":"vanish","phonetic":"/'væniʃ/","pos":"vi.","meaning":"消失；不见；成为零","example":"The situation may vanish if no one takes action.","exampleCn":"如果没人采取行动，情况可能会消失。","level":"IELTS"},{"id":2906,"word":"confess","phonetic":"/kәn'fes/","pos":"v.","meaning":"承认；坦白；忏悔；供认","example":"She wanted to confess without wasting time.","exampleCn":"她想不浪费时间地承认。","level":"IELTS"},{"id":2907,"word":"contemplate","phonetic":"/'kɒntempleit/","pos":"vt.","meaning":"注视；沉思；盘算 vi. 冥思苦想","example":"He sat by the window to contemplate the future.","exampleCn":"他坐在窗边思考未来。","level":"IELTS"},{"id":2908,"word":"starter","phonetic":"/'stɑ:tә/","pos":"n.","meaning":"开端者；在起跑线上的人；参加赛跑的人；调度员","example":"The report explained the starter in simple language.","exampleCn":"这份报告用简单语言解释了开端者。","level":"IELTS"},{"id":2909,"word":"splendid","phonetic":"/'spendid/","pos":"adj.","meaning":"光亮的；了不起的；灿烂的；壮丽的","example":"Her response sounded splendid in that situation.","exampleCn":"在那种情况下，她的回应显得很光亮的。","level":"IELTS"},{"id":2910,"word":"gravity","phonetic":"/'græviti/","pos":"n.","meaning":"地心引力；重力 重力","example":"She noticed the gravity while reviewing the notes.","exampleCn":"她复习笔记时注意到了地心引力。","level":"IELTS"},{"id":2911,"word":"intervene","phonetic":"/.intә'vi:n/","pos":"vi.","meaning":"插入；调停；干涉 进场干预","example":"The group continued to intervene until the work was done.","exampleCn":"这个小组继续插入，直到工作完成。","level":"IELTS"},{"id":2912,"word":"decorate","phonetic":"/'dekәreit/","pos":"v.","meaning":"装饰","example":"They decorate the classroom before the festival.","exampleCn":"他们在节日前装饰教室。","level":"IELTS"},{"id":2913,"word":"accuracy","phonetic":"/'ækjurәsi/","pos":"n.","meaning":"精确；正确 准确度","example":"The team focused on the accuracy during the meeting.","exampleCn":"团队在会议中重点关注了精确。","level":"IELTS"},{"id":2914,"word":"diminish","phonetic":"/di'miniʃ/","pos":"v.","meaning":"(使)减少；(使)变小","example":"She wanted to diminish without wasting time.","exampleCn":"她想不浪费时间地(使)减少。","level":"IELTS"},{"id":2915,"word":"prevention","phonetic":"/pri'venʃәn/","pos":"n.","meaning":"阻止；妨碍；预防 预防","example":"The story treated the prevention as an important detail.","exampleCn":"这个故事把阻止当作一个重要细节。","level":"IELTS"},{"id":2916,"word":"intent","phonetic":"/in'tent/","pos":"n.","meaning":"意图；含义；故意 a. 专心的；决心的","example":"The report explained the intent in simple language.","exampleCn":"这份报告用简单语言解释了意图。","level":"IELTS"},{"id":2917,"word":"metropolitan","phonetic":"/.metrә'pɒlitn/","pos":"n.","meaning":"大都市居民；都主教；宗主国的公民 a. 大都市的；都主教区的","example":"The team focused on the metropolitan during the meeting.","exampleCn":"团队在会议中重点关注了大都市居民。","level":"IELTS"},{"id":2918,"word":"chop","phonetic":"/tʃɒp/","pos":"n.","meaning":"肋条肉；排骨；砍；戳记","example":"She noticed the chop while reviewing the notes.","exampleCn":"她复习笔记时注意到了肋条肉。","level":"IELTS"},{"id":2919,"word":"greece","phonetic":"/gri:s/","pos":"n.","meaning":"希腊","example":"The story treated Greece as an important detail.","exampleCn":"这个故事把希腊当作一个重要细节。","level":"IELTS"},{"id":2920,"word":"thief","phonetic":"/θi:f/","pos":"n.","meaning":"小偷；贼 取样","example":"The report explained the thief in simple language.","exampleCn":"这份报告用简单语言解释了小偷。","level":"IELTS"},{"id":2921,"word":"flavour","phonetic":"/'fleivә/","pos":"n.","meaning":"味；调味香料；滋味；香味","example":"The team focused on the flavour during the meeting.","exampleCn":"团队在会议中重点关注了味。","level":"IELTS"},{"id":2922,"word":"productive","phonetic":"/prә'dʌktiv/","pos":"adj.","meaning":"能生产的；有生产价值的；多产的 产出性的；产生性的","example":"The meeting was short but productive.","exampleCn":"这次会议时间短但很有成效。","level":"IELTS"},{"id":2923,"word":"geography","phonetic":"/dʒi'ɒgrәfi/","pos":"n.","meaning":"地理学；地理 地理","example":"The story treated the geography as an important detail.","exampleCn":"这个故事把地理学当作一个重要细节。","level":"IELTS"},{"id":2924,"word":"inventory","phonetic":"/'invәntәri/","pos":"n.","meaning":"详细目录；存货清单 vt. 列入详细目录；清点存货 存货清单","example":"The report explained the inventory in simple language.","exampleCn":"这份报告用简单语言解释了详细目录。","level":"IELTS"},{"id":2925,"word":"civic","phonetic":"/'sivik/","pos":"adj.","meaning":"市的；市民的；公民的 公民的；市民的","example":"Her response sounded civic in that situation.","exampleCn":"在那种情况下，她的回应显得很市的。","level":"IELTS"},{"id":2926,"word":"exceptional","phonetic":"/ik'sepʃәnәl/","pos":"adj.","meaning":"例外的；异常的；特别的","example":"She showed exceptional talent in music.","exampleCn":"她在音乐方面表现出非凡的才能。","level":"IELTS"},{"id":2927,"word":"descend","phonetic":"/di'send/","pos":"vi.","meaning":"下降；世代相传；屈尊；袭击 vt. 下降","example":"The group continued to descend until the work was done.","exampleCn":"这个小组继续下降，直到工作完成。","level":"IELTS"},{"id":2928,"word":"magnitude","phonetic":"/'mægnitju:d/","pos":"n.","meaning":"巨大；重大；重要；大小","example":"The report explained the magnitude in simple language.","exampleCn":"这份报告用简单语言解释了巨大。","level":"IELTS"},{"id":2929,"word":"hostage","phonetic":"/'hɒstidʒ/","pos":"n.","meaning":"人质；抵押品 人质；抵押品","example":"The team focused on the hostage during the meeting.","exampleCn":"团队在会议中重点关注了人质。","level":"IELTS"},{"id":2930,"word":"alien","phonetic":"/'eiljәn/","pos":"n.","meaning":"外国人；外侨 a. 外国的；相异的","example":"She noticed the alien while reviewing the notes.","exampleCn":"她复习笔记时注意到了外国人。","level":"IELTS"},{"id":2931,"word":"dynamic","phonetic":"/dai'næmik/","pos":"adj.","meaning":"动态的；有活力的；有力的；动力的","example":"The result was dynamic enough for everyone to notice.","exampleCn":"结果足够动态的，大家都注意到了。","level":"IELTS"},{"id":2932,"word":"forecast","phonetic":"/'fɒ:kɑ:st/","pos":"n.","meaning":"预想；预测；预报 vt. 预想；预测","example":"The report explained the forecast in simple language.","exampleCn":"这份报告用简单语言解释了预想。","level":"IELTS"},{"id":2933,"word":"cling","phonetic":"/kliŋ/","pos":"vi.","meaning":"粘紧；附着；紧贴；坚持","example":"The situation may cling if no one takes action.","exampleCn":"如果没人采取行动，情况可能会粘紧。","level":"IELTS"},{"id":2934,"word":"rage","phonetic":"/reidʒ/","pos":"n.","meaning":"愤怒；情绪激动；狂暴 vi. 大怒；狂吹","example":"She noticed the rage while reviewing the notes.","exampleCn":"她复习笔记时注意到了愤怒。","level":"IELTS"},{"id":2935,"word":"execution","phonetic":"/.eksi'kju:ʃәn/","pos":"n.","meaning":"实行；完成；执行；死刑 执行","example":"The story treated the execution as an important detail.","exampleCn":"这个故事把实行当作一个重要细节。","level":"IELTS"},{"id":2936,"word":"precious","phonetic":"/'preʃәs/","pos":"adj.","meaning":"宝贵的；珍贵的；过于精致的；珍爱的","example":"Time with family is precious.","exampleCn":"和家人在一起的时间很宝贵。","level":"IELTS"},{"id":2937,"word":"prohibit","phonetic":"/prә'hibit/","pos":"vt.","meaning":"禁止；阻止 禁止","example":"Please prohibit the document carefully before you send it.","exampleCn":"发送之前，请仔细禁止这份文件。","level":"IELTS"},{"id":2938,"word":"exclusively","phonetic":"/ik'sklu:sivli/","pos":"adv.","meaning":"排他地；仅仅；专门；只","example":"The club is exclusively for members.","exampleCn":"这个俱乐部只对会员开放。","level":"IELTS"},{"id":2939,"word":"enroll","phonetic":"/in'rәul/","pos":"vt.","meaning":"登记；使加入 vi. 参军；注册","example":"You can enroll in the course online.","exampleCn":"你可以在线报名这门课程。","level":"IELTS"},{"id":2940,"word":"conceal","phonetic":"/kәn'si:l/","pos":"vt.","meaning":"隐藏；掩盖；隐瞒 隐瞒；隐匿","example":"He tried to conceal his disappointment.","exampleCn":"他试图掩饰自己的失望。","level":"IELTS"},{"id":2941,"word":"compulsory","phonetic":"/kәm'pʌlsәri/","pos":"adj.","meaning":"被强制的；强迫的；义务的 强迫的；强制的","example":"Her response sounded compulsory in that situation.","exampleCn":"在那种情况下，她的回应显得很被强制的。","level":"IELTS"},{"id":2942,"word":"stumble","phonetic":"/'stʌmbl/","pos":"n.","meaning":"绊倒；蹒跚而行；失足 vt. 使绊倒；使困惑 vi. 绊倒","example":"She noticed the stumble while reviewing the notes.","exampleCn":"她复习笔记时注意到了绊倒。","level":"IELTS"},{"id":2943,"word":"ridge","phonetic":"/ridʒ/","pos":"n.","meaning":"脊；山脊；山脉 嵴；脊","example":"The story treated the ridge as an important detail.","exampleCn":"这个故事把脊当作一个重要细节。","level":"IELTS"},{"id":2944,"word":"dawn","phonetic":"/dɒ:n/","pos":"n.","meaning":"破晓；黎明 vi. 破晓","example":"The report explained the dawn in simple language.","exampleCn":"这份报告用简单语言解释了破晓。","level":"IELTS"},{"id":2945,"word":"automobile","phonetic":"/'ɒ:tәmәbi:l/","pos":"n.","meaning":"汽车 汽车","example":"The team focused on the automobile during the meeting.","exampleCn":"团队在会议中重点关注了汽车。","level":"IELTS"},{"id":2946,"word":"terminal","phonetic":"/'tә:minәl/","pos":"n.","meaning":"终端机；终点；末端；极限","example":"She noticed the terminal while reviewing the notes.","exampleCn":"她复习笔记时注意到了终端机。","level":"IELTS"},{"id":2947,"word":"incur","phonetic":"/in'kә:/","pos":"vt.","meaning":"招致；蒙受；遭遇 招致；蒙受","example":"Late payment may incur extra fees.","exampleCn":"逾期付款可能会产生额外费用。","level":"IELTS"},{"id":2948,"word":"cab","phonetic":"/kæb/","pos":"n.","meaning":"出租车；出租汽车；出租马车 vi. 乘出租马车(或汽车)","example":"The report explained the cab in simple language.","exampleCn":"这份报告用简单语言解释了出租车。","level":"IELTS"},{"id":2949,"word":"cooperate","phonetic":"/kәu'ɒpәreit/","pos":"vi.","meaning":"合作；协力；配合 合作","example":"The situation may cooperate if no one takes action.","exampleCn":"如果没人采取行动，情况可能会合作。","level":"IELTS"},{"id":2950,"word":"pillow","phonetic":"/'pilәu/","pos":"n.","meaning":"枕头；靠垫；枕状岩 vt. 作...的枕头；垫","example":"She noticed the pillow while reviewing the notes.","exampleCn":"她复习笔记时注意到了枕头。","level":"IELTS"},{"id":2951,"word":"primitive","phonetic":"/'primitiv/","pos":"n.","meaning":"原始人；早期艺术家 a. 原始的；上古的 图元；原语","example":"The story treated the primitive as an important detail.","exampleCn":"这个故事把原始人当作一个重要细节。","level":"IELTS"},{"id":2952,"word":"seal","phonetic":"/si:l/","pos":"n.","meaning":"印章；封条；海豹；海豹皮","example":"The report explained the seal in simple language.","exampleCn":"这份报告用简单语言解释了印章。","level":"IELTS"},{"id":2953,"word":"bronze","phonetic":"/brɒnz/","pos":"n.","meaning":"青铜；铜像 a. 青铜色的","example":"The team focused on the bronze during the meeting.","exampleCn":"团队在会议中重点关注了青铜。","level":"IELTS"},{"id":2954,"word":"orchestra","phonetic":"/'ɒ:kistrә/","pos":"n.","meaning":"管弦乐队；乐队演奏处","example":"She noticed the orchestra while reviewing the notes.","exampleCn":"她复习笔记时注意到了管弦乐队。","level":"IELTS"},{"id":2955,"word":"scarcely","phonetic":"/'skɑ:sli/","pos":"adv.","meaning":"简直不；一定不；仅仅","example":"There was scarcely enough time to finish.","exampleCn":"几乎没有足够的时间完成。","level":"IELTS"},{"id":2956,"word":"deadline","phonetic":"/'dedlain/","pos":"n.","meaning":"最后期限；截止期限 截止日期","example":"The report explained the deadline in simple language.","exampleCn":"这份报告用简单语言解释了最后期限。","level":"IELTS"},{"id":2957,"word":"rear","phonetic":"/riә/","pos":"n.","meaning":"后面；背后；后方 a. 后面的；背面的","example":"The team focused on the rear during the meeting.","exampleCn":"团队在会议中重点关注了后面。","level":"IELTS"},{"id":2958,"word":"occupational","phonetic":"/.ɒkju'peiʃәnl/","pos":"adj.","meaning":"职业的；军事占领的 职业的","example":"The company offers occupational health training.","exampleCn":"公司提供职业健康培训。","level":"IELTS"},{"id":2959,"word":"verbal","phonetic":"/'vә:bl/","pos":"adj.","meaning":"用言辞的；言语的；口头的；逐字的","example":"The result was verbal enough for everyone to notice.","exampleCn":"结果足够用言辞的，大家都注意到了。","level":"IELTS"},{"id":2960,"word":"coastal","phonetic":"/'kәustәl/","pos":"adj.","meaning":"海岸的；沿海的；沿岸的 海岸的；沿海的","example":"They moved to a quiet coastal town.","exampleCn":"他们搬到一个安静的海滨小镇。","level":"IELTS"},{"id":2961,"word":"systematic","phonetic":"/.sisti'mætik/","pos":"adj.","meaning":"有系统的；分类上的；体系的 系统的；系的","example":"Her response sounded systematic in that situation.","exampleCn":"在那种情况下，她的回应显得很有系统的。","level":"IELTS"},{"id":2962,"word":"constituent","phonetic":"/kәn'stitjuәnt/","pos":"n.","meaning":"成分；选民；构成物 a. 构成的；组织的","example":"She noticed the constituent while reviewing the notes.","exampleCn":"她复习笔记时注意到了成分。","level":"IELTS"},{"id":2963,"word":"payable","phonetic":"/'peiәbl/","pos":"adj.","meaning":"可付的；到期的；应付的；有利益的 应付的","example":"The result was payable enough for everyone to notice.","exampleCn":"结果足够可付的，大家都注意到了。","level":"IELTS"},{"id":2964,"word":"sentiment","phonetic":"/'sentimәnt/","pos":"n.","meaning":"感情；感伤；情操；情绪","example":"The report explained the sentiment in simple language.","exampleCn":"这份报告用简单语言解释了感情。","level":"IELTS"},{"id":2965,"word":"divine","phonetic":"/di'vain/","pos":"adj.","meaning":"神的；神圣的；非凡的 n. 神学家","example":"Her response sounded divine in that situation.","exampleCn":"在那种情况下，她的回应显得很神的。","level":"IELTS"},{"id":2966,"word":"cart","phonetic":"/kɑ:t/","pos":"n.","meaning":"二轮运货马车 vi. 驾运货马车 vt. 用车装载","example":"She noticed the cart while reviewing the notes.","exampleCn":"她复习笔记时注意到了二轮运货马车。","level":"IELTS"},{"id":2967,"word":"interim","phonetic":"/'intәrim/","pos":"adj.","meaning":"暂时的；临时的；间歇的 n. 过渡时期","example":"The result was interim enough for everyone to notice.","exampleCn":"结果足够暂时的，大家都注意到了。","level":"IELTS"},{"id":2968,"word":"oversee","phonetic":"/.әuvә'si:/","pos":"vt.","meaning":"向下看；了望；监督；偷看到 监察","example":"She was hired to oversee the project.","exampleCn":"她受聘监督这个项目。","level":"IELTS"},{"id":2969,"word":"elder","phonetic":"/'eldә/","pos":"n.","meaning":"年长者；老人；前辈 a. 年长的；资深的","example":"The team focused on the elder during the meeting.","exampleCn":"团队在会议中重点关注了年长者。","level":"IELTS"},{"id":2970,"word":"inspiration","phonetic":"/.inspә'reiʃәn/","pos":"n.","meaning":"灵感；鼓舞人心的人或物；妙计；吸气 吸","example":"She noticed the inspiration while reviewing the notes.","exampleCn":"她复习笔记时注意到了灵感。","level":"IELTS"},{"id":2971,"word":"equilibrium","phonetic":"/.i:kwi'libriәm/","pos":"n.","meaning":"平衡；平静；均衡 平衡","example":"The story treated the equilibrium as an important detail.","exampleCn":"这个故事把平衡当作一个重要细节。","level":"IELTS"},{"id":2972,"word":"genius","phonetic":"/'dʒi:njәs/","pos":"n.","meaning":"天才；天赋；精神；神魔 特征","example":"The report explained genius in simple language.","exampleCn":"这份报告用简单语言解释了天才。","level":"IELTS"},{"id":2973,"word":"quest","phonetic":"/kwest/","pos":"n.","meaning":"探索；寻求；调查 v. 寻找；找","example":"The team focused on the quest during the meeting.","exampleCn":"团队在会议中重点关注了探索。","level":"IELTS"},{"id":2974,"word":"sacrifice","phonetic":"/'sækrifais/","pos":"n.","meaning":"牺牲；供奉；祭品 vt. 牺牲；祭祀","example":"She noticed the sacrifice while reviewing the notes.","exampleCn":"她复习笔记时注意到了牺牲。","level":"IELTS"},{"id":2975,"word":"talented","phonetic":"/'tælәntid/","pos":"adj.","meaning":"天资高的；有才能的","example":"The result was talented enough for everyone to notice.","exampleCn":"结果足够天资高的，大家都注意到了。","level":"IELTS"},{"id":2976,"word":"nominee","phonetic":"/.nɒmi'ni:/","pos":"n.","meaning":"被提名者；被任命者 被指定人","example":"The report explained the nominee in simple language.","exampleCn":"这份报告用简单语言解释了被提名者。","level":"IELTS"},{"id":2977,"word":"definite","phonetic":"/'definit/","pos":"adj.","meaning":"明确的；一定的 明确的；确切的；一定的","example":"Her response sounded definite in that situation.","exampleCn":"在那种情况下，她的回应显得很明确的。","level":"IELTS"},{"id":2978,"word":"stiff","phonetic":"/stif/","pos":"adj.","meaning":"坚硬的；严厉的；呆板的；生硬的","example":"My neck feels stiff after the long flight.","exampleCn":"长途飞行后我的脖子感觉僵硬。","level":"IELTS"},{"id":2979,"word":"advertise","phonetic":"/'ædvәtaiz/","pos":"vt.","meaning":"做广告；通知；公布 vi. 做广告","example":"The shop will advertise its sale online.","exampleCn":"这家商店将在网上宣传促销活动。","level":"IELTS"},{"id":2980,"word":"slap","phonetic":"/slæp/","pos":"n.","meaning":"掴；掌击；侮辱；拍击声 v. 拍击","example":"The report explained the slap in simple language.","exampleCn":"这份报告用简单语言解释了掴。","level":"IELTS"},{"id":2981,"word":"supermarket","phonetic":"/'sju:pәmɑ:kit/","pos":"n.","meaning":"超级市场 超级市场；自助售货商店","example":"The team focused on the supermarket during the meeting.","exampleCn":"团队在会议中重点关注了超级市场。","level":"IELTS"},{"id":2982,"word":"cutting","phonetic":"/'kʌtiŋ/","pos":"n.","meaning":"切断；切下；路堑 切屑","example":"She noticed the cutting while reviewing the notes.","exampleCn":"她复习笔记时注意到了切断。","level":"IELTS"},{"id":2983,"word":"toxic","phonetic":"/'tɒksik/","pos":"adj.","meaning":"有毒的；中毒的 中毒的；毒物的","example":"The result was toxic enough for everyone to notice.","exampleCn":"结果足够有毒的，大家都注意到了。","level":"IELTS"},{"id":2984,"word":"grief","phonetic":"/gri:f/","pos":"n.","meaning":"伤心；忧愁；悲痛；不幸","example":"The report explained the grief in simple language.","exampleCn":"这份报告用简单语言解释了伤心。","level":"IELTS"},{"id":2985,"word":"donate","phonetic":"/'dәuneit/","pos":"v.","meaning":"捐赠","example":"The method can donate when conditions are right.","exampleCn":"条件合适时，这种方法可以捐赠。","level":"IELTS"},{"id":2986,"word":"breakdown","phonetic":"/'breikdaun/","pos":"n.","meaning":"崩溃；故障 事故；击穿","example":"She noticed the breakdown while reviewing the notes.","exampleCn":"她复习笔记时注意到了崩溃。","level":"IELTS"},{"id":2987,"word":"awkward","phonetic":"/'ɒ:kwәd/","pos":"adj.","meaning":"笨拙的；棘手的","example":"The result was awkward enough for everyone to notice.","exampleCn":"结果足够笨拙的，大家都注意到了。","level":"IELTS"},{"id":2988,"word":"invariably","phonetic":"/in'vєәriәbli/","pos":"adv.","meaning":"不变化地；恒定地；始终如一地","example":"He invariably arrives ten minutes early.","exampleCn":"他总是提前十分钟到达。","level":"IELTS"},{"id":2989,"word":"dignity","phonetic":"/'digniti/","pos":"n.","meaning":"尊严；高贵 尊严；高位；高贵","example":"The team focused on the dignity during the meeting.","exampleCn":"团队在会议中重点关注了尊严。","level":"IELTS"},{"id":2990,"word":"dispose","phonetic":"/dis'pәuz/","pos":"vt.","meaning":"处理；排列；布置 vi. 处置","example":"Please dispose of batteries safely.","exampleCn":"请安全处理电池。","level":"IELTS"},{"id":2991,"word":"parental","phonetic":"/pә'rentәl/","pos":"adj.","meaning":"父母亲的；做双亲的；作为渊源的 父母的；双亲的","example":"The result was parental enough for everyone to notice.","exampleCn":"结果足够父母亲的，大家都注意到了。","level":"IELTS"},{"id":2992,"word":"affection","phonetic":"/ә'fekʃәn/","pos":"n.","meaning":"影响；病；喜爱；情感","example":"The report explained the affection in simple language.","exampleCn":"这份报告用简单语言解释了影响。","level":"IELTS"},{"id":2993,"word":"grace","phonetic":"/greis/","pos":"n.","meaning":"优雅；风度；慈悲；恩惠","example":"The team focused on the grace during the meeting.","exampleCn":"团队在会议中重点关注了优雅。","level":"IELTS"},{"id":2994,"word":"bubble","phonetic":"/'bʌbl/","pos":"n.","meaning":"泡沫 vi. 冒泡；沸腾 vt. 使冒泡；滔滔不绝地说","example":"She noticed the bubble while reviewing the notes.","exampleCn":"她复习笔记时注意到了泡沫。","level":"IELTS"},{"id":2995,"word":"isolated","phonetic":"/'aisәleitid/","pos":"adj.","meaning":"孤立的；孤零零的 隔离的；绝缘的","example":"The result was isolated enough for everyone to notice.","exampleCn":"结果足够孤立的，大家都注意到了。","level":"IELTS"},{"id":2996,"word":"barn","phonetic":"/bɑ:n/","pos":"n.","meaning":"谷仓 靶(恩)(核反应截面单位)","example":"The report explained the barn in simple language.","exampleCn":"这份报告用简单语言解释了谷仓。","level":"IELTS"},{"id":2997,"word":"dissolve","phonetic":"/di'zɒlv/","pos":"v.","meaning":"溶解；解散","example":"The method can dissolve when conditions are right.","exampleCn":"条件合适时，这种方法可以溶解。","level":"IELTS"},{"id":2998,"word":"specialize","phonetic":"/'speʃәlaiz/","pos":"vt.","meaning":"使特殊化；列举；特别指明；限定...的范围 vi. 成为专家","example":"The clinic specializes in eye care.","exampleCn":"这家诊所专门从事眼科护理。","level":"IELTS"},{"id":2999,"word":"prejudice","phonetic":"/'predʒudis/","pos":"n.","meaning":"偏见；成见；侵害 vt. 使存偏见；使有成见","example":"The story treated the prejudice as an important detail.","exampleCn":"这个故事把偏见当作一个重要细节。","level":"IELTS"},{"id":3000,"word":"shield","phonetic":"/'ʃi:ld/","pos":"n.","meaning":"盾；防卫物；保护者；屏蔽 vt. 保护","example":"The report explained the shield in simple language.","exampleCn":"这份报告用简单语言解释了盾。","level":"IELTS"}];
